const BUBBLE_PRESETS_KEY = 'my_bubble_presets';

function getUserBubblePresets() {
    try {
        const raw = localStorage.getItem(BUBBLE_PRESETS_KEY);
        if (raw) return JSON.parse(raw);
    } catch (e) {}
    return [];
}

function saveUserBubblePresets(list) {
    localStorage.setItem(BUBBLE_PRESETS_KEY, JSON.stringify(list));
}

function getAllBubblePresets() {
    return [...BUBBLE_CSS_PRESETS, ...getUserBubblePresets()];
}

function renderBubblePresetDropdown(selectedCss) {
    const sel = document.getElementById('wcs-bubble-preset');
    if (!sel) return;
    const all = getAllBubblePresets();
    sel.innerHTML = all.map(p =>
        `<option value="${p.id}">${p.name}</option>`
    ).join('');
    // 找到匹配当前CSS的预设
    const match = all.find(p => p.css.replace(/\s+/g, '') === (selectedCss || '').replace(/\s+/g, ''));
    sel.value = match ? match.id : 'default';
    renderBubblePresetPicker(all, sel.value);
}

function renderBubblePresetPicker(all, selectedId) {
    const label = document.getElementById('wcs-bubble-preset-label');
    const menu = document.getElementById('wcs-bubble-preset-menu');
    if (!label || !menu) return;
    const selected = all.find(p => p.id === selectedId) || all[0];
    label.textContent = selected ? selected.name : '默认';
    menu.innerHTML = all.map(p => `
        <button type="button" class="wcs-bubble-option ${p.id === selectedId ? 'active' : ''}" data-preset-id="${wcEscapeHtml(p.id)}">
            <span>${wcEscapeHtml(p.name)}</span>
            ${p.id === selectedId ? '<i class="ri-check-line"></i>' : ''}
        </button>
    `).join('');
    menu.querySelectorAll('.wcs-bubble-option').forEach(btn => {
        btn.onclick = () => chooseBubblePreset(btn.dataset.presetId || 'default');
    });
}

function toggleBubblePresetPicker(event) {
    if (event) event.stopPropagation();
    const wrap = document.querySelector('.wcs-bubble-preset-wrap');
    if (!wrap) return;
    wrap.classList.toggle('open');
}

function closeBubblePresetPicker() {
    const wrap = document.querySelector('.wcs-bubble-preset-wrap');
    if (wrap) wrap.classList.remove('open');
}

function chooseBubblePreset(presetId) {
    const sel = document.getElementById('wcs-bubble-preset');
    if (sel) sel.value = presetId;
    applyBubblePreset(presetId);
    closeBubblePresetPicker();
}

function applyBubblePreset(presetId) {
    const all = getAllBubblePresets();
    const preset = all.find(p => p.id === presetId);
    if (!preset) return;
    const textarea = document.getElementById('wcs-custom-css');
    if (textarea) {
        textarea.value = preset.css;
        previewBubbleCss(preset.css);
    }
    const sel = document.getElementById('wcs-bubble-preset');
    if (sel) sel.value = preset.id;
    renderBubblePresetPicker(all, preset.id);
}

function saveCurrentCssAsPreset() {
    const textarea = document.getElementById('wcs-custom-css');
    if (!textarea || !textarea.value.trim()) {
        alert('请先在下面的编辑框中输入CSS样式');
        return;
    }
    const name = prompt('给这个气泡样式起个名字：');
    if (!name || !name.trim()) return;
    const presets = getUserBubblePresets();
    const newPreset = {
        id: 'bp_' + Date.now(),
        name: name.trim(),
        css: textarea.value.trim()
    };
    presets.push(newPreset);
    saveUserBubblePresets(presets);
    renderBubblePresetDropdown(newPreset.css);
    const sel = document.getElementById('wcs-bubble-preset');
    if (sel) sel.value = newPreset.id;
}

function deleteSelectedPreset() {
    const sel = document.getElementById('wcs-bubble-preset');
    if (!sel) return;
    const id = sel.value;
    if (BUBBLE_CSS_PRESETS.find(p => p.id === id)) {
        alert('内置预设不能删除哦～');
        return;
    }
    const presets = getUserBubblePresets();
    const idx = presets.findIndex(p => p.id === id);
    if (idx === -1) return;
    if (!confirm(`确定删除预设「${presets[idx].name}」吗？`)) return;
    presets.splice(idx, 1);
    saveUserBubblePresets(presets);
    document.getElementById('wcs-custom-css').value = '';
    previewBubbleCss('');
    renderBubblePresetDropdown('');
}

function clearBubbleCssPreset() {
    const textarea = document.getElementById('wcs-custom-css');
    if (textarea) textarea.value = '';
    previewBubbleCss('');
    renderBubblePresetDropdown('');
}

document.addEventListener('click', event => {
    if (!event.target.closest('.wcs-bubble-preset-wrap')) closeBubblePresetPicker();
});

// --- A. 微信界面渲染 ---

function getWechatQQGroupSettings(group) {
    if (!group || !group.isGroupChat) return {};
    group.chatConfig = group.chatConfig || {};
    const settings = group.chatConfig.qqGroupSettings && typeof group.chatConfig.qqGroupSettings === 'object'
        ? group.chatConfig.qqGroupSettings
        : {};
    if (!/^\d{11}$/.test(String(settings.groupNumber || ''))) {
        settings.groupNumber = buildWechatQQGroupNumber(group);
    }
    group.chatConfig.qqGroupSettings = settings;
    return settings;
}

function getWechatQQGroupFlag(settings, key, defaultValue = true) {
    if (!settings || settings[key] == null) return defaultValue;
    return !!settings[key];
}

function buildWechatQQGroupNumber(group) {
    const seed = String(group?.id || group?.groupCreatedAt || group?.name || 'group');
    let hash = 1469598103934665603n;
    for (let i = 0; i < seed.length; i++) {
        hash ^= BigInt(seed.charCodeAt(i));
        hash = (hash * 1099511628211n) & ((1n << 64n) - 1n);
    }
    return String(10000000000n + (hash % 90000000000n));
}

function getWechatQQGroupDisplayName(group) {
    const settings = getWechatQQGroupSettings(group);
    return settings.groupRemark || (group && group.chatConfig && group.chatConfig.nickname) || (group && group.name) || '群聊';
}

function isWechatQQGroupPinned(char) {
    return !!(char && char.isGroupChat && getWechatQQGroupSettings(char).pinned);
}

function isWechatQQGroupHiddenPreview(char) {
    return !!(char && char.isGroupChat && getWechatQQGroupSettings(char).hideChat);
}

function isWechatQQGroupMuted(char) {
    const settings = char && char.isGroupChat ? getWechatQQGroupSettings(char) : {};
    return !!(settings.muteNotifications || settings.notificationMode === 'silent' || settings.notificationMode === 'blocked');
}

function isWechatQQGroupBlocked(char) {
    const settings = char && char.isGroupChat ? getWechatQQGroupSettings(char) : {};
    return settings.notificationMode === 'blocked';
}

function isWechatQQGroupSpeechMuted(char) {
    const settings = char && char.isGroupChat ? getWechatQQGroupSettings(char) : {};
    return !!settings.speechMuted;
}

function isWechatGroupNpcContact(char) {
    return !!(char && !char.isGroupChat && (char.isGroupNpc || char.groupNpc || char.npcOriginGroupId));
}

function getWechatVisibleChatCharacters() {
    return (window.myCharacters || []).filter(char => char && !isWechatGroupNpcContact(char));
}

function getWechatSortedChatCharacters() {
    return getWechatVisibleChatCharacters().slice().sort((a, b) => {
        const pinDelta = Number(isWechatQQGroupPinned(b)) - Number(isWechatQQGroupPinned(a));
        if (pinDelta) return pinDelta;
        return 0;
    });
}

function renderChatList() {
    renderWechatThemeChatHeader();
    const listEl = document.getElementById('wc-chat-list');
    if (!listEl) return;
    listEl.innerHTML = ''; 
    const themeId = getWechatUiThemeId();
    const isXTheme = themeId === 'hallowrok';
    const syncThemeChrome = () => {
        if (typeof updateWechatUiThemeStructure === 'function') updateWechatUiThemeStructure(getWechatUiTheme());
    };

    if (getWechatVisibleChatCharacters().length === 0) {
        if (isXTheme) {
            syncThemeChrome();
            return;
        }
        listEl.innerHTML = `
            <div style="display:flex; flex-direction:column; align-items:center; justify-content:center; height:300px; color:#ccc;">
                <i class="ri-chat-smile-2-line" style="font-size:48px; margin-bottom:10px;"></i>
                <span style="font-size:14px;">暂无消息</span>
                <span style="font-size:12px; margin-top:5px;">点击右上角 + 导入角色卡</span>
            </div>
        `;
        syncThemeChrome();
        return;
    }

    const isDouyinTheme = themeId === 'douyin';
    const isLineTheme = themeId === 'line';
    const isWechatTheme = themeId === 'wechat';
    const supportsBuiltinEmojiPreview = themeId === 'wechat' || themeId === 'qq';
    getWechatSortedChatCharacters().forEach(char => {
        const container = document.createElement('div');
        container.className = 'wc-swipe-container';
        container.dataset.charId = char.id;

        const item = document.createElement('div');
        item.className = 'wc-chat-item';
        let pointerStartX = 0;
        let pointerStartY = 0;
        const openFromListItem = (event) => {
            if (event?.target?.closest('.wc-delete-btn')) return;
            if (container.classList.contains('swiping') || container.classList.contains('swipe-open')) return;
            const lastOpenAt = Number(container.dataset.openingAt || 0);
            if (Date.now() - lastOpenAt < 360) return;
            container.dataset.openingAt = String(Date.now());
            event?.preventDefault?.();
            event?.stopPropagation?.();
            openChat(char.id);
        };
        item.addEventListener('pointerdown', (event) => {
            pointerStartX = event.clientX;
            pointerStartY = event.clientY;
        }, { passive: true });
        item.addEventListener('pointerup', (event) => {
            if (event.pointerType === 'mouse') return;
            if (Math.abs(event.clientX - pointerStartX) < 18 && Math.abs(event.clientY - pointerStartY) < 18) {
                openFromListItem(event);
            }
        });
        item.addEventListener('click', openFromListItem);
        const isGroup = !!char.isGroupChat;
        const isPinned = isWechatQQGroupPinned(char);
        const isMuted = isWechatQQGroupMuted(char);
        const isHiddenPreview = isWechatQQGroupHiddenPreview(char);
        item.classList.toggle('wc-chat-pinned', isPinned);
        item.classList.toggle('wc-chat-muted', isMuted);
        item.classList.toggle('wc-chat-hidden-preview', isHiddenPreview);
        const displayName = isGroup ? getWechatQQGroupDisplayName(char) : ((char.chatConfig && char.chatConfig.nickname) || char.name);
        const avatar = getWechatCharAvatarSource(char, isGroup ? buildWechatGroupAvatar(char) : DEFAULT_AVATAR);
        const douyinUnread = isDouyinTheme ? getWechatDouyinUnreadCount(char) : 0;
        const douyinSpark = isDouyinTheme ? getWechatDouyinSparkScore(char) : 0;
        const douyinUnreadHtml = isDouyinTheme && douyinUnread > 0
            ? `<span class="wc-douyin-unread">${douyinUnread > 99 ? '99+' : douyinUnread}</span>`
            : '';
        const douyinSparkHtml = isDouyinTheme && douyinSpark > 0
            ? `<span class="wc-douyin-spark">🔥 ${douyinSpark}</span>`
            : '';

        const telegramTime = formatTelegramChatListTime(char);
        const telegramUnread = getTelegramChatUnreadCount(char);
        const telegramUnreadHtml = telegramUnread > 0
            ? `<span class="wc-telegram-unread">${telegramUnread > 99 ? '99+' : telegramUnread}</span>`
            : '';
        const lineUnread = isLineTheme ? getTelegramChatUnreadCount(char) : 0;
        const lineUnreadHtml = lineUnread > 0
            ? `<span class="wc-line-unread">${lineUnread > 99 ? '99+' : lineUnread}</span>`
            : '';
        const wechatUnread = isWechatTheme && typeof getWechatThemeCharUnreadCount === 'function'
            ? getWechatThemeCharUnreadCount(char)
            : 0;
        const wechatUnreadHtml = wechatUnread > 0
            ? `<span class="wc-wechat-list-unread">${wechatUnread > 99 ? '99+' : wechatUnread}</span>`
            : '';
        const stateHtml = `${isPinned ? '<i class="ri-pushpin-fill wc-list-state-icon"></i>' : ''}${isMuted ? '<i class="ri-notification-off-line wc-list-state-icon"></i>' : ''}`;
        const previewText = isHiddenPreview
            ? '会话已隐藏'
            : `${isGroup ? `[${getWechatQQGroupDisplayMembers(char).length}人] ` : ''}${getChatPreview(char)}`;
        const previewHtml = supportsBuiltinEmojiPreview
            ? renderWechatChatPreviewHtml(previewText)
            : escapeHtml(previewText);

        item.innerHTML = `
            <div class="wc-avatar ${isGroup ? 'wc-group-avatar' : ''}"><img src="${avatar}" onerror="this.src='${DEFAULT_AVATAR}'">${douyinUnreadHtml}</div>
            <div class="wc-info">
                <div class="wc-top">
                    <span class="wc-name">${escapeHtml(displayName)}${stateHtml}${douyinSparkHtml}</span>
                    <span class="wc-time">${escapeHtml(formatWechatChatListTime(char))}</span>
                    <span class="wc-line-list-side">
                        <span class="wc-line-date">${escapeHtml(formatWechatChatListTime(char))}</span>
                        ${lineUnreadHtml}
                    </span>
                    <span class="wc-telegram-list-meta">
                        <span class="wc-telegram-date"><i class="ri-pushpin-2-fill"></i>${escapeHtml(telegramTime)}</span>
                        ${telegramUnreadHtml}
                    </span>
                </div>
                <div class="wc-bottom">
                    <span class="wc-msg">${previewHtml}</span>
                    ${wechatUnreadHtml}
                </div>
            </div>
        `;

        const delBtn = document.createElement('div');
        delBtn.className = 'wc-delete-btn';
        delBtn.innerHTML = '<span>删除</span>';
        const stopDeleteEvent = (e) => {
            e.stopPropagation?.();
            e.stopImmediatePropagation?.();
        };
        ['pointerdown', 'pointerup', 'touchstart', 'touchend', 'mousedown', 'mouseup'].forEach(type => {
            delBtn.addEventListener(type, stopDeleteEvent, { passive: false });
        });
        delBtn.addEventListener('click', (e) => {
            e.preventDefault?.();
            stopDeleteEvent(e);
            deleteCharacter(char.id);
        });

        container.appendChild(item);
        container.appendChild(delBtn);
        listEl.appendChild(container);
    });

    initSwipeHandlers();
    syncThemeChrome();
}

function getWechatGroupContacts(options = {}) {
    const includeGroupNpc = options.includeGroupNpc === true;
    return (window.myCharacters || []).filter(char => (
        char
        && char.id
        && !char.isGroupChat
        && (includeGroupNpc || !isWechatGroupNpcContact(char))
    ));
}

function getWechatGroupMembers(group) {
    const ids = Array.isArray(group?.groupMembers) ? group.groupMembers : [];
    return ids.map(id => getWechatGroupContacts({ includeGroupNpc: true }).find(char => char.id === id)).filter(Boolean);
}

function getWechatGroupMemberName(member) {
    return (member && member.chatConfig && member.chatConfig.nickname) || (member && member.name) || '成员';
}

function getWechatQQGroupUserProfile(group) {
    if (typeof getWechatChatUserProfile === 'function') return getWechatChatUserProfile(group);
    if (typeof getUserProfile === 'function') return getUserProfile();
    return {};
}

function getWechatQQGroupUserMember(group) {
    const profile = getWechatQQGroupUserProfile(group);
    const settings = getWechatQQGroupSettings(group);
    const selfProfile = settings.memberProfiles && typeof settings.memberProfiles === 'object'
        ? settings.memberProfiles[WECHAT_QQ_GROUP_USER_ID]
        : null;
    const selfRemark = selfProfile && typeof selfProfile === 'object' ? selfProfile.remark : '';
    return {
        id: WECHAT_QQ_GROUP_USER_ID,
        name: selfRemark || settings.myNickname || profile.name || '我',
        avatar: profile.avatar || DEFAULT_AVATAR,
        isUser: true
    };
}

function getWechatQQGroupDisplayMembers(group, options = {}) {
    const includeUser = options.includeUser !== false;
    const members = getWechatGroupMembers(group);
    return includeUser ? [getWechatQQGroupUserMember(group), ...members] : members;
}

function getWechatQQGroupMemberProfiles(group) {
    const settings = getWechatQQGroupSettings(group);
    if (!settings.memberProfiles || typeof settings.memberProfiles !== 'object' || Array.isArray(settings.memberProfiles)) {
        settings.memberProfiles = {};
    }
    return settings.memberProfiles;
}

function getWechatQQGroupOwnerId(group) {
    const settings = getWechatQQGroupSettings(group);
    settings.ownerId = WECHAT_QQ_GROUP_USER_ID;
    if (group) group.groupOwnerId = WECHAT_QQ_GROUP_USER_ID;
    const ownerProfile = getWechatQQGroupMemberProfile(group, WECHAT_QQ_GROUP_USER_ID);
    ownerProfile.role = 'owner';
    return WECHAT_QQ_GROUP_USER_ID;
}

function getWechatQQGroupMemberProfile(group, memberId) {
    const profiles = getWechatQQGroupMemberProfiles(group);
    const id = String(memberId || '');
    if (!id) return {};
    if (!profiles[id] || typeof profiles[id] !== 'object' || Array.isArray(profiles[id])) profiles[id] = {};
    return profiles[id];
}

function getWechatQQGroupMemberRole(group, memberId) {
    if (!group?.isGroupChat || !memberId) return 'member';
    if (memberId === WECHAT_QQ_GROUP_USER_ID) return 'owner';
    if (getWechatQQGroupOwnerId(group) === memberId) return 'owner';
    const profile = getWechatQQGroupMemberProfile(group, memberId);
    return profile.role === 'admin' ? 'admin' : 'member';
}

function getWechatQQGroupMemberDisplayName(group, member) {
    if (!member) return '成员';
    const profile = getWechatQQGroupMemberProfile(group, member.id);
    if (member.id === WECHAT_QQ_GROUP_USER_ID || member.isUser) {
        return profile.remark || member.name || '我';
    }
    return profile.remark || getWechatGroupMemberName(member);
}

function getWechatQQGroupMemberBadge(group, memberId) {
    const role = getWechatQQGroupMemberRole(group, memberId);
    const profile = getWechatQQGroupMemberProfile(group, memberId);
    if (role === 'owner') return { text: profile.title || '群主', kind: 'owner' };
    if (role === 'admin') return { text: profile.title || '管理员', kind: 'admin' };
    if (profile.title) return { text: profile.title, kind: 'title' };
    return null;
}

function renderWechatQQGroupMemberBadge(group, memberId) {
    const badge = getWechatQQGroupMemberBadge(group, memberId);
    if (!badge || !badge.text) return '';
    return `<em class="wcs-qq-member-badge ${wcEscapeAttr(badge.kind)}">${wcEscapeHtml(badge.text)}</em>`;
}

function renderWechatQQGroupMessageSenderLabel(group, member) {
    if (!group?.isGroupChat || !member) return '';
    const badgeHtml = renderWechatQQGroupMemberBadge(group, member.id);
    const name = getWechatQQGroupMemberDisplayName(group, member);
    return `<div class="msg-sender-name"><span class="msg-sender-name-line"><b>${wcEscapeHtml(name)}</b>${badgeHtml}</span></div>`;
}

function findWechatGroupMember(group, value) {
    const query = String(value || '').trim();
    if (!group || !query) return null;
    const members = getWechatGroupMembers(group);
    return members.find(member => {
        const display = getWechatGroupMemberName(member);
        const groupDisplay = getWechatQQGroupMemberDisplayName(group, member);
        return member.id === query || member.name === query || display === query || groupDisplay === query
            || query.includes(display) || display.includes(query)
            || query.includes(groupDisplay) || groupDisplay.includes(query);
    }) || null;
}

function normalizeWechatGroupSpeechText(text, group) {
    const source = cleanWechatVisibleContent(text);
    if (!source || !group?.isGroupChat) return { text: source, member: null };
    const match = source.match(/^\s*([^：:\n]{1,24})\s*[：:]\s*([\s\S]+)$/);
    if (!match) return { text: source, member: null };
    const member = findWechatGroupMember(group, match[1]);
    if (!member) return { text: source, member: null };
    return { text: match[2].trim(), member };
}

function attachWechatGroupSpeaker(msg, group, fallbackIndex = 0, fallbackMembers = null) {
    if (!msg || !group?.isGroupChat || msg.isMe || msg.type === 'system_notice') return msg;
    const scopedMembers = Array.isArray(fallbackMembers) ? fallbackMembers.filter(Boolean) : [];
    const members = scopedMembers.length ? scopedMembers : getWechatGroupMembers(group);
    const scopedIds = scopedMembers.length ? new Set(scopedMembers.map(member => member && member.id).filter(Boolean)) : null;
    if (!members.length) return msg;

    let speaker = null;
    if (msg.senderId || msg.speakerId || msg.senderName || msg.speakerName) {
        speaker = findWechatGroupMember(group, msg.senderId || msg.speakerId || msg.senderName || msg.speakerName);
        if (speaker && scopedIds && !scopedIds.has(speaker.id)) speaker = null;
    }
    if (!speaker && msg.type === 'text') {
        const normalized = normalizeWechatGroupSpeechText(msg.content, group);
        if (normalized.member) {
            speaker = normalized.member;
            msg = { ...msg, content: normalized.text };
            if (speaker && scopedIds && !scopedIds.has(speaker.id)) speaker = null;
        }
    }
    if (!speaker) {
        const safeIndex = Math.max(0, Math.min(members.length - 1, Number(fallbackIndex) || 0));
        speaker = members[safeIndex] || members[0];
    }
    if (!speaker) return msg;

    return {
        ...msg,
        senderId: speaker.id,
        senderName: getWechatQQGroupMemberDisplayName(group, speaker)
    };
}

function getWechatGroupMessageSpeakerMember(group, msg) {
    if (!group?.isGroupChat || !msg || msg.isMe || msg.type === 'system_notice') return null;
    const direct = findWechatGroupMember(group, msg.senderId || msg.speakerId || msg.senderName || msg.speakerName);
    if (direct) return direct;
    if (msg.type === 'text') {
        const normalized = normalizeWechatGroupSpeechText(msg.content, group);
        if (normalized.member) return normalized.member;
    }
    return null;
}

function getWechatGroupMissingReplyMembers(group, startIndex) {
    if (!group?.isGroupChat || !Array.isArray(group.history)) return [];
    const spokenIds = new Set();
    group.history.slice(Math.max(0, startIndex || 0)).forEach(msg => {
        const member = getWechatGroupMessageSpeakerMember(group, msg);
        if (member && member.id) spokenIds.add(member.id);
    });
    return getWechatGroupMembers(group).filter(member => member && member.id && !spokenIds.has(member.id));
}

function getWechatGroupNextFallbackMembers(group, startIndex, preferredMembers = null) {
    if (!group?.isGroupChat) return [];
    const base = Array.isArray(preferredMembers) && preferredMembers.length
        ? preferredMembers.filter(Boolean)
        : getWechatGroupMembers(group);
    if (!base.length) return [];
    const spokenIds = new Set();
    if (Array.isArray(group.history)) {
        group.history.slice(Math.max(0, startIndex || 0)).forEach(msg => {
            const member = getWechatGroupMessageSpeakerMember(group, msg);
            if (member && member.id) spokenIds.add(member.id);
        });
    }
    const missing = base.filter(member => member && member.id && !spokenIds.has(member.id));
    return missing.length ? missing : base;
}

function getWechatLastVisibleMessageBefore(char, endIndex) {
    const history = Array.isArray(char?.history) ? char.history : [];
    for (let i = Math.min(history.length, endIndex || history.length) - 1; i >= 0; i--) {
        const msg = history[i];
        if (msg && msg.type !== 'system_notice') return msg;
    }
    return null;
}

function buildWechatGroupAvatar(group) {
    const members = Array.isArray(group?.groupMembers) ? group.groupMembers : [];
    const hue = Math.abs(String(group?.id || group?.name || 'group').split('').reduce((sum, ch) => sum + ch.charCodeAt(0), 0)) % 360;
    const label = group?.isGroupChat ? getWechatQQGroupDisplayMembers(group).length : (members.length || 'G');
    return 'data:image/svg+xml,' + encodeURIComponent(`
        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 120 120">
            <rect width="120" height="120" rx="24" fill="hsl(${hue},70%,92%)"/>
            <rect x="18" y="18" width="38" height="38" rx="12" fill="hsl(${hue},70%,58%)"/>
            <rect x="64" y="18" width="38" height="38" rx="12" fill="hsl(${(hue + 36) % 360},70%,66%)"/>
            <rect x="18" y="64" width="38" height="38" rx="12" fill="hsl(${(hue + 72) % 360},68%,72%)"/>
            <rect x="64" y="64" width="38" height="38" rx="12" fill="#ffffff"/>
            <text x="83" y="88" text-anchor="middle" font-family="Arial" font-size="24" font-weight="800" fill="hsl(${hue},54%,34%)">${label}</text>
        </svg>
    `);
}

function closeWechatPlusMenu() {
    document.getElementById('wc-plus-menu')?.remove();
}

function openWechatPlusMenu(event) {
    event?.stopPropagation?.();
    const old = document.getElementById('wc-plus-menu');
    if (old) {
        old.remove();
        return;
    }
    const root = document.getElementById('app-wechat-window');
    if (!root) return;
    const menu = document.createElement('div');
    menu.id = 'wc-plus-menu';
    const fromXFab = !!(event && event.currentTarget && event.currentTarget.closest && event.currentTarget.closest('.wc-x-compose-fab'));
    menu.className = `wc-plus-menu${fromXFab ? ' wc-plus-menu-x-fab' : ''}`;
    menu.innerHTML = `
        <button type="button" onclick="closeWechatPlusMenu();testAddCharacter()"><i class="ri-user-add-line"></i><span>导入角色</span></button>
        <button type="button" onclick="openWechatGroupCreator()"><i class="ri-group-line"></i><span>发起群聊</span></button>
        <button type="button" onclick="startWechatScreenShare()"><i class="ri-cast-line"></i><span>共享屏幕</span></button>
    `;
    root.appendChild(menu);
    setTimeout(() => {
        const closer = (ev) => {
            if (!ev.target.closest('#wc-plus-menu, .wc-header-right')) {
                closeWechatPlusMenu();
                document.removeEventListener('click', closer, true);
            }
        };
        document.addEventListener('click', closer, true);
    }, 0);
}
window.openWechatPlusMenu = openWechatPlusMenu;
window.closeWechatPlusMenu = closeWechatPlusMenu;

function openWechatSearch() {
    const root = document.getElementById('app-wechat-window');
    const input = document.getElementById('wc-search-input');
    if (!root || !input) return;
    closeWechatPlusMenu();
    root.classList.add('wc-search-open');
    requestAnimationFrame(() => {
        input.focus();
        input.select();
    });
}

function closeWechatSearch() {
    const root = document.getElementById('app-wechat-window');
    const input = document.getElementById('wc-search-input');
    if (input) input.value = '';
    filterChatList('');
    if (root) root.classList.remove('wc-search-open');
}

function getWechatMessageSearchText(msg) {
    if (!msg) return '';
    if (isWechatRegexPayloadMessage(msg)) return '';
    if (isWechatSpecialMessage(msg.type)) return getWechatMessageSummary(msg);
    if (msg.type === 'image') return '[图片]';
    if (msg.type === 'sticker') return msg.stickerName ? `[表情] ${msg.stickerName}` : '[表情]';
    if (msg.type === 'system_notice') return msg.content || '';
    return stripWechatPromptText(msg.content || msg.dialogue || msg.description || '', 260);
}

function renderWechatCurrentChatSearchResults(query = '') {
    const list = document.getElementById('wc-chat-message-search-results');
    if (!list) return;
    const char = getCurrentChatChar();
    if (!char) {
        list.innerHTML = '<div class="wc-chat-search-empty">没有打开聊天</div>';
        return;
    }
    const q = String(query || '').trim().toLowerCase();
    const history = Array.isArray(char.history) ? char.history : [];
    const rows = history
        .map((msg, index) => ({ msg, index, text: getWechatMessageSearchText(msg) }))
        .filter(item => item.text && item.msg && item.msg.type !== 'system_notice')
        .filter(item => !q || item.text.toLowerCase().includes(q))
        .slice(q ? 0 : Math.max(0, history.length - 24), q ? 80 : history.length)
        .reverse();
    if (!rows.length) {
        list.innerHTML = `<div class="wc-chat-search-empty">${q ? '没有搜到相关消息' : '还没有可搜索的消息'}</div>`;
        return;
    }
    list.innerHTML = rows.map(item => {
        const side = item.msg.isMe ? '你' : getWechatCharDisplayName(char);
        const time = formatMessageTime(item.msg);
        return `
            <button type="button" class="wc-chat-search-result" onclick="openWechatSearchResult(${Number(item.index)})">
                <b>${wcEscapeHtml(side)}</b>
                <span>${wcEscapeHtml(item.text)}</span>
                <em>${wcEscapeHtml(time)}</em>
            </button>
        `;
    }).join('');
}

function openWechatCurrentChatSearch() {
    const char = getCurrentChatChar();
    if (!char) {
        showWechatToast('先打开一个聊天');
        return;
    }
    closeChatToolbar();
    openWechatFeatureScreen('搜索消息', `
        <div class="wc-chat-search-page">
            <label class="wc-chat-search-box">
                <i class="ri-search-line"></i>
                <input id="wc-chat-message-search-input" placeholder="搜索当前聊天记录" oninput="renderWechatCurrentChatSearchResults(this.value)">
            </label>
            <div id="wc-chat-message-search-results" class="wc-chat-search-results"></div>
        </div>
    `);
    setWechatFeatureLeftText('取消', 'closeWechatFeatureScreen()');
    requestAnimationFrame(() => {
        document.getElementById('wc-chat-message-search-input')?.focus();
        renderWechatCurrentChatSearchResults('');
    });
}

function openWechatSearchResult(msgIdx) {
    const char = getCurrentChatChar();
    if (!char) return;
    window._wechatExpandedHistoryIds = window._wechatExpandedHistoryIds || new Set();
    window._wechatExpandedHistoryIds.add(char.id);
    closeWechatFeatureScreen();
    refreshChatView(char);
    setTimeout(() => {
        const row = document.querySelector(`.msg-row[data-msg-idx="${Number(msgIdx)}"]`);
        if (!row) return;
        row.scrollIntoView({ block: 'center', behavior: 'smooth' });
        row.classList.add('msg-source-highlight');
        setTimeout(() => row.classList.remove('msg-source-highlight'), 1600);
    }, 260);
}

window.openWechatSearch = openWechatSearch;
window.closeWechatSearch = closeWechatSearch;
window.openWechatCurrentChatSearch = openWechatCurrentChatSearch;
window.renderWechatCurrentChatSearchResults = renderWechatCurrentChatSearchResults;
window.openWechatSearchResult = openWechatSearchResult;

function openWechatGroupCreator() {
    closeWechatPlusMenu();
    const contacts = getWechatGroupContacts();
    window._wechatGroupDraftIds = Array.isArray(window._wechatGroupDraftIds) ? window._wechatGroupDraftIds.filter(id => contacts.some(c => c.id === id)) : [];
    const html = `
        <div class="wc-group-create">
            <div class="wc-group-create-top">
                <strong>选择联系人</strong>
                <span>从现有 AI 联系人里拉进群聊，至少选择 2 个。</span>
            </div>
            <input id="wc-group-name-input" class="wc-group-name-input" maxlength="24" placeholder="群聊名称，可留空自动生成">
            <div class="wc-group-select-list">
                ${contacts.length ? contacts.map(char => `
                    <button type="button" class="wc-group-select-item ${window._wechatGroupDraftIds.includes(char.id) ? 'active' : ''}" onclick="toggleWechatGroupDraftMember(${quoteWechatJsString(char.id)})">
                        <img src="${wcEscapeHtml(char.avatar || DEFAULT_AVATAR)}" onerror="this.src='${DEFAULT_AVATAR}'">
                        <span>${wcEscapeHtml((char.chatConfig && char.chatConfig.nickname) || char.name || '未命名')}</span>
                        <i class="${window._wechatGroupDraftIds.includes(char.id) ? 'ri-checkbox-circle-fill' : 'ri-add-circle-line'}"></i>
                    </button>
                `).join('') : '<div class="wc-contacts-empty">还没有可拉入群聊的联系人</div>'}
            </div>
            <button type="button" class="wc-group-create-btn" onclick="createWechatGroupChat()">创建群聊</button>
        </div>
    `;
    openWechatFeatureScreen('发起群聊', html);
}
window.openWechatGroupCreator = openWechatGroupCreator;
window.openWechatGroupCreate = openWechatGroupCreator;

function toggleWechatGroupDraftMember(charId) {
    const ids = Array.isArray(window._wechatGroupDraftIds) ? window._wechatGroupDraftIds : [];
    window._wechatGroupDraftIds = ids.includes(charId) ? ids.filter(id => id !== charId) : [...ids, charId];
    openWechatGroupCreator();
}
window.toggleWechatGroupDraftMember = toggleWechatGroupDraftMember;

function createWechatGroupChat() {
    const ids = Array.isArray(window._wechatGroupDraftIds) ? window._wechatGroupDraftIds : [];
    const members = ids.map(id => getWechatGroupContacts().find(char => char.id === id)).filter(Boolean);
    if (members.length < 2) {
        if (typeof showWechatToast === 'function') showWechatToast('至少选择 2 个联系人');
        return;
    }
    const inputName = (document.getElementById('wc-group-name-input')?.value || '').trim();
    const name = inputName || members.slice(0, 3).map(char => (char.chatConfig && char.chatConfig.nickname) || char.name || '好友').join('、') + (members.length > 3 ? ` 等${members.length}人` : '');
    const group = {
        id: 'group_' + Date.now(),
        name,
        description: '微信联系人群聊',
        avatar: '',
        isGroupChat: true,
        groupMembers: members.map(char => char.id),
        groupOwnerId: WECHAT_QQ_GROUP_USER_ID,
        groupCreatedAt: Date.now(),
        chatConfig: { qqGroupSettings: { ownerId: WECHAT_QQ_GROUP_USER_ID } },
        history: [
            { type: 'system_notice', isMe: false, content: `你邀请 ${members.map(char => (char.chatConfig && char.chatConfig.nickname) || char.name || '好友').join('、')} 加入了群聊`, timestamp: createMessageTimestamp() }
        ]
    };
    group.avatar = buildWechatGroupAvatar(group);
    window.myCharacters.unshift(group);
    window._wechatGroupDraftIds = [];
    saveCharactersToStorage();
    closeWechatFeatureScreen();
    switchWcTab('chat');
    renderChatList();
    openChat(group.id);
}
window.createWechatGroupChat = createWechatGroupChat;

function isWechatQQGroupSettingsAvailable(group) {
    return !!(group && group.isGroupChat && getWechatUiThemeId() === 'qq');
}

function syncWechatQQGroupSettingsEntry(group) {
    const wrap = document.getElementById('wcs-qq-group-entry-wrap');
    if (!wrap) return;
    const available = isWechatQQGroupSettingsAvailable(group);
    wrap.classList.toggle('hidden', !available);
    if (!available) return;
    const settings = getWechatQQGroupSettings(group);
    const summary = document.getElementById('wcs-qq-group-entry-summary');
    if (summary) {
        const count = getWechatQQGroupDisplayMembers(group).length;
        const tags = [
            `${count}人`,
            settings.pinned ? '已置顶' : '',
            settings.muteNotifications ? '免打扰' : '',
            settings.hideChat ? '隐藏预览' : ''
        ].filter(Boolean);
        summary.textContent = tags.join(' · ') || '群信息、成员、免打扰等';
    }
}

function ensureWechatQQGroupSettingsPage() {
    const panel = document.getElementById('wc-chat-settings-panel');
    if (!panel) return null;
    let page = document.getElementById('wcs-qq-group-settings-page');
    if (!page) {
        page = document.createElement('div');
        page.id = 'wcs-qq-group-settings-page';
        page.className = 'wcs-qq-group-subpage';
        panel.appendChild(page);
    }
    return page;
}

function closeWechatQQGroupSettings() {
    document.getElementById('wcs-qq-group-settings-page')?.classList.remove('active');
    document.getElementById('wcs-qq-group-resource-page')?.remove();
}

function renderWechatQQGroupMemberStrip(group) {
    const members = getWechatQQGroupDisplayMembers(group);
    const settings = getWechatQQGroupSettings(group);
    const inviteEnabled = getWechatQQGroupFlag(settings, 'memberInviteEnabled', true);
    const removeEnabled = getWechatQQGroupFlag(settings, 'memberRemoveEnabled', true);
    const people = members.map(member => ({
            id: member.id,
            name: getWechatQQGroupMemberDisplayName(group, member),
            avatar: member.avatar || DEFAULT_AVATAR,
            isUser: !!member.isUser
        }))
        .slice(0, 3);
    const avatars = people.map(person => `
        <button type="button" class="wcs-qq-member-mini" onclick="${person.isUser ? `openWechatQQGroupMemberSettings(${quoteWechatJsString(WECHAT_QQ_GROUP_USER_ID)})` : `openWechatContactProfile(${quoteWechatJsString(person.id)})`}">
            <img src="${wcEscapeAttr(person.avatar)}" onerror="this.src='${DEFAULT_AVATAR}'">
            <span><b>${wcEscapeHtml(person.name)}</b>${renderWechatQQGroupMemberBadge(group, person.id)}</span>
        </button>
    `).join('');
    return `
        ${avatars}
        <button type="button" class="wcs-qq-member-mini action" onclick="${inviteEnabled ? "openWechatQQGroupMemberPicker('add')" : 'openWechatQQGroupManagePage()'}"><i class="ri-add-line"></i><span>邀请</span></button>
        <button type="button" class="wcs-qq-member-mini action" onclick="${removeEnabled ? "openWechatQQGroupMemberPicker('remove')" : 'openWechatQQGroupManagePage()'}"><i class="ri-subtract-line"></i><span>移除</span></button>
    `;
}

function renderWechatQQGroupSettingsHtml(group) {
    const settings = getWechatQQGroupSettings(group);
    getWechatQQGroupOwnerId(group);
    const members = getWechatQQGroupDisplayMembers(group);
    const notificationMode = settings.notificationMode || (settings.muteNotifications ? 'silent' : 'all');
    const notifyText = notificationMode === 'blocked'
        ? '屏蔽群消息'
        : (notificationMode === 'silent' ? '接收消息但不提醒' : '接收并提醒');
    const groupRemarkText = settings.groupRemark || '未设置';
    const announcementText = settings.announcement || '未设置';
    const myNickText = settings.myNickname || '未设置';
    const personalityText = settings.personality || '群关系、标识佩戴等';
    return `
        <div class="wcs-qq-group-header">
            <i class="ri-arrow-left-s-line" onclick="closeWechatQQGroupSettings()"></i>
            <span>聊天信息</span>
            <i class="ri-more-fill"></i>
        </div>
        <div class="wcs-qq-group-body">
            <div class="wcs-qq-group-profile">
                <img src="${wcEscapeAttr(group.avatar || buildWechatGroupAvatar(group))}" onerror="this.src='${DEFAULT_AVATAR}'">
                <div>
                    <strong>${wcEscapeHtml(group.name || '群聊')}</strong>
                    <span>群号：${wcEscapeHtml(settings.groupNumber || buildWechatQQGroupNumber(group))}</span>
                    <em><i class="${settings.allowSearch ? 'ri-search-eye-line' : 'ri-lock-line'}"></i>${settings.allowSearch ? '允许被搜索' : '不允许被搜索'}</em>
                </div>
                <button type="button" class="wcs-qq-qr-btn" onclick="openWechatQQGroupQrCode()" aria-label="打开群二维码"><i class="ri-qr-code-line"></i></button>
            </div>

            <div class="wcs-qq-card member-card">
                <button type="button" class="wcs-qq-card-title" onclick="openWechatQQGroupMemberPicker('manage')">
                    <strong>群成员</strong><em>${members.length}人</em><i class="ri-arrow-right-s-line"></i>
                </button>
                <div class="wcs-qq-member-strip">${renderWechatQQGroupMemberStrip(group)}</div>
            </div>

            <div class="wcs-qq-card info-card">
                <button type="button" class="wcs-qq-link-row" onclick="openWechatQQGroupEditField('name')"><span>群名称</span><em>${wcEscapeHtml(group.name || '群聊')}</em><i class="ri-arrow-right-s-line"></i></button>
                <button type="button" class="wcs-qq-link-row" onclick="openWechatQQGroupEditField('remark')"><span>群备注</span><em>${wcEscapeHtml(groupRemarkText)}</em><i class="ri-arrow-right-s-line"></i></button>
                <button type="button" class="wcs-qq-link-row" onclick="openWechatQQGroupEditField('announcement')"><span>群公告</span><em>${wcEscapeHtml(announcementText)}</em><i class="ri-arrow-right-s-line"></i></button>
                <button type="button" class="wcs-qq-link-row" onclick="openWechatQQGroupManagePage()"><span>管理群</span><em>加群设置、发言管理等</em><i class="ri-arrow-right-s-line"></i></button>
            </div>

            <div class="wcs-qq-card apps">
                <button type="button" class="wcs-qq-card-title" onclick="openWechatQQGroupResource('files')">
                    <strong>群应用</strong><em></em><i class="ri-arrow-right-s-line"></i>
                </button>
                <div class="wcs-qq-app-grid">
                    <button type="button" onclick="openWechatQQGroupResource('files')"><i class="ri-folder-fill"></i><span>文件</span></button>
                    <button type="button" onclick="openWechatQQGroupResource('photos')"><i class="ri-image-fill"></i><span>相册</span></button>
                    <button type="button" onclick="openWechatQQGroupResource('highlights')"><i class="ri-star-smile-fill"></i><span>精华消息</span></button>
                </div>
                <label class="wcs-qq-switch-row"><span>群快捷栏</span><em>边聊边使用小程序、文档等</em><input type="checkbox" id="wcs-qq-group-shortcut" onchange="saveWechatQQGroupQuickSettings()" ${settings.shortcutBar ? 'checked' : ''}></label>
                <button type="button" class="wcs-qq-link-row" onclick="openWechatQQGroupRobotEditor()"><span>群机器人</span><em>${(settings.robots || []).length ? `${settings.robots.length}个` : '未添加'}</em><i class="ri-arrow-right-s-line"></i></button>
            </div>

            <div class="wcs-qq-card">
                <button type="button" class="wcs-qq-link-row" onclick="openWechatQQGroupSearchFromSettings()"><span>查找聊天记录</span><em>图片、视频、文件等</em><i class="ri-arrow-right-s-line"></i></button>
                <label class="wcs-qq-switch-row"><span>设为置顶</span><input type="checkbox" id="wcs-qq-group-pinned" onchange="saveWechatQQGroupQuickSettings()" ${settings.pinned ? 'checked' : ''}></label>
                <label class="wcs-qq-switch-row"><span>隐藏会话</span><input type="checkbox" id="wcs-qq-group-hide" onchange="saveWechatQQGroupQuickSettings()" ${settings.hideChat ? 'checked' : ''}></label>
                <label class="wcs-qq-switch-row"><span>消息免打扰</span><input type="checkbox" id="wcs-qq-group-mute" onchange="saveWechatQQGroupQuickSettings()" ${settings.muteNotifications ? 'checked' : ''}></label>
                <button type="button" class="wcs-qq-link-row ${notificationMode === 'blocked' ? 'disabled' : ''}" onclick="openWechatQQGroupNotificationPage()"><span>消息提醒方式</span><em>${wcEscapeHtml(notifyText)}</em><i class="ri-arrow-right-s-line"></i></button>
                <button type="button" class="wcs-qq-link-row muted"><span>消息通知设置</span><em>消息预览、提示音等</em><i class="ri-arrow-right-s-line"></i></button>
            </div>

            <div class="wcs-qq-card">
                <button type="button" class="wcs-qq-link-row" onclick="openWechatQQGroupEditField('myNickname')"><span>我在本群的昵称</span><em>${wcEscapeHtml(myNickText)}</em><i class="ri-arrow-right-s-line"></i></button>
                <button type="button" class="wcs-qq-link-row" onclick="openWechatQQGroupMemberPicker('manage')"><span>群成员备注与头衔</span><em>群主、管理员、专属头衔</em><i class="ri-arrow-right-s-line"></i></button>
                <button type="button" class="wcs-qq-link-row" onclick="openWechatQQGroupEditField('personality')"><span>个性设置</span><em>${wcEscapeHtml(personalityText)}</em><i class="ri-arrow-right-s-line"></i></button>
                <label class="wcs-qq-switch-row"><span>允许通过群号搜索</span><input type="checkbox" id="wcs-qq-group-searchable" onchange="saveWechatQQGroupQuickSettings()" ${settings.allowSearch ? 'checked' : ''}></label>
            </div>

            <div class="wcs-qq-card danger">
                <button type="button" onclick="clearCurrentWechatChatHistory()">删除聊天记录</button>
                <button type="button" class="danger" onclick="dismissWechatQQGroupChat()">解散群聊</button>
            </div>
        </div>
    `;
}

function openWechatQQGroupSettings() {
    const group = getCurrentChatChar();
    if (!isWechatQQGroupSettingsAvailable(group)) {
        showWechatToast('QQ 主题的群聊才有这个设置');
        return;
    }
    const page = ensureWechatQQGroupSettingsPage();
    if (!page) return;
    page.innerHTML = renderWechatQQGroupSettingsHtml(group);
    page.classList.add('active');
    page.querySelector('.wcs-qq-group-body')?.scrollTo?.(0, 0);
}
window.openWechatQQGroupSettings = openWechatQQGroupSettings;

function saveWechatQQGroupSettingsFromPanel() {
    const group = getCurrentChatChar();
    if (!group || !group.isGroupChat) return;
    const settings = getWechatQQGroupSettings(group);
    const prevName = group.name || '';
    const nameEl = document.getElementById('wcs-qq-group-name');
    const nextName = nameEl ? ((nameEl.value || '').trim() || prevName || '群聊') : (prevName || '群聊');
    group.name = nextName;
    const remarkEl = document.getElementById('wcs-qq-group-remark');
    const announcementEl = document.getElementById('wcs-qq-group-announcement');
    const myNickEl = document.getElementById('wcs-qq-group-my-nick');
    const personalityEl = document.getElementById('wcs-qq-group-personality');
    if (remarkEl) settings.groupRemark = (remarkEl.value || '').trim();
    if (announcementEl) settings.announcement = (announcementEl.value || '').trim();
    if (myNickEl) settings.myNickname = (myNickEl.value || '').trim();
    if (personalityEl) settings.personality = (personalityEl.value || '').trim();
    saveWechatQQGroupQuickSettings({ silent: true });
    group.chatConfig = group.chatConfig || {};
    group.chatConfig.qqGroupSettings = settings;
    if (!group.avatar || /^data:image\/svg\+xml/.test(group.avatar)) group.avatar = buildWechatGroupAvatar(group);
    if (prevName && prevName !== nextName) {
        group.history = Array.isArray(group.history) ? group.history : [];
        group.history.push({ type: 'system_notice', isMe: false, content: `群名称已修改为「${nextName}」`, timestamp: createMessageTimestamp() });
    }
    saveCharactersToStorage();
    applyChatConfig(group);
    refreshChatView(group);
    renderChatList();
    syncWechatQQGroupSettingsEntry(group);
    openWechatQQGroupSettings();
    showWechatToast('QQ群设置已保存');
}
window.saveWechatQQGroupSettingsFromPanel = saveWechatQQGroupSettingsFromPanel;

function saveWechatQQGroupQuickSettings(options = {}) {
    const group = getCurrentChatChar();
    if (!group || !group.isGroupChat) return;
    const settings = getWechatQQGroupSettings(group);
    const shortcutEl = document.getElementById('wcs-qq-group-shortcut');
    const pinnedEl = document.getElementById('wcs-qq-group-pinned');
    const hideEl = document.getElementById('wcs-qq-group-hide');
    const muteEl = document.getElementById('wcs-qq-group-mute');
    const searchableEl = document.getElementById('wcs-qq-group-searchable');
    if (shortcutEl) settings.shortcutBar = !!shortcutEl.checked;
    if (pinnedEl) settings.pinned = !!pinnedEl.checked;
    if (hideEl) settings.hideChat = !!hideEl.checked;
    if (muteEl) settings.muteNotifications = !!muteEl.checked;
    if (searchableEl) settings.allowSearch = !!searchableEl.checked;
    if (!settings.notificationMode) settings.notificationMode = settings.muteNotifications ? 'silent' : 'all';
    if (muteEl && settings.muteNotifications && settings.notificationMode === 'all') settings.notificationMode = 'silent';
    if (muteEl && !settings.muteNotifications && settings.notificationMode === 'silent') settings.notificationMode = 'all';
    group.chatConfig = group.chatConfig || {};
    group.chatConfig.qqGroupSettings = settings;
    saveCharactersToStorage();
    applyChatConfig(group);
    renderChatList();
    syncWechatQQGroupSettingsEntry(group);
    if (!options.silent) showWechatToast('QQ群设置已更新');
}
window.saveWechatQQGroupQuickSettings = saveWechatQQGroupQuickSettings;

function getWechatQQGroupEditFieldConfig(kind, group) {
    const settings = getWechatQQGroupSettings(group);
    const profile = getWechatQQGroupUserProfile(group);
    const map = {
        name: { title: '群名称', label: '群名称', value: group.name || '', placeholder: '输入群名称', max: 36, multiline: false },
        remark: { title: '群备注', label: '群备注', value: settings.groupRemark || '', placeholder: '未设置', max: 36, multiline: false },
        announcement: { title: '群公告', label: '群公告', value: settings.announcement || '', placeholder: '写一条群公告', max: 240, multiline: true },
        myNickname: { title: '我在本群的昵称', label: '本群昵称', value: settings.myNickname || profile.name || '', placeholder: '未设置', max: 24, multiline: false },
        personality: { title: '个性设置', label: '个性设置', value: settings.personality || '', placeholder: '群关系、标识佩戴等', max: 180, multiline: true }
    };
    return map[kind] || map.name;
}

function openWechatQQGroupEditField(kind) {
    const group = getCurrentChatChar();
    if (!group || !group.isGroupChat) return;
    const config = getWechatQQGroupEditFieldConfig(kind, group);
    const control = config.multiline
        ? `<textarea id="wcs-qq-edit-value" maxlength="${Number(config.max)}" rows="5" placeholder="${wcEscapeAttr(config.placeholder)}">${wcEscapeHtml(config.value)}</textarea>`
        : `<input id="wcs-qq-edit-value" maxlength="${Number(config.max)}" value="${wcEscapeAttr(config.value)}" placeholder="${wcEscapeAttr(config.placeholder)}">`;
    openWechatQQGroupResourceShell(config.title, `
        <div class="wcs-qq-card wcs-qq-editor-card">
            <label><span>${wcEscapeHtml(config.label)}</span>${control}</label>
        </div>
        <button type="button" class="wcs-qq-save" onclick="saveWechatQQGroupEditField(${quoteWechatJsString(kind)})">保存</button>
    `);
    requestAnimationFrame(() => document.getElementById('wcs-qq-edit-value')?.focus());
}
window.openWechatQQGroupEditField = openWechatQQGroupEditField;

function saveWechatQQGroupEditField(kind) {
    const group = getCurrentChatChar();
    if (!group || !group.isGroupChat) return;
    const settings = getWechatQQGroupSettings(group);
    const value = (document.getElementById('wcs-qq-edit-value')?.value || '').trim();
    const prevName = group.name || '';
    if (kind === 'name') {
        group.name = value || prevName || '群聊';
        if (prevName && prevName !== group.name) {
            group.history = Array.isArray(group.history) ? group.history : [];
            group.history.push({ type: 'system_notice', isMe: false, content: `群名称已修改为「${group.name}」`, timestamp: createMessageTimestamp() });
        }
    } else if (kind === 'remark') {
        settings.groupRemark = value;
    } else if (kind === 'announcement') {
        settings.announcement = value;
    } else if (kind === 'myNickname') {
        settings.myNickname = value;
    } else if (kind === 'personality') {
        settings.personality = value;
    }
    group.chatConfig = group.chatConfig || {};
    group.chatConfig.qqGroupSettings = settings;
    saveCharactersToStorage();
    refreshChatView(group);
    renderChatList();
    closeWechatQQGroupResource();
    openWechatQQGroupSettings();
    showWechatToast('已保存');
}
window.saveWechatQQGroupEditField = saveWechatQQGroupEditField;

function openWechatQQGroupNotificationPage() {
    const group = getCurrentChatChar();
    if (!group || !group.isGroupChat) return;
    const settings = getWechatQQGroupSettings(group);
    const mode = settings.notificationMode || (settings.muteNotifications ? 'silent' : 'all');
    const rows = [
        ['all', '接收并提醒', '正常显示未读和提醒'],
        ['silent', '接收消息但不提醒', '保留未读，不弹出提醒'],
        ['blocked', '屏蔽群消息', '不显示未读和桌面提醒']
    ];
    openWechatQQGroupResourceShell('消息提醒方式', `
        <div class="wcs-qq-card">
            ${rows.map(row => `
                <button type="button" class="wcs-qq-option-row ${mode === row[0] ? 'active' : ''}" onclick="setWechatQQGroupNotificationMode(${quoteWechatJsString(row[0])})">
                    <span><b>${wcEscapeHtml(row[1])}</b><em>${wcEscapeHtml(row[2])}</em></span>
                    <i class="${mode === row[0] ? 'ri-check-line' : ''}"></i>
                </button>
            `).join('')}
        </div>
    `);
}
window.openWechatQQGroupNotificationPage = openWechatQQGroupNotificationPage;

function setWechatQQGroupNotificationMode(mode) {
    const group = getCurrentChatChar();
    if (!group || !group.isGroupChat) return;
    const settings = getWechatQQGroupSettings(group);
    settings.notificationMode = ['all', 'silent', 'blocked'].includes(mode) ? mode : 'all';
    settings.muteNotifications = settings.notificationMode !== 'all';
    group.chatConfig = group.chatConfig || {};
    group.chatConfig.qqGroupSettings = settings;
    saveCharactersToStorage();
    renderChatList();
    syncWechatQQGroupSettingsEntry(group);
    openWechatQQGroupNotificationPage();
}
window.setWechatQQGroupNotificationMode = setWechatQQGroupNotificationMode;

function getWechatQQGroupQrCellDark(seed, x, y) {
    let hash = 2166136261;
    const text = `${seed}:${x}:${y}`;
    for (let i = 0; i < text.length; i++) {
        hash ^= text.charCodeAt(i);
        hash = Math.imul(hash, 16777619);
    }
    return (hash >>> 0) % 100 < 44;
}

function isWechatQQGroupQrFinderCell(x, y, ox, oy) {
    const dx = x - ox;
    const dy = y - oy;
    if (dx < 0 || dy < 0 || dx > 6 || dy > 6) return null;
    if (dx === 0 || dy === 0 || dx === 6 || dy === 6) return true;
    if (dx === 1 || dy === 1 || dx === 5 || dy === 5) return false;
    return true;
}

function renderWechatQQGroupQrGrid(group) {
    const settings = getWechatQQGroupSettings(group);
    const seed = `${settings.groupNumber}:${group.id || ''}`;
    const size = 21;
    let html = '';
    for (let y = 0; y < size; y++) {
        for (let x = 0; x < size; x++) {
            const finder = isWechatQQGroupQrFinderCell(x, y, 0, 0)
                ?? isWechatQQGroupQrFinderCell(x, y, size - 7, 0)
                ?? isWechatQQGroupQrFinderCell(x, y, 0, size - 7);
            const dark = finder == null ? getWechatQQGroupQrCellDark(seed, x, y) : finder;
            html += `<i class="${dark ? 'dark' : ''}"></i>`;
        }
    }
    return html;
}

function openWechatQQGroupQrCode() {
    const group = getCurrentChatChar();
    if (!group || !group.isGroupChat) return;
    const settings = getWechatQQGroupSettings(group);
    openWechatQQGroupResourceShell('群二维码', `
        <div class="wcs-qq-qr-card">
            <img src="${wcEscapeAttr(group.avatar || buildWechatGroupAvatar(group))}" onerror="this.src='${DEFAULT_AVATAR}'">
            <strong>${wcEscapeHtml(group.name || '群聊')}</strong>
            <span>群号：${wcEscapeHtml(settings.groupNumber)}</span>
            <div class="wcs-qq-qr-grid">${renderWechatQQGroupQrGrid(group)}</div>
            <em>二维码内容绑定当前群号，可用于展示和分享这个群。</em>
        </div>
    `);
}
window.openWechatQQGroupQrCode = openWechatQQGroupQrCode;

function openWechatQQGroupManagePage() {
    const group = getCurrentChatChar();
    if (!group || !group.isGroupChat) return;
    const settings = getWechatQQGroupSettings(group);
    const pendingIds = Array.isArray(settings.pendingMembers) ? settings.pendingMembers : [];
    const contacts = getWechatGroupContacts({ includeGroupNpc: true });
    const pendingRows = pendingIds
        .map(id => contacts.find(char => char.id === id))
        .filter(Boolean);
    openWechatQQGroupResourceShell('管理群', `
        <div class="wcs-qq-card">
            <label class="wcs-qq-switch-row"><span>允许成员邀请</span><em>关闭后邀请入口会进入管理页</em><input type="checkbox" id="wcs-qq-manage-invite" ${getWechatQQGroupFlag(settings, 'memberInviteEnabled', true) ? 'checked' : ''}></label>
            <label class="wcs-qq-switch-row"><span>允许移除成员</span><em>关闭后不能从群里移除角色</em><input type="checkbox" id="wcs-qq-manage-remove" ${getWechatQQGroupFlag(settings, 'memberRemoveEnabled', true) ? 'checked' : ''}></label>
            <label class="wcs-qq-switch-row"><span>精华消息</span><em>关闭后不能新增或取消精华</em><input type="checkbox" id="wcs-qq-manage-highlight" ${getWechatQQGroupFlag(settings, 'highlightEnabled', true) ? 'checked' : ''}></label>
            <label class="wcs-qq-switch-row"><span>群机器人</span><em>关闭后不能新增或删除机器人</em><input type="checkbox" id="wcs-qq-manage-robot" ${getWechatQQGroupFlag(settings, 'robotEnabled', true) ? 'checked' : ''}></label>
            <label class="wcs-qq-switch-row"><span>加群需要确认</span><em>邀请成员后先进入待审核</em><input type="checkbox" id="wcs-qq-manage-approval" ${settings.joinApproval ? 'checked' : ''}></label>
            <label class="wcs-qq-switch-row"><span>全员禁言</span><em>开启后不能在群内发送新消息</em><input type="checkbox" id="wcs-qq-manage-speech-muted" ${settings.speechMuted ? 'checked' : ''}></label>
        </div>
        <div class="wcs-qq-card">
            <button type="button" class="wcs-qq-link-row" onclick="openWechatQQGroupMemberPicker('add')"><span>邀请成员</span><em>${getWechatQQGroupFlag(settings, 'memberInviteEnabled', true) ? '可用' : '已关闭'}</em><i class="ri-arrow-right-s-line"></i></button>
            <button type="button" class="wcs-qq-link-row" onclick="openWechatQQGroupMemberPicker('remove')"><span>移除成员</span><em>${getWechatQQGroupFlag(settings, 'memberRemoveEnabled', true) ? '可用' : '已关闭'}</em><i class="ri-arrow-right-s-line"></i></button>
        </div>
        <div class="wcs-qq-card">
            <button type="button" class="wcs-qq-card-title">
                <strong>待审核成员</strong><em>${pendingRows.length}人</em><i></i>
            </button>
            <div class="wcs-qq-resource-list">
                ${pendingRows.length ? pendingRows.map(char => `
                    <button type="button">
                        <span>${wcEscapeHtml(getWechatGroupMemberName(char))}</span>
                        <em>
                            <b onclick="approveWechatQQGroupPendingMember(${quoteWechatJsString(char.id)})">同意</b>
                            <b onclick="rejectWechatQQGroupPendingMember(${quoteWechatJsString(char.id)})">拒绝</b>
                        </em>
                    </button>
                `).join('') : '<div class="wcs-qq-empty">暂无待审核成员。</div>'}
            </div>
        </div>
        <button type="button" class="wcs-qq-save" onclick="saveWechatQQGroupManageSettings()">保存管理设置</button>
    `);
}
window.openWechatQQGroupManagePage = openWechatQQGroupManagePage;

function saveWechatQQGroupManageSettings() {
    const group = getCurrentChatChar();
    if (!group || !group.isGroupChat) return;
    const settings = getWechatQQGroupSettings(group);
    settings.memberInviteEnabled = !!document.getElementById('wcs-qq-manage-invite')?.checked;
    settings.memberRemoveEnabled = !!document.getElementById('wcs-qq-manage-remove')?.checked;
    settings.highlightEnabled = !!document.getElementById('wcs-qq-manage-highlight')?.checked;
    settings.robotEnabled = !!document.getElementById('wcs-qq-manage-robot')?.checked;
    settings.joinApproval = !!document.getElementById('wcs-qq-manage-approval')?.checked;
    settings.speechMuted = !!document.getElementById('wcs-qq-manage-speech-muted')?.checked;
    group.chatConfig = group.chatConfig || {};
    group.chatConfig.qqGroupSettings = settings;
    saveCharactersToStorage();
    renderChatList();
    syncWechatQQGroupSettingsEntry(group);
    openWechatQQGroupManagePage();
    showWechatToast('管理设置已保存');
}
window.saveWechatQQGroupManageSettings = saveWechatQQGroupManageSettings;

function openWechatQQGroupMemberPicker(mode = 'manage') {
    const group = getCurrentChatChar();
    if (!group || !group.isGroupChat) return;
    const settings = getWechatQQGroupSettings(group);
    if (mode === 'add' && !getWechatQQGroupFlag(settings, 'memberInviteEnabled', true)) {
        showWechatToast('成员邀请已关闭');
        openWechatQQGroupManagePage();
        return;
    }
    if (mode === 'remove' && !getWechatQQGroupFlag(settings, 'memberRemoveEnabled', true)) {
        showWechatToast('成员移除已关闭');
        openWechatQQGroupManagePage();
        return;
    }
    const currentIds = new Set(Array.isArray(group.groupMembers) ? group.groupMembers : []);
    const contacts = getWechatGroupContacts({ includeGroupNpc: mode !== 'add' });
    const rows = mode === 'add'
        ? contacts.filter(char => !currentIds.has(char.id))
        : (mode === 'remove'
            ? contacts.filter(char => currentIds.has(char.id))
            : getWechatQQGroupDisplayMembers(group));
    const title = mode === 'add' ? '邀请成员' : (mode === 'remove' ? '移除成员' : '管理群成员');
    const action = mode === 'add' ? 'addWechatQQGroupMember' : (mode === 'remove' ? 'removeWechatQQGroupMember' : 'openWechatQQGroupMemberSettings');
    openWechatQQGroupResourceShell(title, `
        <div class="wcs-qq-picker-list">
            ${rows.length ? rows.map(char => `
                <button type="button" onclick="${action}(${quoteWechatJsString(char.id)})">
                    <img src="${wcEscapeAttr(char.avatar || DEFAULT_AVATAR)}" onerror="this.src='${DEFAULT_AVATAR}'">
                    <span><strong><b>${wcEscapeHtml(mode === 'add' ? getWechatGroupMemberName(char) : getWechatQQGroupMemberDisplayName(group, char))}</b>${mode === 'add' ? '' : renderWechatQQGroupMemberBadge(group, char.id)}</strong><em>${mode === 'add' ? '加入群聊' : (mode === 'remove' ? '从本群移除' : '群备注、身份、头衔')}</em></span>
                    <i class="${mode === 'add' ? 'ri-add-circle-line' : (mode === 'remove' ? 'ri-indeterminate-circle-line' : 'ri-settings-3-line')}"></i>
                </button>
            `).join('') : `<div class="wcs-qq-empty">${mode === 'add' ? '没有可邀请的联系人' : (mode === 'remove' ? '没有可移除的成员' : '还没有群成员')}</div>`}
        </div>
    `);
}
window.openWechatQQGroupMemberPicker = openWechatQQGroupMemberPicker;

function openWechatQQGroupMemberSettings(charId) {
    const group = getCurrentChatChar();
    const isUser = charId === WECHAT_QQ_GROUP_USER_ID;
    const member = isUser ? getWechatQQGroupUserMember(group) : getWechatGroupContacts({ includeGroupNpc: true }).find(char => char.id === charId);
    if (!group || !group.isGroupChat || !member) return;
    const profile = getWechatQQGroupMemberProfile(group, charId);
    const role = getWechatQQGroupMemberRole(group, charId);
    const isOwner = role === 'owner';
    openWechatQQGroupResourceShell('成员设置', `
        <div class="wcs-qq-member-editor">
            <div class="wcs-qq-member-editor-head">
                <img src="${wcEscapeAttr(member.avatar || DEFAULT_AVATAR)}" onerror="this.src='${DEFAULT_AVATAR}'">
                <div><strong>${wcEscapeHtml(getWechatQQGroupMemberDisplayName(group, member))}</strong>${renderWechatQQGroupMemberBadge(group, charId)}</div>
            </div>
            <div class="wcs-qq-card wcs-qq-editor-card">
                <label><span>群备注</span><input id="wcs-qq-member-remark" maxlength="24" value="${wcEscapeAttr(profile.remark || '')}" placeholder="${wcEscapeAttr(getWechatGroupMemberName(member))}"></label>
                <label><span>群身份</span><select id="wcs-qq-member-role" ${isOwner ? 'disabled' : ''}>
                    ${isOwner ? '<option value="owner" selected>群主</option>' : ''}
                    <option value="member" ${role === 'member' ? 'selected' : ''}>普通成员</option>
                    <option value="admin" ${role === 'admin' ? 'selected' : ''}>管理员</option>
                </select></label>
                <label><span>群头衔</span><input id="wcs-qq-member-title" maxlength="16" value="${wcEscapeAttr(profile.title || '')}" placeholder="${isOwner ? '群主' : (role === 'admin' ? '管理员' : '例如 学霸、摸鱼王')}"></label>
            </div>
            <button type="button" class="wcs-qq-save" onclick="saveWechatQQGroupMemberSettings(${quoteWechatJsString(charId)})">保存成员设置</button>
        </div>
    `);
}
window.openWechatQQGroupMemberSettings = openWechatQQGroupMemberSettings;

function saveWechatQQGroupMemberSettings(charId) {
    const group = getCurrentChatChar();
    const isUser = charId === WECHAT_QQ_GROUP_USER_ID;
    const member = isUser ? getWechatQQGroupUserMember(group) : getWechatGroupContacts({ includeGroupNpc: true }).find(char => char.id === charId);
    if (!group || !group.isGroupChat || !member) return;
    const profile = getWechatQQGroupMemberProfile(group, charId);
    const role = getWechatQQGroupMemberRole(group, charId);
    profile.remark = (document.getElementById('wcs-qq-member-remark')?.value || '').trim();
    profile.title = (document.getElementById('wcs-qq-member-title')?.value || '').trim();
    profile.role = isUser || role === 'owner' ? 'owner' : (document.getElementById('wcs-qq-member-role')?.value === 'admin' ? 'admin' : 'member');
    if (isUser) {
        const settingsForNick = getWechatQQGroupSettings(group);
        settingsForNick.myNickname = profile.remark;
    }
    const settings = getWechatQQGroupSettings(group);
    if (isUser) {
        settings.ownerId = WECHAT_QQ_GROUP_USER_ID;
        group.groupOwnerId = WECHAT_QQ_GROUP_USER_ID;
    }
    settings.memberProfiles = getWechatQQGroupMemberProfiles(group);
    group.chatConfig = group.chatConfig || {};
    group.chatConfig.qqGroupSettings = settings;
    saveCharactersToStorage();
    refreshChatView(group);
    renderChatList();
    syncWechatQQGroupSettingsEntry(group);
    openWechatQQGroupMemberPicker('manage');
    showWechatToast('成员设置已保存');
}
window.saveWechatQQGroupMemberSettings = saveWechatQQGroupMemberSettings;

function addWechatQQGroupMember(charId) {
    const group = getCurrentChatChar();
    const member = getWechatGroupContacts({ includeGroupNpc: true }).find(char => char.id === charId);
    if (!group || !group.isGroupChat || !member) return;
    const settings = getWechatQQGroupSettings(group);
    if (!getWechatQQGroupFlag(settings, 'memberInviteEnabled', true)) {
        showWechatToast('成员邀请已关闭');
        openWechatQQGroupManagePage();
        return;
    }
    group.groupMembers = Array.isArray(group.groupMembers) ? group.groupMembers : [];
    if (settings.joinApproval) {
        settings.pendingMembers = Array.isArray(settings.pendingMembers) ? settings.pendingMembers : [];
        if (!group.groupMembers.includes(charId) && !settings.pendingMembers.includes(charId)) {
            settings.pendingMembers.push(charId);
            group.history = Array.isArray(group.history) ? group.history : [];
            group.history.push({ type: 'system_notice', isMe: false, content: `${getWechatGroupMemberName(member)} 的入群邀请已进入审核`, timestamp: createMessageTimestamp() });
            saveCharactersToStorage();
            refreshChatView(group);
            renderChatList();
        }
        closeWechatQQGroupResource();
        openWechatQQGroupManagePage();
        showWechatToast('已加入待审核');
        return;
    }
    if (!group.groupMembers.includes(charId)) {
        group.groupMembers.push(charId);
        getWechatQQGroupOwnerId(group);
        group.avatar = buildWechatGroupAvatar(group);
        group.history = Array.isArray(group.history) ? group.history : [];
        group.history.push({ type: 'system_notice', isMe: false, content: `你邀请 ${getWechatGroupMemberName(member)} 加入了群聊`, timestamp: createMessageTimestamp() });
        saveCharactersToStorage();
        refreshChatView(group);
        renderChatList();
        syncWechatQQGroupSettingsEntry(group);
    }
    closeWechatQQGroupResource();
    openWechatQQGroupSettings();
}
window.addWechatQQGroupMember = addWechatQQGroupMember;

function removeWechatQQGroupMember(charId) {
    const group = getCurrentChatChar();
    if (!group || !group.isGroupChat) return;
    if (charId === WECHAT_QQ_GROUP_USER_ID) {
        showWechatToast('群主不能从自己创建的群里移除');
        return;
    }
    const settings = getWechatQQGroupSettings(group);
    if (!getWechatQQGroupFlag(settings, 'memberRemoveEnabled', true)) {
        showWechatToast('成员移除已关闭');
        openWechatQQGroupManagePage();
        return;
    }
    const members = Array.isArray(group.groupMembers) ? group.groupMembers : [];
    if (members.length <= 1) {
        showWechatToast('群里至少保留 1 个角色成员');
        return;
    }
    const member = getWechatGroupContacts({ includeGroupNpc: true }).find(char => char.id === charId);
    group.groupMembers = members.filter(id => id !== charId);
    getWechatQQGroupOwnerId(group);
    group.avatar = buildWechatGroupAvatar(group);
    group.history = Array.isArray(group.history) ? group.history : [];
    group.history.push({ type: 'system_notice', isMe: false, content: `你将 ${getWechatGroupMemberName(member)} 移出了群聊`, timestamp: createMessageTimestamp() });
    saveCharactersToStorage();
    refreshChatView(group);
    renderChatList();
    syncWechatQQGroupSettingsEntry(group);
    closeWechatQQGroupResource();
    openWechatQQGroupSettings();
}
window.removeWechatQQGroupMember = removeWechatQQGroupMember;

function approveWechatQQGroupPendingMember(charId) {
    const group = getCurrentChatChar();
    const member = getWechatGroupContacts({ includeGroupNpc: true }).find(char => char.id === charId);
    if (!group || !group.isGroupChat || !member) return;
    const settings = getWechatQQGroupSettings(group);
    settings.pendingMembers = (Array.isArray(settings.pendingMembers) ? settings.pendingMembers : []).filter(id => id !== charId);
    group.groupMembers = Array.isArray(group.groupMembers) ? group.groupMembers : [];
    if (!group.groupMembers.includes(charId)) {
        group.groupMembers.push(charId);
        getWechatQQGroupOwnerId(group);
        group.avatar = buildWechatGroupAvatar(group);
        group.history = Array.isArray(group.history) ? group.history : [];
        group.history.push({ type: 'system_notice', isMe: false, content: `已同意 ${getWechatGroupMemberName(member)} 加入群聊`, timestamp: createMessageTimestamp() });
    }
    saveCharactersToStorage();
    refreshChatView(group);
    renderChatList();
    syncWechatQQGroupSettingsEntry(group);
    openWechatQQGroupManagePage();
}
window.approveWechatQQGroupPendingMember = approveWechatQQGroupPendingMember;

function rejectWechatQQGroupPendingMember(charId) {
    const group = getCurrentChatChar();
    const member = getWechatGroupContacts({ includeGroupNpc: true }).find(char => char.id === charId);
    if (!group || !group.isGroupChat) return;
    const settings = getWechatQQGroupSettings(group);
    settings.pendingMembers = (Array.isArray(settings.pendingMembers) ? settings.pendingMembers : []).filter(id => id !== charId);
    group.history = Array.isArray(group.history) ? group.history : [];
    if (member) group.history.push({ type: 'system_notice', isMe: false, content: `已拒绝 ${getWechatGroupMemberName(member)} 的入群申请`, timestamp: createMessageTimestamp() });
    saveCharactersToStorage();
    refreshChatView(group);
    renderChatList();
    syncWechatQQGroupSettingsEntry(group);
    openWechatQQGroupManagePage();
}
window.rejectWechatQQGroupPendingMember = rejectWechatQQGroupPendingMember;

function openWechatQQGroupResourceShell(title, bodyHtml) {
    const host = document.getElementById('wcs-qq-group-settings-page') || ensureWechatQQGroupSettingsPage();
    if (!host) return;
    document.getElementById('wcs-qq-group-resource-page')?.remove();
    const page = document.createElement('div');
    page.id = 'wcs-qq-group-resource-page';
    page.className = 'wcs-qq-group-subpage wcs-qq-resource-page active';
    page.innerHTML = `
        <div class="wcs-qq-group-header">
            <i class="ri-arrow-left-s-line" onclick="closeWechatQQGroupResource()"></i>
            <span>${wcEscapeHtml(title)}</span>
            <i></i>
        </div>
        <div class="wcs-qq-group-body">${bodyHtml}</div>
    `;
    host.appendChild(page);
}

function closeWechatQQGroupResource() {
    document.getElementById('wcs-qq-group-resource-page')?.remove();
}
window.closeWechatQQGroupResource = closeWechatQQGroupResource;

function getWechatQQGroupResourceRows(group, type) {
    const history = Array.isArray(group?.history) ? group.history : [];
    return history.map((msg, index) => ({ msg, index })).filter(row => {
        const msg = row.msg || {};
        if (msg.type === 'system_notice') return false;
        if (type === 'files') return msg.type === 'file' || msg.fileName || msg.fileUrl || msg.attachmentName;
        if (type === 'photos') return msg.type === 'image' || isWechatReplyMediaSource(msg.content || msg.image || msg.url || '');
        if (type === 'highlights') return !!msg.qqGroupHighlight;
        return false;
    });
}

function openWechatQQGroupResource(type) {
    const group = getCurrentChatChar();
    if (!group || !group.isGroupChat) return;
    const settings = getWechatQQGroupSettings(group);
    const titleMap = { files: '群文件', photos: '群相册', highlights: '精华消息' };
    const rows = getWechatQQGroupResourceRows(group, type);
    let body = '';
    if (type === 'photos') {
        body = rows.length ? `<div class="wcs-qq-photo-grid">${rows.map(row => {
            const src = row.msg.content || row.msg.image || row.msg.url || '';
            return `<button type="button" onclick="openWechatImagePreview(${quoteWechatJsString(src)})"><img src="${wcEscapeAttr(src)}" onerror="this.closest('button').remove()"></button>`;
        }).join('')}</div>` : '<div class="wcs-qq-empty">这群还没有真实图片消息。</div>';
    } else if (type === 'highlights') {
        if (!getWechatQQGroupFlag(settings, 'highlightEnabled', true)) {
            body = '<div class="wcs-qq-empty">精华消息功能已在管理群中关闭。</div>';
            openWechatQQGroupResourceShell(titleMap[type] || '群应用', body);
            return;
        }
        const recent = (Array.isArray(group.history) ? group.history : [])
            .map((msg, index) => ({ msg, index }))
            .filter(row => row.msg && row.msg.type !== 'system_notice')
            .slice(-30)
            .reverse();
        body = `
            <div class="wcs-qq-resource-list">
                ${recent.length ? recent.map(row => `
                    <button type="button" class="${row.msg.qqGroupHighlight ? 'active' : ''}" onclick="toggleWechatQQGroupHighlight(${Number(row.index)})">
                        <span>${wcEscapeHtml(getWechatMessagePlainSummary(row.msg, 80))}</span>
                        <em>${row.msg.qqGroupHighlight ? '取消精华' : '设为精华'}</em>
                    </button>
                `).join('') : '<div class="wcs-qq-empty">还没有可设置为精华的消息。</div>'}
            </div>
        `;
    } else {
        body = rows.length ? `<div class="wcs-qq-resource-list">${rows.map(row => `
            <button type="button" onclick="openWechatSearchResult(${Number(row.index)})">
                <span>${wcEscapeHtml(row.msg.fileName || row.msg.attachmentName || getWechatMessagePlainSummary(row.msg, 80))}</span>
                <em>${wcEscapeHtml(formatMessageTime(row.msg))}</em>
            </button>
        `).join('')}</div>` : '<div class="wcs-qq-empty">这群还没有真实文件消息。</div>';
    }
    openWechatQQGroupResourceShell(titleMap[type] || '群应用', body);
}
window.openWechatQQGroupResource = openWechatQQGroupResource;

function toggleWechatQQGroupHighlight(index) {
    const group = getCurrentChatChar();
    const settings = getWechatQQGroupSettings(group);
    if (!getWechatQQGroupFlag(settings, 'highlightEnabled', true)) {
        showWechatToast('精华消息功能已关闭');
        return;
    }
    const msg = group && Array.isArray(group.history) ? group.history[index] : null;
    if (!msg || msg.type === 'system_notice') return;
    msg.qqGroupHighlight = !msg.qqGroupHighlight;
    saveCharactersToStorage();
    openWechatQQGroupResource('highlights');
}
window.toggleWechatQQGroupHighlight = toggleWechatQQGroupHighlight;

function normalizeWechatQQGroupRobots(settings) {
    settings.robots = (Array.isArray(settings.robots) ? settings.robots : [])
        .map((item, index) => {
            if (typeof item === 'string') {
                return { id: `robot-${Date.now()}-${index}`, name: item, remark: '', persona: '' };
            }
            if (!item || typeof item !== 'object') return null;
            const name = String(item.name || item.title || '').trim();
            if (!name) return null;
            return {
                id: item.id || `robot-${Date.now()}-${index}`,
                name,
                remark: String(item.remark || item.note || '').trim(),
                persona: String(item.persona || item.prompt || item.character || '').trim()
            };
        })
        .filter(Boolean);
    return settings.robots;
}

function openWechatQQGroupRobotEditor(editIndex = -1) {
    const group = getCurrentChatChar();
    if (!group || !group.isGroupChat) return;
    const settings = getWechatQQGroupSettings(group);
    const robots = normalizeWechatQQGroupRobots(settings);
    const index = Number.isFinite(Number(editIndex)) ? Number(editIndex) : -1;
    const editing = index >= 0 ? robots[index] : null;
    if (!getWechatQQGroupFlag(settings, 'robotEnabled', true)) {
        openWechatQQGroupResourceShell('群机器人', '<div class="wcs-qq-empty">群机器人已在管理群中关闭。</div>');
        return;
    }
    openWechatQQGroupResourceShell('群机器人', `
        <div class="wcs-qq-robot-editor">
            <div class="wcs-qq-card wcs-qq-robot-form">
                <input type="hidden" id="wcs-qq-robot-index" value="${editing ? Number(index) : -1}">
                <label><span>机器人名称</span><input id="wcs-qq-robot-name" maxlength="24" value="${wcEscapeAttr(editing?.name || '')}" placeholder="机器人名称"></label>
                <label><span>备注</span><input id="wcs-qq-robot-remark" maxlength="40" value="${wcEscapeAttr(editing?.remark || '')}" placeholder="例如 负责提醒、整理文件"></label>
                <label><span>人设</span><textarea id="wcs-qq-robot-persona" maxlength="500" rows="4" placeholder="写这个机器人在群里的语气、职责和边界">${wcEscapeHtml(editing?.persona || '')}</textarea></label>
                <button type="button" class="wcs-qq-save" onclick="saveWechatQQGroupRobot()">${editing ? '保存机器人' : '添加机器人'}</button>
            </div>
            <div class="wcs-qq-robot-list">
                ${robots.length ? robots.map((robot, index) => `
                    <div class="wcs-qq-robot-row">
                        <button type="button" onclick="openWechatQQGroupRobotEditor(${Number(index)})">
                            <span><b>${wcEscapeHtml(robot.name)}</b><em>${wcEscapeHtml(robot.remark || robot.persona || '未设置备注和人设')}</em></span>
                            <i class="ri-edit-2-line"></i>
                        </button>
                        <button type="button" class="danger" onclick="removeWechatQQGroupRobot(${Number(index)})"><i class="ri-close-line"></i></button>
                    </div>
                `).join('') : '<div class="wcs-qq-empty">还没有添加群机器人。</div>'}
            </div>
        </div>
    `);
}
window.openWechatQQGroupRobotEditor = openWechatQQGroupRobotEditor;

function saveWechatQQGroupRobot() {
    const group = getCurrentChatChar();
    const name = (document.getElementById('wcs-qq-robot-name')?.value || '').trim();
    if (!group || !name) return;
    const settings = getWechatQQGroupSettings(group);
    if (!getWechatQQGroupFlag(settings, 'robotEnabled', true)) {
        showWechatToast('群机器人已关闭');
        return;
    }
    const robots = normalizeWechatQQGroupRobots(settings);
    const index = Number(document.getElementById('wcs-qq-robot-index')?.value || -1);
    const prev = Number.isInteger(index) && index >= 0 ? robots[index] : null;
    const next = {
        id: prev?.id || `robot-${Date.now()}`,
        name,
        remark: (document.getElementById('wcs-qq-robot-remark')?.value || '').trim(),
        persona: (document.getElementById('wcs-qq-robot-persona')?.value || '').trim()
    };
    if (prev) robots[index] = next;
    else robots.push(next);
    settings.robots = robots;
    saveCharactersToStorage();
    openWechatQQGroupRobotEditor();
}
window.saveWechatQQGroupRobot = saveWechatQQGroupRobot;
window.addWechatQQGroupRobot = saveWechatQQGroupRobot;

function removeWechatQQGroupRobot(index) {
    const group = getCurrentChatChar();
    if (!group) return;
    const settings = getWechatQQGroupSettings(group);
    if (!getWechatQQGroupFlag(settings, 'robotEnabled', true)) {
        showWechatToast('群机器人已关闭');
        return;
    }
    const robots = normalizeWechatQQGroupRobots(settings);
    robots.splice(index, 1);
    settings.robots = robots;
    saveCharactersToStorage();
    openWechatQQGroupRobotEditor();
}
window.removeWechatQQGroupRobot = removeWechatQQGroupRobot;

function dismissWechatQQGroupChat() {
    const group = getCurrentChatChar();
    if (!group || !group.isGroupChat) return;
    if (!confirm(`确定解散「${group.name || '群聊'}」吗？\n会删除这个群聊和群聊天记录，不会删除群成员角色卡。`)) return;
    window.myCharacters = (window.myCharacters || []).filter(char => char.id !== group.id);
    window.currentChatCharId = null;
    closeWechatQQGroupSettings();
    closeChatSettings();
    const room = document.getElementById('wechat-chat-room');
    if (room) {
        room.classList.remove('active');
        room.classList.add('hidden');
    }
    saveCharactersToStorage();
    renderChatList();
    switchWcTab('chat');
    showWechatToast('群聊已解散');
}
window.dismissWechatQQGroupChat = dismissWechatQQGroupChat;

function syncWechatQQGroupShortcutBar(group) {
    const room = document.getElementById('wechat-chat-room');
    if (!room) return;
    let bar = document.getElementById('wc-qq-group-shortcut-bar');
    const settings = group && group.isGroupChat ? getWechatQQGroupSettings(group) : {};
    const enabled = !!(group && group.isGroupChat && settings.shortcutBar);
    room.classList.toggle('qq-group-shortcuts-on', enabled);
    if (!enabled) {
        if (bar) bar.remove();
        return;
    }
    if (!bar) {
        bar = document.createElement('div');
        bar.id = 'wc-qq-group-shortcut-bar';
        bar.className = 'wc-qq-group-shortcut-bar';
        const footer = room.querySelector('.wc-room-footer');
        if (footer) room.insertBefore(bar, footer);
        else room.appendChild(bar);
    }
    bar.innerHTML = `
        <button type="button" onclick="openWechatQQGroupShortcutFeature('files')"><i class="ri-folder-line"></i><span>文件</span></button>
        <button type="button" onclick="openWechatQQGroupShortcutFeature('photos')"><i class="ri-image-line"></i><span>相册</span></button>
        <button type="button" onclick="openWechatQQGroupShortcutFeature('highlights')"><i class="ri-star-smile-line"></i><span>精华</span></button>
        <button type="button" onclick="openWechatCurrentChatSearch()"><i class="ri-search-line"></i><span>查找</span></button>
    `;
}

function renderWechatQQGroupFeatureResourceHtml(type) {
    const group = getCurrentChatChar();
    if (!group || !group.isGroupChat) return '<div class="wcs-qq-empty">没有打开群聊。</div>';
    const rows = getWechatQQGroupResourceRows(group, type);
    if (type === 'photos') {
        return rows.length ? `<div class="wcs-qq-photo-grid feature">${rows.map(row => {
            const src = row.msg.content || row.msg.image || row.msg.url || '';
            return `<button type="button" onclick="openWechatImagePreview(${quoteWechatJsString(src)})"><img src="${wcEscapeAttr(src)}" onerror="this.closest('button').remove()"></button>`;
        }).join('')}</div>` : '<div class="wcs-qq-empty">这群还没有真实图片消息。</div>';
    }
    if (type === 'highlights') {
        const settings = getWechatQQGroupSettings(group);
        if (!getWechatQQGroupFlag(settings, 'highlightEnabled', true)) return '<div class="wcs-qq-empty">精华消息功能已在管理群中关闭。</div>';
        const recent = (Array.isArray(group.history) ? group.history : [])
            .map((msg, index) => ({ msg, index }))
            .filter(row => row.msg && row.msg.type !== 'system_notice')
            .slice(-30)
            .reverse();
        return `<div class="wcs-qq-resource-list feature">
            ${recent.length ? recent.map(row => `
                <button type="button" class="${row.msg.qqGroupHighlight ? 'active' : ''}" onclick="toggleWechatQQGroupHighlightFromFeature(${Number(row.index)})">
                    <span>${wcEscapeHtml(getWechatMessagePlainSummary(row.msg, 80))}</span>
                    <em>${row.msg.qqGroupHighlight ? '取消精华' : '设为精华'}</em>
                </button>
            `).join('') : '<div class="wcs-qq-empty">还没有可设置为精华的消息。</div>'}
        </div>`;
    }
    return rows.length ? `<div class="wcs-qq-resource-list feature">${rows.map(row => `
        <button type="button" onclick="openWechatSearchResult(${Number(row.index)})">
            <span>${wcEscapeHtml(row.msg.fileName || row.msg.attachmentName || getWechatMessagePlainSummary(row.msg, 80))}</span>
            <em>${wcEscapeHtml(formatMessageTime(row.msg))}</em>
        </button>
    `).join('')}</div>` : '<div class="wcs-qq-empty">这群还没有真实文件消息。</div>';
}

function openWechatQQGroupShortcutFeature(type) {
    const titleMap = { files: '群文件', photos: '群相册', highlights: '精华消息' };
    closeChatToolbar();
    openWechatFeatureScreen(titleMap[type] || '群应用', renderWechatQQGroupFeatureResourceHtml(type));
    setWechatFeatureLeftText('取消', 'closeWechatFeatureScreen()');
}
window.openWechatQQGroupShortcutFeature = openWechatQQGroupShortcutFeature;

function openWechatQQGroupSearchFromSettings() {
    closeWechatQQGroupSettings();
    closeChatSettings();
    setTimeout(() => openWechatCurrentChatSearch(), 320);
}
window.openWechatQQGroupSearchFromSettings = openWechatQQGroupSearchFromSettings;

function toggleWechatQQGroupHighlightFromFeature(index) {
    const group = getCurrentChatChar();
    const settings = getWechatQQGroupSettings(group);
    if (!getWechatQQGroupFlag(settings, 'highlightEnabled', true)) {
        showWechatToast('精华消息功能已关闭');
        return;
    }
    const msg = group && Array.isArray(group.history) ? group.history[index] : null;
    if (!msg || msg.type === 'system_notice') return;
    msg.qqGroupHighlight = !msg.qqGroupHighlight;
    saveCharactersToStorage();
    const body = document.getElementById('wc-feature-body');
    const title = document.getElementById('wc-feature-title');
    if (body && title && title.textContent === '精华消息') body.innerHTML = renderWechatQQGroupFeatureResourceHtml('highlights');
}
window.toggleWechatQQGroupHighlightFromFeature = toggleWechatQQGroupHighlightFromFeature;

function getWechatChatListTimestamp(char) {
    const msg = getWechatLastChatMessage(char);
    const raw = msg && (msg.timestamp || msg.createdAt || msg.time);
    if (raw) return raw;
    return char?.importedAt || char?.createdAt || char?.created_at || char?.importTime || char?.updatedAt || '';
}

function formatWechatChatListTime(char) {
    const raw = getWechatChatListTimestamp(char);
    if (!raw) return '现在';
    const date = new Date(raw);
    if (Number.isNaN(date.getTime())) return '现在';
    const now = new Date();
    const diff = now.getTime() - date.getTime();
    if (diff < 60 * 1000) return '刚刚';
    if (diff < 60 * 60 * 1000) return `${Math.max(1, Math.floor(diff / 60000))}分钟前`;
    const sameDay = date.getFullYear() === now.getFullYear()
        && date.getMonth() === now.getMonth()
        && date.getDate() === now.getDate();
    if (sameDay) return `${padWechatDatePart(date.getHours())}:${padWechatDatePart(date.getMinutes())}`;
    const yesterday = new Date(now);
    yesterday.setDate(now.getDate() - 1);
    const isYesterday = date.getFullYear() === yesterday.getFullYear()
        && date.getMonth() === yesterday.getMonth()
        && date.getDate() === yesterday.getDate();
    if (isYesterday) return '昨天';
    if (date.getFullYear() === now.getFullYear()) return `${date.getMonth() + 1}/${date.getDate()}`;
    return `${date.getFullYear()}/${date.getMonth() + 1}/${date.getDate()}`;
}

function getChatPreview(char) {
    const last = getWechatLastChatMessage(char);
    if (!last) return '';
    if (last.type === 'image') return last.isMe ? '[图片]' : '[对方发来图片]';
    if (last.type === 'sticker') {
        const name = last.stickerName || last.name || '';
        if ((last.emoji || last.stickerKind === 'wechatEmoji' || isWechatBuiltinEmojiUrl(last.content)) && name) {
            const source = last.stickerKind === 'qqEmoji' ? 'qq' : getWechatBuiltinEmojiSourceFromUrl(last.content);
            return `${last.isMe ? '' : '对方发来 '}${buildWechatBuiltinEmojiMarker(name, source, last.content || '')}`;
        }
        return last.isMe ? '[表情]' : '[对方发来表情]';
    }
    if (isWechatSpecialMessage(last.type)) return getWechatMessageSummary(last);
    const text = String(last.content || last.dialogue || last.description || '')
        .replace(/<[^>]+>/g, '')
        .replace(/\s+/g, ' ')
        .trim();
    return text || '[消息]';
}

function filterChatList(keyword) {
    const items = document.querySelectorAll('#wc-chat-list .wc-swipe-container');
    const kw = keyword.trim().toLowerCase();
    items.forEach(container => {
        const charId = container.dataset.charId;
        const char = window.myCharacters.find(c => c.id === charId);
        if (!char) return;
        const nickname = (char.chatConfig && char.chatConfig.nickname) || '';
        const qqGroup = char.isGroupChat ? getWechatQQGroupSettings(char) : {};
        const groupNumber = qqGroup.allowSearch ? String(qqGroup.groupNumber || '') : '';
        const groupRemark = qqGroup.groupRemark || '';
        const match = !kw
            || String(char.name || '').toLowerCase().includes(kw)
            || nickname.toLowerCase().includes(kw)
            || String(groupRemark).toLowerCase().includes(kw)
            || groupNumber.includes(kw);
        container.style.display = match ? '' : 'none';
    });
}

// 通用工具：正则替换 + Markdown 清洗
function getWechatDisplayUserName() {
    const profile = typeof getUserProfile === 'function' ? getUserProfile() : {};
    return (profile && profile.name) || '我';
}

function getWechatDisplayCharName(char) {
    if (!char) return '';
    return (char.chatConfig && char.chatConfig.nickname) || char.name || '';
}

function fillWechatRegexTemplate(value, char) {
    return String(value == null ? '' : value)
        .replace(/\{\{char\}\}/gi, getWechatDisplayCharName(char))
        .replace(/\{\{user\}\}/gi, getWechatDisplayUserName());
}

function getWechatRegexScriptField(script, keys) {
    if (!script || typeof script !== 'object') return '';
    for (const key of keys) {
        if (script[key] != null && script[key] !== '') return script[key];
    }
    const common = {
        findRegex: ['find_regex', 'find', 'match', 'matcher', 'regexPattern', 'regex_pattern'],
        replaceString: ['replace_string', 'replaceWith', 'replace_with', 'replacement', 'substitute_regex', 'substituteRegex']
    };
    for (const key of keys) {
        const aliases = common[key] || [];
        for (const alias of aliases) {
            if (script[alias] != null && script[alias] !== '') return script[alias];
        }
    }
    if (script.script && typeof script.script === 'object') {
        return getWechatRegexScriptField(script.script, keys);
    }
    return '';
}

function isWechatRegexScriptEnabled(script) {
    if (!script || typeof script !== 'object') return false;
    if (script.enabled === false || script.disabled === true || script.isDisabled === true) return false;
    if (script.use_regex === false || script.useRegex === false) return false;
    if (String(script.enabled).toLowerCase() === 'false') return false;
    if (String(script.disabled).toLowerCase() === 'true') return false;
    if (String(script.use_regex).toLowerCase() === 'false') return false;
    if (String(script.useRegex).toLowerCase() === 'false') return false;
    return true;
}

function renderWechatMarkdownLite(text) {
    let html = wcEscapeHtml(text);
    const codeSpans = [];
    html = html.replace(/`([^`\n]+)`/g, (match, code) => {
        const key = `__WC_CODE_${codeSpans.length}__`;
        codeSpans.push(`<code>${code}</code>`);
        return key;
    });
    html = html.replace(/\*\*([^*\n][\s\S]*?)\*\*/g, '<strong>$1</strong>');
    html = html.replace(/(^|[^*])\*([^*\n]+)\*(?!\*)/g, '$1<em>$2</em>');
    codeSpans.forEach((value, index) => {
        html = html.replace(`__WC_CODE_${index}__`, value);
    });
    return html.replace(/\n/g, '<br>');
}

function shouldPreserveWechatRegexRenderedHtml(text, char) {
    const source = cleanWechatVisibleContent(text);
    if (!source) return false;
    if (/^\s*<\s*(?:音乐|music)\b/i.test(source)) return false;
    return /<\s*(?:jwy|status|state|bqb)\b/i.test(source)
        || looksLikeWechatRegexPayloadSource(source)
        || looksLikeWechatPipeStatusPayloadSource(source);
}

function processMsgContent(content, char) {
    if (!content) return "";
    let text = cleanWechatVisibleContent(content);
    if (!text) return "";

    const preserveRegexHtml = shouldPreserveWechatRegexRenderedHtml(text, char);
    text = preserveRegexHtml
        ? normalizeWechatRegexPayloadSource(fillWechatRegexTemplate(text, char), char)
        : fillWechatRegexTemplate(text, char);

    // 1. 执行正则脚本
    const globalScripts = window.globalRegexScripts || [];
    const charScripts = char.regex || [];
    const allScripts = [...globalScripts, ...charScripts];

    allScripts.forEach(script => {
        if (!isWechatRegexScriptEnabled(script)) return; // 🔥 跳过已关闭的脚本
        try {
            const regexStr = getWechatRegexScriptField(script, ['findRegex', 'regex', 'regex_pattern', 'regexPattern', 'pattern']);
            let replaceStr = getWechatRegexScriptField(script, ['replaceString', 'regexReplace', 'replace', 'replacement', 'substituteRegex']);
            if (regexStr) {
                let pattern = fillWechatRegexTemplate(regexStr, char);
                let flags = 'g'; 
                if (pattern.startsWith('/') && pattern.lastIndexOf('/') > 0) {
                    const lastSlash = pattern.lastIndexOf('/');
                    flags = pattern.substring(lastSlash + 1).replace(/[^gimsuy]/g, '');
                    pattern = pattern.substring(1, lastSlash);
                }
                const re = new RegExp(pattern, flags);
                if (replaceStr && typeof replaceStr === 'string') {
                    replaceStr = fillWechatRegexTemplate(replaceStr, char).replace(/\{\{match\}\}/gi, '$&');
                }
                text = text.replace(re, replaceStr);
            }
        } catch (e) { console.warn("正则执行失败:", script.name, e); }
    });

    text = cleanWechatVisibleContent(text, { stripExecutableCodeBlocks: !preserveRegexHtml });
    if (!text) return "";

    // 2. 剥离 Markdown 代码块包装（支持混合内容：文本 + 代码块）
    // 先处理内嵌的 ```html...``` 代码块，提取其中的HTML
    text = text.replace(/```(?:html|xml|markdown)?\s*([\s\S]*?)```/gi, function(match, code) {
        return code.trim();
    });
    // 如果处理后包含HTML/正则渲染块，直接返回，避免把结构化 UI 拆成旁白或 <br>
    if (isRichMessageContent(text)) {
        return text;
    } else {
        return renderWechatMarkdownLite(text);
    }
}

// 微信聊天窗口
function openChat(charId) {
    const char = window.myCharacters.find(c => c.id === charId);
    if (!char) return;

    window.currentChatCharId = charId;
    clearWechatReplyDraft();
    const sanitizedContext = sanitizeWechatEmptyChatDerivedContext(char);
    const touchedMessageTime = ensureWechatHistoryTimestamps(char);
    const readStateChanged = markWechatCharMessagesRead(char);

    const config = char.chatConfig || {};
    const chatTitle = char.isGroupChat ? getWechatQQGroupDisplayName(char) : (config.nickname || char.name);
    document.getElementById('chat-room-title').textContent = chatTitle;
    const floatImg = document.getElementById('wc-float-avatar-img');
    const floatName = document.getElementById('wc-float-name');
    const roomHeaderAvatar = document.getElementById('chat-room-header-avatar');
    const charAvatar = getWechatCharAvatarSource(char);
    if (floatImg) floatImg.src = charAvatar;
    if (floatName) floatName.textContent = chatTitle;
    if (roomHeaderAvatar) roomHeaderAvatar.src = charAvatar;
    syncWechatLineRoomHeader();
    syncWechatCoupleThemeHeader(char);
    if (touchedMessageTime || readStateChanged || sanitizedContext) saveCharactersToStorage();
    if (readStateChanged) {
        scheduleWechatChatListRefresh();
    }
    // 应用聊天配置（背景/气泡/字体）
    applyChatConfig(char);
    refreshChatView(char);
    setWechatVoiceInputMode(false, { keepDraft: true });
    syncWechatDraftState();

    const room = document.getElementById('wechat-chat-room');
    const inputEl = document.getElementById('wc-msg-input');
    const richEl = getWechatRichInputElement?.();
    const placeholder = isWechatXTheme() ? '私信' : getWechatChatInputPlaceholder(getWechatUiThemeId());
    if (inputEl) inputEl.placeholder = placeholder;
    if (richEl) richEl.dataset.placeholder = placeholder;
    recoverWechatInputLockIfStale();
    room.classList.remove('hidden');
    setTimeout(() => room.classList.add('active'), 10);
}


function openWechatMessageSource(charId, msgKey) {
    if (!charId) return;
    if (typeof openApp === 'function') openApp('wechat');
    closeWechatFeatureScreen();
    setTimeout(() => {
        openChat(charId);
        requestAnimationFrame(() => {
            const char = window.myCharacters.find(c => c.id === charId);
            const history = Array.isArray(char && char.history) ? char.history : [];
            const index = history.findIndex((msg, idx) => getWechatMessageSourceKey(charId, msg, idx) === msgKey);
            const row = index >= 0 ? document.querySelector(`.msg-row[data-msg-idx="${index}"]`) : null;
            if (row) {
                row.scrollIntoView({ block: 'center', behavior: 'smooth' });
                row.classList.add('msg-source-highlight');
                setTimeout(() => row.classList.remove('msg-source-highlight'), 1600);
            }
        });
    }, 80);
}

function getWechatMessageSourceKey(charId, msg, msgIdx) {
    return `message:${charId}:${msg?.id || msg?.timestamp || msg?.createdAt || msgIdx}`;
}

// 2. 修复切换开场白导致微信也变的问题 (数据分离)
function switchGreeting(direction) {
    const charId = window.currentChatCharId;
    if (!charId) return;
    const char = window.myCharacters.find(c => c.id === charId);
    if (!char) return;

    const allGreetings = [char.first_mes_original || char.first_mes, ...(char.alternates || [])].filter(t => t);
    
    if (typeof char.currentGreetingIndex === 'undefined') char.currentGreetingIndex = 0;

    let newIndex = char.currentGreetingIndex + direction;
    if (newIndex < 0) newIndex = allGreetings.length - 1; 
    if (newIndex >= allGreetings.length) newIndex = 0; 

    // 🔥 核心修改：只更新“索引”，绝对不去改 history 里的内容！
    // 微信读取的是 history，所以微信永远不变。
    // 当前问候语索引会影响角色开场白。
    char.currentGreetingIndex = newIndex;
    
    // 注意：这里不再调用 openChat 刷新微信，因为微信不需要变
}

function createMessageTimestamp() {
    return Date.now();
}

function padWechatDatePart(value) {
    return String(value).padStart(2, '0');
}

function toWechatDatetimeLocalValue(value) {
    const date = value ? new Date(value) : new Date();
    const safeDate = Number.isNaN(date.getTime()) ? new Date() : date;
    return `${safeDate.getFullYear()}-${padWechatDatePart(safeDate.getMonth() + 1)}-${padWechatDatePart(safeDate.getDate())}T${padWechatDatePart(safeDate.getHours())}:${padWechatDatePart(safeDate.getMinutes())}`;
}

function formatWechatDateTimeForPrompt(value) {
    const date = value ? new Date(value) : new Date();
    const safeDate = Number.isNaN(date.getTime()) ? new Date() : date;
    const weekdays = ['星期日', '星期一', '星期二', '星期三', '星期四', '星期五', '星期六'];
    return `${safeDate.getFullYear()}年${safeDate.getMonth() + 1}月${safeDate.getDate()}日 ${weekdays[safeDate.getDay()]} ${padWechatDatePart(safeDate.getHours())}:${padWechatDatePart(safeDate.getMinutes())}`;
}

function getWechatCurrentTimeContext(char) {
    const config = (char && char.chatConfig) || {};
    const mode = config.timeMode === 'virtual' ? 'virtual' : 'real';
    const rawTime = mode === 'virtual' ? config.virtualTime : null;
    const date = rawTime ? new Date(rawTime) : new Date();
    const safeDate = Number.isNaN(date.getTime()) ? new Date() : date;
    return {
        mode,
        label: mode === 'virtual' ? '虚拟时间' : '真实世界时间',
        text: formatWechatDateTimeForPrompt(safeDate),
        iso: safeDate.toISOString()
    };
}

function ensureMessageTimestamp(msg) {
    if (!msg.timestamp && !msg.createdAt && !msg.time) {
        msg.timestamp = createMessageTimestamp();
        return true;
    }
    return false;
}

function getWechatHistoryVersionKey(char) {
    const history = Array.isArray(char && char.history) ? char.history : [];
    const last = history[history.length - 1] || {};
    const lastText = String(last.content || last.description || last.dialogue || last.text || '');
    return [
        WECHAT_HISTORY_REPAIR_SCHEMA_VERSION,
        char && char.id || '',
        history.length,
        last.id || '',
        last.timestamp || last.createdAt || last.time || '',
        last.type || '',
        last.isMe ? '1' : '0',
        lastText.length
    ].join('|');
}

function ensureWechatHistoryTimestamps(char) {
    if (!char || !Array.isArray(char.history)) return false;
    window._wechatTimestampCheckKeys = window._wechatTimestampCheckKeys || new Map();
    const beforeKey = getWechatHistoryVersionKey(char);
    if (window._wechatTimestampCheckKeys.get(char.id) === beforeKey) return false;
    let touched = false;
    char.history.forEach(msg => {
        if (ensureMessageTimestamp(msg)) touched = true;
    });
    window._wechatTimestampCheckKeys.set(char.id, getWechatHistoryVersionKey(char));
    return touched;
}

function scheduleWechatChatListRefresh() {
    clearTimeout(window._wechatChatListRefreshTimer);
    window._wechatChatListRefreshTimer = setTimeout(() => {
        renderChatList();
    }, 80);
}

function formatMessageTime(msg) {
    const rawTime = msg.timestamp || msg.createdAt || msg.time;
    const date = rawTime ? new Date(rawTime) : new Date();
    const safeDate = Number.isNaN(date.getTime()) ? new Date() : date;
    return `${String(safeDate.getHours()).padStart(2, '0')}:${String(safeDate.getMinutes()).padStart(2, '0')}`;
}

function formatWechatCoupleMessageDateTime(msg) {
    const rawTime = msg && (msg.timestamp || msg.createdAt || msg.time);
    const date = rawTime ? new Date(rawTime) : new Date();
    const safeDate = Number.isNaN(date.getTime()) ? new Date() : date;
    const now = new Date();
    const dateText = safeDate.getFullYear() === now.getFullYear()
        ? `${safeDate.getMonth() + 1}月${safeDate.getDate()}日`
        : `${safeDate.getFullYear()}年${safeDate.getMonth() + 1}月${safeDate.getDate()}日`;
    return {
        date: dateText,
        time: `${String(safeDate.getHours()).padStart(2, '0')}:${String(safeDate.getMinutes()).padStart(2, '0')}`
    };
}

function getWechatCoupleMessageSenderKey(msg, char = null) {
    if (!msg || msg.type === 'system_notice') return '';
    if (msg.isMe) return 'me';
    return String(
        msg.senderId
        || msg.speakerId
        || msg.senderName
        || msg.speakerName
        || (char && char.isGroupChat ? 'group-member' : 'ai')
    );
}

function shouldShowWechatCoupleMessageHeader(prevMsg, msg, char = null) {
    if (!isWechatCoupleTheme()) return true;
    if (!msg || msg.type === 'system_notice') return true;
    if (!prevMsg || prevMsg.type === 'system_notice') return true;
    if (getWechatCoupleMessageSenderKey(prevMsg, char) !== getWechatCoupleMessageSenderKey(msg, char)) return true;
    const raw = msg.timestamp || msg.createdAt || msg.time;
    const prevRaw = prevMsg.timestamp || prevMsg.createdAt || prevMsg.time;
    const date = raw ? new Date(raw) : null;
    const prevDate = prevRaw ? new Date(prevRaw) : null;
    if (!date || !prevDate || Number.isNaN(date.getTime()) || Number.isNaN(prevDate.getTime())) return false;
    if (date.toDateString() !== prevDate.toDateString()) return true;
    return date.getTime() - prevDate.getTime() >= 10 * 60 * 1000;
}

function buildMessageMeta(msg) {
    const readIcon = '<i class="ri-check-double-line"></i>';
    return `<span class="msg-meta ${msg.isMe ? 'read' : 'delivered'}"><span>${formatMessageTime(msg)}</span>${readIcon}</span>`;
}

function isWechatRegexPayloadMessage(msg, char = null) {
    if (!msg || msg.isMe || msg.type === 'system_notice') return false;
    if (!['text', 'offline_narration'].includes(msg.type || 'text')) return false;
    const source = cleanWechatVisibleContent(msg.content || msg.description || msg.dialogue || msg.text || '');
    if (!source) return false;
    return isWechatStandaloneRichOrRegexSource(source, char) || shouldDropWechatAiPipeStatusPayload(source, char);
}
window.isWechatRegexPayloadMessage = isWechatRegexPayloadMessage;

function isWechatHiddenChatSurfaceMessage(msg) {
    return !!(msg && (msg.hiddenFromChat || msg.internalEvent || msg.monitorEvent));
}

function getWechatLastChatMessage(char) {
    const history = Array.isArray(char?.history) ? char.history : [];
    for (let i = history.length - 1; i >= 0; i--) {
        const msg = history[i];
        if (msg && msg.type !== 'system_notice' && !isWechatHiddenChatSurfaceMessage(msg) && !isWechatRegexPayloadMessage(msg, char)) return msg;
    }
    return null;
}

function formatTelegramChatListTime(char) {
    const msg = getWechatLastChatMessage(char);
    const raw = msg && (msg.timestamp || msg.createdAt || msg.time);
    if (!raw) return '现在';
    const date = new Date(raw);
    if (Number.isNaN(date.getTime())) return '现在';
    const now = new Date();
    const sameDay = date.getFullYear() === now.getFullYear()
        && date.getMonth() === now.getMonth()
        && date.getDate() === now.getDate();
    if (sameDay) return `${padWechatDatePart(date.getHours())}:${padWechatDatePart(date.getMinutes())}`;
    return `${date.getMonth() + 1}月${date.getDate()}日`;
}

function getTelegramChatUnreadCount(char) {
    if (!char) return 0;
    if (typeof isWechatChatPageActive === 'function' && isWechatChatPageActive(char.id)) return 0;
    if (isWechatQQGroupBlocked(char)) return 0;
    const explicit = Number(char?.unreadCount ?? char?.chatConfig?.unreadCount ?? 0);
    if (Number.isFinite(explicit) && explicit > 0) return Math.min(999, Math.floor(explicit));
    const history = Array.isArray(char?.history) ? char.history : [];
    const lastReadAt = Number(char?.chatConfig?.lastReadAt) || 0;
    let count = 0;
    if (lastReadAt > 0) {
        history.forEach(msg => {
            if (!msg || msg.type === 'system_notice' || msg.isMe) return;
            if (isWechatHiddenChatSurfaceMessage(msg)) return;
            if (isWechatRegexPayloadMessage(msg, char)) return;
            if (getWechatMessageTimestampValue(msg) > lastReadAt) count += 1;
        });
    } else {
        for (let i = history.length - 1; i >= 0; i--) {
            const msg = history[i];
            if (!msg || msg.type === 'system_notice') continue;
            if (isWechatHiddenChatSurfaceMessage(msg)) continue;
            if (msg.isMe) break;
            if (isWechatRegexPayloadMessage(msg, char)) continue;
            count += 1;
        }
    }
    return Math.min(999, count);
}


function getWechatMessageDate(msg) {
    const raw = msg && (msg.timestamp || msg.createdAt || msg.time);
    const date = raw ? new Date(raw) : new Date();
    return Number.isNaN(date.getTime()) ? new Date() : date;
}

function buildWechatCollectedAtText(msg) {
    const rawTime = msg.collectedAt || msg.timestamp || msg.createdAt || msg.time;
    return rawTime ? `已于 ${formatMessageTime({ timestamp: rawTime })} 收取` : '已收取';
}

function getWechatMessagePlainSummary(msg, maxLength = 92) {
    const raw = getWechatMessageSummary(msg)
        .replace(/<[^>]+>/g, '')
        .replace(/\|\|\|/g, ' ')
        .replace(/\s+/g, ' ')
        .trim();
    if (!raw) return '[消息]';
    return raw.length > maxLength ? raw.slice(0, maxLength - 1) + '…' : raw;
}

function isWechatReplyMediaSource(value) {
    const text = String(value || '').trim();
    if (!text || text.length > 2048) return false;
    return /^(?:data:image\/|blob:|https?:\/\/|assets\/|\.{0,2}\/assets\/|\/assets\/)/i.test(text)
        || /\.(?:png|jpe?g|gif|webp|avif|svg)(?:[?#].*)?$/i.test(text);
}

function isWechatReplyMediaTextLeak(value) {
    const text = String(value || '').trim();
    if (!text) return false;
    return /^(?:data:image\/|blob:|https?:\/\/|assets\/|\.{0,2}\/assets\/|\/assets\/)/i.test(text)
        || /\.(?:png|jpe?g|gif|webp|avif|svg)(?:[?#].*)?$/i.test(text);
}

function getWechatReplySourceMessage(replyTo, char) {
    if (!replyTo || !char || !Array.isArray(char.history)) return null;
    const history = char.history;
    const replyId = String(replyTo.msgId || '').trim();
    if (replyId) {
        const byId = history.find(msg => String(msg && msg.id || '') === replyId);
        if (byId) return byId;
    }
    const idx = Number(replyTo.msgIdx);
    if (Number.isInteger(idx) && idx >= 0 && idx < history.length) {
        return history[idx] || null;
    }
    return null;
}

function getWechatReplyMedia(replyTo, char) {
    if (!replyTo) return null;
    const sourceMsg = getWechatReplySourceMessage(replyTo, char);
    const sourceType = String((sourceMsg && sourceMsg.type) || replyTo.type || '').toLowerCase();
    const sourceUrl = sourceMsg && sourceMsg.content;
    if (sourceType === 'sticker' && isWechatReplyMediaSource(sourceUrl)) {
        return {
            type: 'sticker',
            url: sourceUrl,
            label: sourceMsg.stickerName || sourceMsg.name || replyTo.stickerName || replyTo.name || '表情',
            emoji: !!(sourceMsg.emoji || sourceMsg.stickerKind === 'wechatEmoji' || isWechatBuiltinEmojiUrl(sourceUrl))
        };
    }
    if (sourceType === 'image' && isWechatReplyMediaSource(sourceUrl)) {
        return {
            type: 'image',
            url: sourceUrl,
            label: sourceMsg.description || replyTo.text || '图片'
        };
    }
    const directUrl = replyTo.mediaUrl || replyTo.stickerUrl || replyTo.imageUrl || replyTo.url || replyTo.content;
    if ((sourceType === 'sticker' || sourceType === 'image') && isWechatReplyMediaSource(directUrl)) {
        return {
            type: sourceType,
            url: directUrl,
            label: replyTo.stickerName || replyTo.name || replyTo.text || (sourceType === 'sticker' ? '表情' : '图片'),
            emoji: !!replyTo.emoji
        };
    }
    const textUrl = replyTo.text;
    if ((sourceType === 'sticker' || sourceType === 'image') && isWechatReplyMediaSource(textUrl)) {
        return {
            type: sourceType,
            url: textUrl,
            label: sourceType === 'sticker' ? '表情' : '图片',
            emoji: !!replyTo.emoji
        };
    }
    return null;
}

function getWechatReplyDisplayText(replyTo, media) {
    if (media && media.type === 'sticker') return '';
    const fallbackText = media
        ? (media.label || '[图片]')
        : '[消息]';
    const rawText = String(replyTo && replyTo.text || '').trim();
    if (!rawText) return fallbackText;
    if (media && isWechatReplyMediaTextLeak(rawText)) return fallbackText;
    return rawText;
}

function getWechatMessageSenderName(msg, char) {
    if (msg && msg.isMe) {
        const profile = (typeof getWechatChatUserProfile === 'function') ? getWechatChatUserProfile(char) : ((typeof getUserProfile === 'function') ? getUserProfile() : null);
        return (profile && profile.name) || '我';
    }
    if (char?.isGroupChat) {
        const explicit = msg && (msg.senderName || msg.speakerName);
        const member = msg && findWechatGroupMember(char, msg.senderId || msg.speakerId || explicit);
        if (member) return getWechatQQGroupMemberDisplayName(char, member);
        if (explicit) return explicit;
        const normalized = normalizeWechatGroupSpeechText(msg && msg.content, char);
        if (normalized.member) return getWechatQQGroupMemberDisplayName(char, normalized.member);
    }
    return getWechatCharDisplayName(char);
}

function renderWechatXChatProfileIntro(char) {
    if (!char || !isWechatXTheme()) return '';
    const name = wcEscapeHtml(getWechatCharDisplayName(char));
    const avatar = wcEscapeHtml(char.avatar || DEFAULT_AVATAR);
    const handleSource = getWechatContactId(char) || String(char.name || 'contact').replace(/\s+/g, '').slice(0, 18) || 'contact';
    const handle = wcEscapeHtml(handleSource.startsWith('@') ? handleSource : `@${handleSource}`);
    const createdAt = char.importedAt || char.createdAt || char.addedAt || Date.now();
    const date = new Date(createdAt);
    const joined = Number.isNaN(date.getTime())
        ? '加入于今天'
        : `加入于 ${date.getFullYear()}年${date.getMonth() + 1}月${date.getDate()}日`;
    return `
        <div class="wc-x-chat-profile-intro" onclick="openWechatContactProfile(${quoteWechatJsString(char.id)})">
            <img src="${avatar}" onerror="this.src='${DEFAULT_AVATAR}'">
            <strong>${name}</strong>
            <span>${handle}</span>
            <em>${wcEscapeHtml(joined)}</em>
            <button type="button" onclick="event.stopPropagation();openWechatContactProfile(${quoteWechatJsString(char.id)})">查看个人资料</button>
        </div>
    `;
}

function buildWechatReplySnapshot(msg, char, msgIdx) {
    if (!msg) return null;
    const type = msg.type || 'text';
    const snapshot = {
        msgId: msg.id || '',
        msgIdx: Number.isInteger(msgIdx) ? msgIdx : null,
        isMe: !!msg.isMe,
        sender: getWechatMessageSenderName(msg, char),
        text: getWechatMessagePlainSummary(msg, 120),
        type,
        timestamp: msg.timestamp || msg.createdAt || msg.time || ''
    };
    if (type === 'music_card') {
        const music = msg.music && typeof msg.music === 'object' ? msg.music : {};
        snapshot.title = music.title || msg.title || '音乐';
        snapshot.artist = music.artist || msg.artist || '';
        snapshot.artwork = music.artwork || msg.artwork || '';
    }
    if ((type === 'sticker' || type === 'image') && isWechatReplyMediaSource(msg.content)) {
        snapshot.mediaUrl = msg.content;
        if (type === 'sticker') {
            snapshot.stickerName = msg.stickerName || msg.name || '';
            snapshot.emoji = !!(msg.emoji || msg.stickerKind === 'wechatEmoji' || isWechatBuiltinEmojiUrl(msg.content));
        }
    }
    return snapshot;
}

function renderWechatMessageQuote(replyTo, char) {
    if (!replyTo) return '';
    const media = getWechatReplyMedia(replyTo, char);
    const senderText = replyTo.sender || (replyTo.isMe ? '我' : '对方');
    const sender = wcEscapeHtml(senderText);
    const sourceMsg = getWechatReplySourceMessage(replyTo, char);
    const sourceType = String((sourceMsg && sourceMsg.type) || replyTo.type || '').toLowerCase();
    if (sourceType === 'music_card') {
        const music = (sourceMsg && sourceMsg.music && typeof sourceMsg.music === 'object') ? sourceMsg.music : {};
        const title = music.title || sourceMsg?.title || replyTo.title || getWechatReplyDisplayText(replyTo, media).replace(/^\[音乐卡片\]\s*/, '') || '音乐';
        const artist = music.artist || sourceMsg?.artist || replyTo.artist || '';
        const artwork = music.artwork || sourceMsg?.artwork || replyTo.artwork || '';
        return `
            <div class="msg-quote msg-quote-music">
                <div class="msg-quote-music-art">${artwork ? `<img src="${wcEscapeHtml(artwork)}" alt="" loading="lazy" onerror="this.remove()">` : '<i class="ri-music-2-fill"></i>'}</div>
                <div class="msg-quote-music-main">
                    <span>音乐卡片</span>
                    <strong>${wcEscapeHtml(title)}</strong>
                    ${(artist || senderText) ? `<em>${wcEscapeHtml(artist || senderText)}</em>` : ''}
                </div>
                <button type="button" class="msg-quote-music-play" aria-label="播放音乐"><i class="ri-play-fill"></i></button>
                <div class="msg-quote-music-footer"><span>一起听歌</span></div>
            </div>
        `;
    }
    const displayText = getWechatReplyDisplayText(replyTo, media);
    const text = wcEscapeHtml(displayText);
    if (media && media.url) {
        const mediaClass = `msg-quote-image ${media.type === 'sticker' ? 'sticker' : 'image'}${media.emoji ? ' emoji' : ''}`;
        const quoteClass = `msg-quote has-media is-${media.type}${media.emoji ? ' is-emoji' : ''}`;
        return `
            <div class="${quoteClass}">
                <div class="msg-quote-media">
                    <img class="${mediaClass}" src="${wcEscapeHtml(media.url)}" alt="${wcEscapeHtml(media.label || '表情')}" loading="lazy" onerror="this.closest('.msg-quote-media')?.classList.add('is-broken');this.remove()">
                </div>
                <div class="msg-quote-caption">
                    <strong>${sender}</strong>
                    ${displayText ? `<span>${text}</span>` : ''}
                </div>
            </div>
        `;
    }
    return `<div class="msg-quote"><strong>${sender}</strong><span>${text}</span></div>`;
}

function findWechatMessageForAiQuote(char, query) {
    if (!char || !Array.isArray(char.history) || !char.history.length) return null;
    const history = char.history;
    const options = (arguments.length > 2 && arguments[2] && typeof arguments[2] === 'object') ? arguments[2] : {};
    const raw = String(query || '').trim();
    if (/^\d+$/.test(raw)) {
        const index = Math.max(0, Math.min(history.length - 1, parseInt(raw, 10) - 1));
        return { msg: history[index], index };
    }
    const normalized = raw.replace(/^(?:最后|上一条|最近|last)$/i, '').trim();
    if (!normalized) {
        for (let i = history.length - 1; i >= 0; i -= 1) {
            const msg = history[i];
            if (i === options.excludeIndex || msg === options.excludeMessage) continue;
            if (msg && msg.type !== 'system_notice' && msg.isMe && !isWechatAiQuoteDirectiveLeakMessage(msg)) return { msg, index: i };
        }
    }
    const queryKey = normalizeWechatQuoteSearchText(normalized);
    if (isWechatMusicQuoteQuery(normalized, queryKey)) {
        for (let i = history.length - 1; i >= 0; i -= 1) {
            const msg = history[i];
            if (i === options.excludeIndex || msg === options.excludeMessage) continue;
            if (!msg || msg.type !== 'music_card' || isWechatAiQuoteDirectiveLeakMessage(msg)) continue;
            if (isWechatGenericMusicQuoteQuery(normalized, queryKey)) return { msg, index: i };
            const summary = getWechatMessagePlainSummary(msg, 180);
            const summaryKeys = getWechatQuoteSearchKeys(msg, summary);
            if (summary.includes(normalized) || summaryKeys.some(key => key && (key.includes(queryKey) || (queryKey.includes(key) && key.length >= 4)))) {
                return { msg, index: i };
            }
        }
    }
    for (let i = history.length - 1; i >= 0; i -= 1) {
        const msg = history[i];
        if (i === options.excludeIndex || msg === options.excludeMessage) continue;
        if (!msg || msg.type === 'system_notice') continue;
        if (isWechatAiQuoteDirectiveLeakMessage(msg)) continue;
        const summary = getWechatMessagePlainSummary(msg, 180);
        if (!normalized || summary.includes(normalized) || getWechatMessageSenderName(msg, char).includes(normalized)) {
            return { msg, index: i };
        }
        if (!queryKey) continue;
        const summaryKeys = getWechatQuoteSearchKeys(msg, summary);
        if (summaryKeys.some(key => key && (key.includes(queryKey) || (queryKey.includes(key) && key.length >= 4)))) {
            return { msg, index: i };
        }
    }
    return null;
}

function normalizeWechatQuoteSearchText(value) {
    let source = cleanWechatVisibleContent(value)
        .replace(/^[\[【](?:微信引用|引用)\s*[：:]\s*/i, '')
        .replace(/[\]】]\s*$/i, '')
        .replace(/^\s*(?:🎵|🎶|♫|♪)+\s*/u, '')
        .replace(/^\s*[\[【](?:音乐卡片|音乐|music card)[\]】]\s*/i, '')
        .replace(/^(?:音乐卡片|音乐|music card)\s*[：:]\s*/i, '')
        .trim();
    if (!source) return '';
    try {
        source = source.normalize('NFKC').toLowerCase();
        return source.replace(/[^\p{L}\p{N}]+/gu, ' ').replace(/\s+/g, ' ').trim();
    } catch (_) {
        return source.toLowerCase().replace(/[^\u3400-\u9fff\w]+/g, ' ').replace(/\s+/g, ' ').trim();
    }
}

function getWechatQuoteSearchKeys(msg, summary) {
    const keys = [normalizeWechatQuoteSearchText(summary)];
    if (msg && msg.type === 'music_card') {
        const music = msg.music && typeof msg.music === 'object' ? msg.music : {};
        const title = music.title || msg.title || '';
        const artist = music.artist || msg.artist || '';
        keys.push(
            normalizeWechatQuoteSearchText(title),
            normalizeWechatQuoteSearchText(artist),
            normalizeWechatQuoteSearchText(`${title} ${artist}`)
        );
    }
    return Array.from(new Set(keys.filter(Boolean)));
}

function isWechatGenericMusicQuoteQuery(raw, normalized) {
    const source = cleanWechatVisibleContent(raw).toLowerCase();
    const key = String(normalized || normalizeWechatQuoteSearchText(raw));
    return /^(?:音乐|音乐卡片|歌曲|歌|这首歌|那首歌|这首|那首|music|song|track|bgm)$/i.test(source)
        || /^(?:音乐|音乐卡片|歌曲|歌|这首歌|那首歌|这首|那首|music|song|track|bgm)$/i.test(key)
        || /(?:这首|那首|泰语歌|音乐卡片|music card)/i.test(source);
}

function isWechatMusicQuoteQuery(raw, normalized) {
    const source = cleanWechatVisibleContent(raw);
    const key = String(normalized || normalizeWechatQuoteSearchText(raw));
    return isWechatGenericMusicQuoteQuery(source, key)
        || /(?:音乐|歌曲|歌|music|song|track|bgm)/i.test(source)
        || /(?:音乐|歌曲|歌|music|song|track|bgm)/i.test(key);
}

function isWechatAiQuoteDirectiveLeakMessage(msg) {
    const raw = cleanWechatVisibleContent((msg && (msg.content || msg.description)) || '');
    if (/^\s*[\[【]微信引用\s*[：:]/.test(raw)) return true;
    const replyText = cleanWechatVisibleContent(msg && msg.replyTo && (msg.replyTo.text || msg.replyTo.content));
    return /^\s*[\[【]微信引用\s*[：:]/.test(replyText);
}

function parseWechatAiQuoteDirectiveText(value) {
    const source = cleanWechatVisibleContent(value);
    if (!source) return null;
    const start = Math.min(
        ...['[微信引用', '【微信引用'].map(token => source.indexOf(token)).filter(index => index >= 0)
    );
    if (!Number.isFinite(start)) return null;
    const event = readWechatAiDirectiveAt(source, start);
    if (!event || event.command !== '微信引用') return null;
    const args = splitWechatDirectiveArgs(event.args);
    const query = args[0] || '';
    const content = args.slice(1).join('|').trim();
    return query || content ? { query, content } : null;
}

function buildWechatFallbackReplySnapshotFromAiQuote(query) {
    const text = cleanWechatVisibleContent(query)
        .replace(/^(?:最后|上一条|最近|last)$/i, '')
        .trim()
        .slice(0, 120);
    if (!text) return null;
    return {
        msgId: '',
        msgIdx: null,
        isMe: true,
        sender: getWechatDisplayUserName(),
        text,
        type: 'text',
        timestamp: createMessageTimestamp()
    };
}

function appendWechatTimeDivider(container, date) {
    if (!container) return;
    const divider = document.createElement('div');
    divider.className = 'msg-row time';
    divider.innerHTML = `<div class="msg-time-divider">${wcEscapeHtml(formatWechatDateTimeDivider(date))}</div>`;
    container.appendChild(divider);
}

function formatWechatDateTimeDivider(date) {
    const safeDate = date instanceof Date && !Number.isNaN(date.getTime()) ? date : new Date();
    const today = new Date();
    const isSameDay = safeDate.toDateString() === today.toDateString();
    const yesterday = new Date(today);
    yesterday.setDate(today.getDate() - 1);
    const dayText = isSameDay
        ? ''
        : (safeDate.toDateString() === yesterday.toDateString()
            ? '昨天 '
            : `${safeDate.getMonth() + 1}月${safeDate.getDate()}日 `);
    return `${dayText}${String(safeDate.getHours()).padStart(2, '0')}:${String(safeDate.getMinutes()).padStart(2, '0')}`;
}

function shouldShowWechatTimeDivider(prevMsg, msg) {
    const raw = msg && (msg.timestamp || msg.createdAt || msg.time);
    const date = raw ? new Date(raw) : new Date();
    if (Number.isNaN(date.getTime())) return false;
    if (!prevMsg) return true;
    const prevRaw = prevMsg.timestamp || prevMsg.createdAt || prevMsg.time;
    const prevDate = prevRaw ? new Date(prevRaw) : null;
    if (!prevDate || Number.isNaN(prevDate.getTime())) return true;
    const gap = date.getTime() - prevDate.getTime();
    if (gap >= 10 * 60 * 1000) return true;
    return date.getMinutes() === 0 && date.getHours() !== prevDate.getHours();
}

function parseWechatRgbColor(value) {
    const text = String(value || '').trim();
    if (!text || text === 'transparent') return null;
    const rgba = text.match(/^rgba?\(([^)]+)\)$/i);
    if (rgba) {
        const parts = rgba[1].split(',').map(part => parseFloat(part.trim()));
        if (parts.length >= 3 && parts.slice(0, 3).every(Number.isFinite)) {
            const alpha = Number.isFinite(parts[3]) ? parts[3] : 1;
            if (alpha <= 0.02) return null;
            return { r: parts[0], g: parts[1], b: parts[2], a: alpha };
        }
    }
    const hex = text.match(/^#([0-9a-f]{3}|[0-9a-f]{6})$/i);
    if (hex) {
        const raw = hex[1].length === 3
            ? hex[1].split('').map(ch => ch + ch).join('')
            : hex[1];
        return {
            r: parseInt(raw.slice(0, 2), 16),
            g: parseInt(raw.slice(2, 4), 16),
            b: parseInt(raw.slice(4, 6), 16),
            a: 1
        };
    }
    return null;
}

function getWechatColorLuminance(color) {
    const channel = value => {
        const normalized = Math.max(0, Math.min(255, value)) / 255;
        return normalized <= 0.03928 ? normalized / 12.92 : Math.pow((normalized + 0.055) / 1.055, 2.4);
    };
    return 0.2126 * channel(color.r) + 0.7152 * channel(color.g) + 0.0722 * channel(color.b);
}

function findWechatPaintedBackground(el) {
    let current = el;
    while (current && current.nodeType === 1) {
        const style = getComputedStyle(current);
        const bg = parseWechatRgbColor(style.backgroundColor);
        if (bg) return bg;
        const imageColor = String(style.backgroundImage || '').match(/rgba?\([^)]+\)|#[0-9a-f]{3,6}/i);
        if (imageColor) {
            const parsed = parseWechatRgbColor(imageColor[0]);
            if (parsed) return parsed;
        }
        current = current.parentElement;
    }
    return { r: 255, g: 255, b: 255, a: 1 };
}

function applyWechatBubbleMetaContrast(scope) {
    if (!scope || typeof scope.querySelectorAll !== 'function') return;
    scope.querySelectorAll('.msg-bubble').forEach(bubble => {
        const color = findWechatPaintedBackground(bubble);
        const isDark = getWechatColorLuminance(color) < 0.48;
        bubble.style.setProperty('--msg-meta-color', isDark ? 'rgba(255,255,255,0.78)' : 'rgba(23,33,43,0.50)');
        bubble.style.setProperty('--msg-meta-icon-color', isDark ? 'rgba(255,255,255,0.88)' : '#4aa3ff');
    });
    scope.querySelectorAll('.msg-meta').forEach(meta => {
        const source = meta.closest('.msg-card-footer') || meta.closest('.msg-bubble') || meta;
        const color = findWechatPaintedBackground(source);
        const isDark = getWechatColorLuminance(color) < 0.48;
        const metaColor = isDark ? 'rgba(255,255,255,0.78)' : 'rgba(23,33,43,0.50)';
        const iconColor = isDark ? 'rgba(255,255,255,0.88)' : '#4aa3ff';
        meta.style.setProperty('color', metaColor, 'important');
        meta.querySelectorAll('i').forEach(icon => icon.style.setProperty('color', iconColor, 'important'));
    });
}

function isRichMessageContent(content) {
    const source = String(content || '');
    return /```(?:html|xml|markdown)?\s*[\s\S]*?```/i.test(source)
        || /<\s*\/?\s*(?:div|style|script|table|iframe|img|span|section|header|article|button|ul|ol|li|p|video|audio|svg|canvas)\b/i.test(source)
        || /<\s*\/?\s*[a-z][\w:-]*\b[^>]*>/i.test(source);
}

function cleanWechatVisibleContent(value, options = {}) {
    const externalCleaner = typeof window.cleanChatApiVisibleContent === 'function'
        ? window.cleanChatApiVisibleContent
        : null;
    let text = externalCleaner ? externalCleaner(value) : String(value == null ? '' : value);
    if (!text) return '';

    const hiddenTags = [
        'thinking',
        'think',
        'thought',
        'execute_think',
        'cot',
        'analysis',
        'reasoning',
        'chain_of_thought'
    ];

    for (let pass = 0; pass < 4; pass += 1) {
        const before = text;
        hiddenTags.forEach(tag => {
            text = text.replace(new RegExp(`<${tag}\\b[^>]*>[\\s\\S]*?<\\/${tag}>`, 'gi'), '');
        });
        if (text === before) break;
    }

    text = text
        .replace(/<\/?(?:thinking|think|thought|execute_think|cot|analysis|reasoning|chain_of_thought)\b[^>]*>/gi, '')
        .replace(/<content\b[^>]*>([\s\S]*?)<\/content>/gi, '$1')
        .replace(/<\/?content\b[^>]*>/gi, '');

    if (options.stripExecutableCodeBlocks !== false) {
        text = text.replace(/```(?:html|xml|markdown|json)?\s*[\s\S]*?(?:setChatMessages|document\.getElementById|<script\b|<style\b)[\s\S]*?```/gi, '');
    }

    return text
        .replace(/^\s*(?:思考完毕[，,。；;：:]?\s*)+/i, '')
        .replace(/^\s*(?:生成回复[，,。；;：:]?\s*)+/i, '')
        .trim();
}

function isWechatAiMetaLeakContent(value) {
    const text = cleanWechatVisibleContent(value)
        .replace(/\s+/g, ' ')
        .trim();
    if (!text) return true;
    if (/^[|‖｜\s]+$/.test(text)) return true;
    if (/^(?:<\/?[a-z][\w-]*\s*\/?>\s*)+$/i.test(text)) return true;
    if (/^\[(?:语音通话|视频通话)\]\s*(?:角色发起，用户处理|用户发起，角色处理)；结果：/i.test(text)) return true;
    if (/^[-\s]*[（(]?自检[）)]?\s*$/i.test(text)) return true;
    if (/^[-\s]*(?:\[?(?:消息|状态栏|狀態欄|状态|狀態|自检|自檢|内心OS|思考|反思|判断|行动|计划|策略)\]?)[：:]/i.test(text)) return true;
    if (/^[-\s]*(?:符合.+人设吗|符合当前情境吗|解决用户问题了吗)[？?]/i.test(text)) return true;
    if (/^[-\s]*(?:是的|否|已|未)[，,、\s]*(?:嘴硬|有掌控欲|行动上会关心|回复简短|解释了|准备回去|解释用户问题|符合.+人设|符合当前情境)/i.test(text)) return true;
    if (/^(?:The soul now awakens|Janus,|I MUST start every response|Process \(|\[Process\d|Archive compression mode)/i.test(text)) return true;
    return false;
}

function wcEscapeHtml(value) {
    if (typeof escapeHtml === 'function') return escapeHtml(value == null ? '' : String(value));
    const div = document.createElement('div');
    div.textContent = value == null ? '' : String(value);
    return div.innerHTML;
}

function wcEscapeAttr(value) {
    return wcEscapeHtml(value)
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;')
        .replace(/`/g, '&#96;');
}

function quoteWechatJsString(value) {
    const json = JSON.stringify(String(value == null ? '' : value)
    )
        .replace(/</g, '\\u003c')
        .replace(/>/g, '\\u003e')
        .replace(/&/g, '\\u0026')
        .replace(/\u2028/g, '\\u2028')
        .replace(/\u2029/g, '\\u2029');
    return json
        .replace(/&/g, '&amp;')
        .replace(/"/g, '&quot;');
}

function getWechatCssUrl(value) {
    const safe = String(value == null ? '' : value)
        .replace(/'/g, '%27')
        .replace(/"/g, '%22')
        .replace(/\)/g, '%29')
        .replace(/[\r\n]/g, '');
    return `url('${wcEscapeHtml(safe)}')`;
}

function isWechatSpecialMessage(type) {
    return ['voice', 'transfer', 'redpacket', 'voiceCall', 'videoCall', 'share_card', 'gift', 'intimatePay', 'poke', 'screen_shake', 'music_card', 'link_card'].includes(type);
}

function normalizeWechatUrl(value) {
    let raw = String(value || '').trim();
    raw = raw.replace(/[，。；、\s]+$/g, '');
    if (!raw) return '';
    if (/^www\./i.test(raw)) raw = `https://${raw}`;
    if (!/^https?:\/\//i.test(raw)) return '';
    return raw.replace(/^http:\/\//i, 'https://');
}

function extractWechatFirstUrl(value) {
    const source = String(value || '');
    const match = source.match(/https?:\/\/[^\s"'<>]+|www\.[^\s"'<>]+/i);
    return match ? normalizeWechatUrl(match[0]) : '';
}

function parseWechatAmountNumber(value) {
    const num = parseFloat(String(value || '').replace(/[^\d.]/g, ''));
    return Number.isFinite(num) && num > 0 ? num : null;
}

function normalizeWechatAmount(value, fallback = '0.00') {
    const num = parseWechatAmountNumber(value);
    if (num == null) return fallback;
    return num.toFixed(2);
}

function normalizeWechatDuration(value, fallback) {
    const num = parseInt(String(value || '').replace(/[^\d]/g, ''), 10);
    if (!Number.isFinite(num) || num <= 0) return fallback;
    return Math.min(num, 5999);
}

function isWechatDurationArg(value) {
    return /^\s*\d+\s*(?:秒|s|S)?\s*$/.test(String(value || ''));
}

function formatWechatDuration(seconds) {
    const sec = normalizeWechatDuration(seconds, 1);
    if (sec < 60) return `${sec}秒`;
    const min = Math.floor(sec / 60);
    const rest = sec % 60;
    return rest ? `${min}分${String(rest).padStart(2, '0')}秒` : `${min}分钟`;
}

function estimateWechatVoiceDuration(text) {
    const source = String(text || '').trim();
    if (!source) return 1;
    const cjkCount = (source.match(/[\u3400-\u9fff\uf900-\ufaff]/g) || []).length;
    const asciiText = source.replace(/[\u3400-\u9fff\uf900-\ufaff]/g, ' ');
    const wordTokens = (asciiText.match(/[A-Za-z0-9]+/g) || [])
        .reduce((sum, word) => sum + Math.max(1, Math.ceil(word.length / 4)), 0);
    const punctuationTokens = Math.ceil(((source.match(/[，。！？、,.!?;；:：]/g) || []).length) * 0.35);
    const tokenCount = Math.max(1, cjkCount + wordTokens + punctuationTokens);
    return Math.max(1, Math.min(90, Math.ceil(tokenCount / 3.8)));
}

function updateWechatVoiceDurationEstimate() {
    const transcript = document.getElementById('wc-compose-transcript')?.value || '';
    const duration = estimateWechatVoiceDuration(transcript);
    const label = document.getElementById('wc-compose-duration-estimate');
    if (label) label.textContent = `${duration}"`;
}

function toggleWechatVoiceTranscript(bubbleEl) {
    if (!bubbleEl || !bubbleEl.querySelector('.msg-voice-transcript')) return;
    bubbleEl.classList.toggle('show-transcript');
}

function toggleWechatVoiceMessage(bubbleEl) {
    if (!bubbleEl) return;
    const audio = bubbleEl.querySelector('audio');
    if (!audio || !audio.getAttribute('src')) {
        toggleWechatVoiceTranscript(bubbleEl);
        return;
    }
    document.querySelectorAll('.msg-voice-bubble.is-playing').forEach(item => {
        if (item === bubbleEl) return;
        const otherAudio = item.querySelector('audio');
        if (otherAudio) otherAudio.pause();
        item.classList.remove('is-playing');
        item.querySelector('.msg-voice-play-state i')?.classList.replace('ri-pause-mini-fill', 'ri-play-mini-fill');
    });
    const icon = bubbleEl.querySelector('.msg-voice-play-state i');
    if (!audio.paused && !audio.ended) {
        audio.pause();
        bubbleEl.classList.remove('is-playing');
        icon?.classList.replace('ri-pause-mini-fill', 'ri-play-mini-fill');
        return;
    }
    audio.onended = () => {
        bubbleEl.classList.remove('is-playing');
        icon?.classList.replace('ri-pause-mini-fill', 'ri-play-mini-fill');
    };
    audio.play().then(() => {
        bubbleEl.classList.add('is-playing');
        icon?.classList.replace('ri-play-mini-fill', 'ri-pause-mini-fill');
    }).catch(() => {
        bubbleEl.classList.remove('is-playing');
        icon?.classList.replace('ri-pause-mini-fill', 'ri-play-mini-fill');
        if (typeof showWechatToast === 'function') showWechatToast('语音播放失败');
    });
}

function getWechatCallDescription(msg) {
    const status = msg.status || '已结束';
    const duration = parseInt(msg.duration, 10);
    const rawReason = msg.reason || msg.note || '';
    const direction = msg.callDirection || msg.direction || (msg.isMe ? 'outgoing' : 'incoming');
    let displayStatus = status;
    if (status === '已拒绝') {
        displayStatus = direction === 'incoming' ? '你已拒绝' : '对方已拒绝';
    } else if (status === '未接通') {
        displayStatus = direction === 'incoming' ? '未接通' : '对方未接通';
    } else if (status === '已取消') {
        displayStatus = direction === 'incoming' ? '对方已取消' : '已取消';
    } else if (status === '对方已挂断') {
        displayStatus = '对方已挂断';
    }
    const reason = rawReason && rawReason !== displayStatus ? rawReason : '';
    if ((status === '已结束' || status === '对方已挂断') && Number.isFinite(duration) && duration > 0) {
        return reason ? `${displayStatus} · ${formatWechatDuration(duration)} · ${reason}` : `${displayStatus} · ${formatWechatDuration(duration)}`;
    }
    return reason ? `${displayStatus} · ${reason}` : displayStatus;
}

function getWechatMessageSummary(msg) {
    if (!msg) return '[消息]';
    if (isWechatRegexPayloadMessage(msg)) return '[状态更新]';
    if (msg.description && msg.type !== 'voiceCall' && msg.type !== 'videoCall') return msg.description;
    if (msg.type === 'sticker') {
        const name = msg.stickerName || msg.name || '';
        return name ? `[表情] ${name}` : '[表情]';
    }
    if (msg.type === 'image') {
        return msg.description || '[图片]';
    }
    if (msg.type === 'voice') {
        const text = msg.transcript ? ` ${msg.transcript}` : '';
        return `[语音 ${formatWechatDuration(msg.duration || 8)}]${text}`;
    }
    if (msg.type === 'transfer') {
        const note = msg.note ? ` ${msg.note}` : '';
        if (msg.returned || msg.status === '已退回') return `[已退回转账 ¥${normalizeWechatAmount(msg.amount)}]${note}`;
        return msg.receipt ? `[已收取转账 ¥${normalizeWechatAmount(msg.amount)}]${note}` : `[转账 ¥${normalizeWechatAmount(msg.amount)}]${note}`;
    }
    if (msg.type === 'redpacket') {
        const title = msg.title || msg.note || '恭喜发财，大吉大利';
        const status = msg.status ? ` ${msg.status}` : '';
        if (msg.returned || msg.status === '已退回') return `[已退回红包] ${title}`;
        return msg.receipt ? `[已收取红包] ${title}` : `[红包${status}] ${title}`;
    }
    if (msg.type === 'gift') {
        const item = msg.item && typeof msg.item === 'object' ? msg.item : {};
        const name = item.name || msg.title || '礼物';
        const status = msg.status ? ` ${msg.status}` : '';
        return msg.receipt ? `[已收取礼物] ${name}` : `[礼物${status}] ${name}`;
    }
    if (msg.type === 'intimatePay') {
        const status = msg.status ? ` ${msg.status}` : '';
        return `[亲密付${status}] ${msg.note || '邀请开通'}`;
    }
    if (msg.type === 'poke') {
        return `[拍一拍] ${msg.content || msg.note || '拍了拍对方'}`;
    }
    if (msg.type === 'screen_shake') {
        return `[震动屏幕] ${msg.content || msg.note || '发送了一次屏幕震动'}`;
    }
    if (msg.type === 'music_card') {
        const music = msg.music && typeof msg.music === 'object' ? msg.music : {};
        const title = music.title || msg.title || '音乐';
        const artist = music.artist || msg.artist || '';
        return `[音乐卡片] ${title}${artist ? ` - ${artist}` : ''}`;
    }
    if (msg.type === 'link_card') {
        const title = msg.title || msg.url || '链接';
        return `[链接] ${title} ${msg.url || ''}`.trim();
    }
    if (msg.type === 'voiceCall') {
        return `[语音通话] ${getWechatCallDescription(msg)}`;
    }
    if (msg.type === 'videoCall') {
        return `[视频通话] ${getWechatCallDescription(msg)}`;
    }
    if (msg.type === 'share_card') {
        const card = msg.card && typeof msg.card === 'object' ? msg.card : {};
        const title = card.title || msg.title || '转发';
        const text = card.text || msg.text || msg.content || '';
        return `[${title}] ${String(text || '').replace(/<[^>]+>/g, '').slice(0, 80)}`;
    }
    return String(msg.content || '[消息]');
}

function syncWechatMessageDescription(msg) {
    if (!msg) return msg;
    if (msg.type === 'share_card') {
        msg.description = getWechatMessageSummary({ ...msg, description: '' });
        return msg;
    }
    if (isWechatSpecialMessage(msg.type)) {
        msg.description = getWechatMessageSummary({ ...msg, description: '' });
        if (msg.type === 'poke' || msg.type === 'screen_shake' || msg.type === 'music_card' || msg.type === 'link_card') {
            if (!msg.content && msg.note) msg.content = msg.note;
        } else if (!msg.content || msg.type !== 'voice') {
            msg.content = msg.description;
        }
    }
    return msg;
}

function getWechatTextMessageVisibleText(msg, charObj = null) {
    if (!msg || isWechatSpecialMessage(msg.type) || msg.type === 'system_notice') return '[special]';
    const source = cleanWechatVisibleContent(msg.content || msg.description || msg.dialogue || msg.text || '');
    if (!source || isWechatAiMetaLeakContent(source)) return '';
    const char = charObj || getCurrentChatChar?.();
    if (!msg.isMe && isWechatGroupSystemActionEchoContent(source, char)) return '';
    if (
        isRichMessageContent(source)
        || looksLikeWechatRegexPayloadSource(source)
        || looksLikeWechatPipeStatusPayloadSource(source)
        || willWechatRegexRenderRich(source, char)
        || isWechatStandaloneRichOrRegexSource(source, char)
    ) {
        return source;
    }
    const rendered = processMsgContent(source, char);
    return String(rendered || '').replace(/<[^>]+>/g, '').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ').trim();
}

function isWechatGroupSystemActionEchoContent(text, group) {
    if (!group?.isGroupChat) return false;
    const compact = cleanWechatVisibleContent(text)
        .replace(/[「」『』“”"'`]/g, '')
        .replace(/\s+/g, '')
        .replace(/[。.!！?？]+$/g, '');
    if (!compact || compact.length > 80) return false;
    return /^(?:[^，、：:]{1,24})?(?:已)?将[^，、：:]{1,24}(?:设置为|设为|升为)群?管理员$/.test(compact)
        || /^(?:[^，、：:]{1,24})?(?:修改|更改|改了?|把).{0,8}群(?:聊)?名(?:称)?(?:为|成|改为).{1,32}$/.test(compact)
        || /^(?:[^，、：:]{1,24})?将群(?:聊)?名(?:称)?从.{1,32}改为.{1,32}$/.test(compact);
}

function isWechatRenderableMessage(msg, charObj = null) {
    if (!msg) return false;
    if (msg.hiddenFromChat || msg.internalEvent) return false;
    if (msg.type === 'system_notice') return true;
    if (isWechatSpecialMessage(msg.type) || msg.type === 'image' || msg.type === 'sticker') return true;
    return !!getWechatTextMessageVisibleText(msg, charObj);
}

function pruneWechatEmptyAiTextMessages(char) {
    if (!char || !Array.isArray(char.history)) return false;
    const before = char.history.length;
    char.history = char.history.filter(msg => msg?.isMe || isWechatRenderableMessage(msg, char));
    return char.history.length !== before;
}

function getWechatLinkHost(url) {
    try {
        return new URL(normalizeWechatUrl(url)).hostname.replace(/^www\./i, '');
    } catch (_) {
        return String(url || '').replace(/^https?:\/\//i, '').split('/')[0] || '链接';
    }
}

function getWechatBuiltinEmojiAliasName(name) {
    const text = String(name || '').trim();
    const lower = text.toLowerCase();
    const aliases = {
        '发': '發',
        '發': '發',
        'emm': 'Emm',
        'ok': 'OK'
    };
    return aliases[text] || aliases[lower] || text;
}

function getWechatActiveBuiltinEmojiSource() {
    return getWechatUiThemeId() === 'qq' ? 'qq' : 'wechat';
}

function buildWechatBuiltinEmojiMarker(name, source = getWechatActiveBuiltinEmojiSource(), url = '') {
    const markerSource = source === 'qq' ? 'QQ_EMOJI' : 'WECHAT_EMOJI';
    const label = source === 'qq' ? String(name || '').trim() : getWechatBuiltinEmojiAliasName(name);
    if (!label) return '';
    return `[[${markerSource}:${encodeURIComponent(label)}${url ? `:${encodeURIComponent(url)}` : ''}]]`;
}

function parseWechatBuiltinEmojiMarker(text) {
    const match = String(text || '').trim().match(/^\[\[(WECHAT_EMOJI|QQ_EMOJI):([^:\]]+)(?::([^\]]+))?\]\]$/);
    if (!match) return null;
    const decode = value => {
        try {
            return decodeURIComponent(value || '');
        } catch (_) {
            return value || '';
        }
    };
    return {
        source: match[1] === 'QQ_EMOJI' ? 'qq' : 'wechat',
        name: decode(match[2]),
        url: decode(match[3])
    };
}

function hasWechatBuiltinEmojiMarker(text) {
    return /\[\[(?:WECHAT_EMOJI|QQ_EMOJI):[^\]]+\]\]/.test(String(text || ''));
}

function getSingleWechatBuiltinEmojiMarker(text) {
    return parseWechatBuiltinEmojiMarker(text);
}

function getWechatInputEmojiDisplayToken(name) {
    const label = String(name || '').trim();
    if (!label) return '';
    if (getWechatUiThemeId() === 'qq') return `[${label}]`;
    return WECHAT_INPUT_EMOJI_MAP[label] || label;
}

function getWechatInputEmojiDraftItems() {
    if (!Array.isArray(window._wechatInputEmojiDraftItems)) window._wechatInputEmojiDraftItems = [];
    return window._wechatInputEmojiDraftItems;
}

function rememberWechatInputEmojiDraftItem(item) {
    if (!item || !item.token || !item.name) return;
    getWechatInputEmojiDraftItems().push(item);
}

function clearWechatInputEmojiDraftItems() {
    window._wechatInputEmojiDraftItems = [];
}

function prepareWechatTextWithDraftEmojis(text) {
    if (!['wechat', 'qq'].includes(getWechatUiThemeId())) return { text: String(text || ''), hasEmoji: false };
    let output = String(text || '');
    let hasEmoji = hasWechatBuiltinEmojiMarker(output);
    getWechatInputEmojiDraftItems().forEach(item => {
        if (!item || !item.token || !item.name) return;
        const index = output.indexOf(item.token);
        if (index < 0) return;
        const marker = buildWechatBuiltinEmojiMarker(item.name, item.source || getWechatActiveBuiltinEmojiSource(), item.url || '');
        if (!marker) return;
        output = output.slice(0, index) + marker + output.slice(index + item.token.length);
        hasEmoji = true;
    });
    return { text: output, hasEmoji };
}

function getWechatRichInputElement() {
    return document.getElementById('wc-rich-msg-input');
}

function isWechatRichInputEnabled() {
    return ['wechat', 'qq'].includes(getWechatUiThemeId()) && !!getWechatRichInputElement();
}

function isWechatMobileKeyboardContext() {
    const ua = navigator.userAgent || '';
    return /Android|iPhone|iPad|iPod|Mobile|SamsungBrowser/i.test(ua)
        || (navigator.maxTouchPoints > 1 && window.matchMedia?.('(max-width: 820px)')?.matches);
}

function handleWechatMessageInputCompositionStart() {
    window._wechatInputComposing = true;
}
window.handleWechatMessageInputCompositionStart = handleWechatMessageInputCompositionStart;

function handleWechatMessageInputCompositionEnd(event) {
    window._wechatInputComposing = false;
    if (event?.target?.id === 'wc-rich-msg-input') handleWechatRichInputInput();
    else syncWechatDraftState();
}
window.handleWechatMessageInputCompositionEnd = handleWechatMessageInputCompositionEnd;

function insertWechatPlainInputLineBreak(inputEl) {
    if (!inputEl) return;
    const start = Number.isFinite(inputEl.selectionStart) ? inputEl.selectionStart : inputEl.value.length;
    const end = Number.isFinite(inputEl.selectionEnd) ? inputEl.selectionEnd : start;
    inputEl.value = `${inputEl.value.slice(0, start)}\n${inputEl.value.slice(end)}`;
    const nextPos = start + 1;
    try {
        inputEl.setSelectionRange(nextPos, nextPos);
    } catch (e) {}
    syncWechatDraftState();
    inputEl.dispatchEvent(new Event('input', { bubbles: true }));
}

function handleWechatMessageInputBeforeInput(event) {
    if (!event || !['insertLineBreak', 'insertParagraph'].includes(event.inputType)) return;
    if (event.isComposing || window._wechatInputComposing) return;
    if (window._wechatAllowNextLineBreakAt && Date.now() - window._wechatAllowNextLineBreakAt < 300) {
        window._wechatAllowNextLineBreakAt = 0;
        return;
    }
    if (!isWechatMobileKeyboardContext()) return;
    event.preventDefault();
    sendWechatMessage();
}
window.handleWechatMessageInputBeforeInput = handleWechatMessageInputBeforeInput;

function handleWechatMessageInputKeydown(event) {
    if (!event || event.key !== 'Enter') return;
    if (event.isComposing || event.keyCode === 229 || event.which === 229 || window._wechatInputComposing) return;
    if (event.shiftKey && !event.altKey && !event.ctrlKey && !event.metaKey) {
        if (event.target?.id === 'wc-rich-msg-input') {
            event.preventDefault();
            insertWechatRichInputLineBreak();
            handleWechatRichInputInput();
        }
        window._wechatAllowNextLineBreakAt = Date.now();
        return;
    }
    if (event.altKey || event.ctrlKey || event.metaKey) return;
    event.preventDefault();
    sendWechatMessage();
}
window.handleWechatMessageInputKeydown = handleWechatMessageInputKeydown;

function isWechatSelectionInside(element) {
    const selection = window.getSelection && window.getSelection();
    if (!selection || !selection.rangeCount || !element) return false;
    const node = selection.anchorNode;
    return !!(node && (node === element || element.contains(node)));
}

function setWechatRichInputCaretAfter(node) {
    const selection = window.getSelection && window.getSelection();
    if (!selection || !node) return;
    const range = document.createRange();
    range.setStartAfter(node);
    range.collapse(true);
    selection.removeAllRanges();
    selection.addRange(range);
}

function syncWechatHiddenInputFromRich() {
    const inputEl = document.getElementById('wc-msg-input');
    if (!inputEl || !isWechatRichInputEnabled()) return;
    inputEl.value = getWechatMessageInputValue({ markers: false });
}

function getWechatRichInputValue(options = {}) {
    const richEl = getWechatRichInputElement();
    if (!richEl) return '';
    const useMarkers = !!options.markers;
    const readNode = node => {
        if (!node) return '';
        if (node.nodeType === Node.TEXT_NODE) return node.nodeValue || '';
        if (node.nodeType !== Node.ELEMENT_NODE) return '';
        const el = node;
        if (el.matches && el.matches('img.wc-rich-input-emoji')) {
            const name = el.dataset.emojiName || el.getAttribute('alt') || '';
            return useMarkers
                ? buildWechatBuiltinEmojiMarker(name.replace(/^\[|\]$/g, ''), el.dataset.emojiSource || getWechatActiveBuiltinEmojiSource(), el.dataset.emojiUrl || '')
                : (el.dataset.displayToken || el.getAttribute('alt') || '');
        }
        if (el.tagName === 'BR') return '\n';
        let text = '';
        el.childNodes.forEach(child => { text += readNode(child); });
        if (['DIV', 'P'].includes(el.tagName) && text && !text.endsWith('\n')) text += '\n';
        return text;
    };
    let text = '';
    richEl.childNodes.forEach(node => { text += readNode(node); });
    return text.replace(/\n+$/g, '');
}

function getWechatMessageInputValue(options = {}) {
    if (isWechatRichInputEnabled()) return getWechatRichInputValue(options);
    const inputEl = document.getElementById('wc-msg-input');
    return inputEl ? inputEl.value : '';
}

function clearWechatMessageInput() {
    const inputEl = document.getElementById('wc-msg-input');
    const richEl = getWechatRichInputElement();
    if (inputEl) inputEl.value = '';
    if (richEl) richEl.innerHTML = '';
    clearWechatInputEmojiDraftItems();
}

function handleWechatRichInputInput() {
    syncWechatHiddenInputFromRich();
    syncWechatDraftState();
}

function insertWechatRichInputText(text) {
    const richEl = getWechatRichInputElement();
    if (!richEl) return;
    richEl.focus();
    const selection = window.getSelection && window.getSelection();
    const range = selection && selection.rangeCount && isWechatSelectionInside(richEl)
        ? selection.getRangeAt(0)
        : document.createRange();
    if (!selection || !selection.rangeCount || !isWechatSelectionInside(richEl)) {
        range.selectNodeContents(richEl);
        range.collapse(false);
    }
    range.deleteContents();
    const textNode = document.createTextNode(String(text || ''));
    range.insertNode(textNode);
    setWechatRichInputCaretAfter(textNode);
    handleWechatRichInputInput();
}

function handleWechatRichInputPaste(event) {
    if (!isWechatRichInputEnabled()) return;
    event.preventDefault();
    const text = event.clipboardData?.getData('text/plain') || '';
    insertWechatRichInputText(text);
}

function insertWechatRichInputEmoji(name, url = '') {
    const richEl = getWechatRichInputElement();
    const source = getWechatActiveBuiltinEmojiSource();
    const label = source === 'qq' ? String(name || '').trim() : getWechatBuiltinEmojiAliasName(name);
    const resolvedUrl = url || (source === 'qq' ? getQqBuiltinEmojiUrlByName(label) : getWechatBuiltinEmojiUrlByName(label));
    if (!richEl || !label || !resolvedUrl) return false;
    richEl.focus();
    const img = document.createElement('img');
    img.className = 'wc-rich-input-emoji';
    img.src = resolvedUrl;
    img.alt = `[${label}]`;
    img.title = label;
    img.draggable = false;
    img.dataset.emojiName = label;
    img.dataset.emojiSource = source;
    img.dataset.emojiUrl = resolvedUrl;
    img.dataset.displayToken = getWechatInputEmojiDisplayToken(name);

    const selection = window.getSelection && window.getSelection();
    const range = selection && selection.rangeCount && isWechatSelectionInside(richEl)
        ? selection.getRangeAt(0)
        : document.createRange();
    if (!selection || !selection.rangeCount || !isWechatSelectionInside(richEl)) {
        range.selectNodeContents(richEl);
        range.collapse(false);
    }
    range.deleteContents();
    range.insertNode(img);
    setWechatRichInputCaretAfter(img);
    handleWechatRichInputInput();
    return true;
}

function buildWechatUserTextMessage(text) {
    const prepared = prepareWechatTextWithDraftEmojis(text);
    const content = prepared.text;
    const singleEmoji = getSingleWechatBuiltinEmojiMarker(content);
    if (singleEmoji && singleEmoji.name) {
        const emojiUrl = singleEmoji.url || (singleEmoji.source === 'qq'
            ? getQqBuiltinEmojiUrlByName(singleEmoji.name)
            : getWechatBuiltinEmojiUrlByName(singleEmoji.name));
        return {
            type: 'sticker',
            isMe: true,
            content: emojiUrl,
            stickerName: singleEmoji.name,
            stickerKind: singleEmoji.source === 'qq' ? 'qqEmoji' : 'wechatEmoji',
            emoji: true,
            timestamp: createMessageTimestamp()
        };
    }
    const url = extractWechatFirstUrl(content);
    if (!url) return { type: 'text', isMe: true, content, wechatEmojiText: prepared.hasEmoji, timestamp: createMessageTimestamp() };
    const note = String(content || '').replace(url, '').trim();
    return syncWechatMessageDescription({
        type: 'link_card',
        isMe: true,
        url,
        title: note || getWechatLinkHost(url),
        note,
        timestamp: createMessageTimestamp()
    });
}

function triggerWechatScreenFeedback(kind = 'shake') {
    const root = document.getElementById('wechat-chat-room') || document.querySelector('.phone-screen') || document.body;
    if (root) {
        root.classList.remove('wc-screen-shake');
        void root.offsetWidth;
        root.classList.add('wc-screen-shake');
        setTimeout(() => root.classList.remove('wc-screen-shake'), 460);
    }
    if (navigator.vibrate) navigator.vibrate(kind === 'poke' ? [22, 24, 22] : [42, 28, 42, 28, 42]);
}

function openWechatLinkCard(url) {
    const safeUrl = normalizeWechatUrl(url);
    if (!safeUrl) return;
    window.open(safeUrl, '_blank', 'noopener,noreferrer');
}

let wechatMusicCardPlaySeq = 0;
const WECHAT_MUSIC_QUEUE_ADDED_KEY = 'wechat_music_queue_added_tracks_v1';

function getWechatMusicAudioPlayer() {
    if (!window._wechatMusicCardAudio) {
        const existing = document.getElementById('wechat-music-card-audio');
        const audio = existing instanceof HTMLAudioElement ? existing : document.createElement('audio');
        audio.id = 'wechat-music-card-audio';
        audio.preload = 'auto';
        audio.removeAttribute('crossorigin');
        audio.playsInline = true;
        audio.muted = false;
        audio.volume = 1;
        audio.style.position = 'fixed';
        audio.style.left = '0';
        audio.style.bottom = '0';
        audio.style.width = '44px';
        audio.style.height = '24px';
        audio.style.opacity = '0.001';
        audio.style.pointerEvents = 'none';
        audio.style.zIndex = '2147483000';
        if (!audio.parentElement) document.body.appendChild(audio);
        audio.addEventListener('ended', handleWechatMusicPlaybackEnded);
        audio.addEventListener('error', () => {
            document.querySelectorAll('.msg-music-card.playing, .msg-music-card.loading').forEach(card => card.classList.remove('playing', 'loading'));
            updateWechatMusicListenProgress();
        });
        audio.addEventListener('timeupdate', () => {
            updateWechatMusicListenProgress();
            updateWechatMusicLyricsFloat(audio.currentTime || 0);
            updateWechatMusicIsland();
        });
        audio.addEventListener('loadedmetadata', updateWechatMusicListenProgress);
        audio.addEventListener('play', () => {
            updateWechatMusicListenProgress();
            updateWechatMusicIsland();
        });
        audio.addEventListener('pause', () => {
            updateWechatMusicListenProgress();
            updateWechatMusicIsland();
        });
        window._wechatMusicCardAudio = audio;
    }
    window._wechatMusicCardAudio.muted = false;
    window._wechatMusicCardAudio.volume = 1;
    return window._wechatMusicCardAudio;
}

function getWechatMusicAudioContext() {
    const AudioCtx = window.AudioContext || window.webkitAudioContext;
    if (!AudioCtx) return null;
    if (!window._wechatMusicAudioContext) window._wechatMusicAudioContext = new AudioCtx();
    return window._wechatMusicAudioContext;
}

function stopWechatMusicBufferPlayback() {
    const playback = window._wechatMusicBufferPlayback;
    if (playback?.source) {
        try { playback.source.onended = null; playback.source.stop(0); } catch (e) {}
    }
    clearInterval(window._wechatMusicBufferTicker);
    window._wechatMusicBufferTicker = null;
    window._wechatMusicBufferPlayback = null;
}

function insertWechatRichInputLineBreak() {
    const richEl = getWechatRichInputElement();
    if (!richEl) return;
    richEl.focus();
    const selection = window.getSelection && window.getSelection();
    if (!selection || !selection.rangeCount || !isWechatSelectionInside(richEl)) {
        const br = document.createElement('br');
        const spacer = document.createTextNode('');
        richEl.appendChild(br);
        richEl.appendChild(spacer);
        setWechatRichInputCaretAfter(spacer);
        return;
    }
    const range = selection.getRangeAt(0);
    range.deleteContents();
    const br = document.createElement('br');
    const spacer = document.createTextNode('');
    range.insertNode(spacer);
    range.insertNode(br);
    range.setStartAfter(spacer);
    range.collapse(true);
    selection.removeAllRanges();
    selection.addRange(range);
}

function getWechatMusicBufferPlaybackState() {
    const playback = window._wechatMusicBufferPlayback;
    if (!playback?.source || !playback.context) return null;
    const duration = Number(playback.duration || 0);
    const offset = Number(playback.offset || 0);
    const startedAt = Number(playback.startedAt || playback.context.currentTime || 0);
    const currentTime = Math.max(0, Math.min(duration || Infinity, offset + (playback.context.currentTime - startedAt)));
    if (duration > 0 && currentTime > duration + 0.25) return null;
    return {
        mode: 'buffer',
        playing: true,
        url: normalizeWechatUrl(playback.safeUrl || ''),
        currentTime,
        duration
    };
}

function getWechatMusicPlaybackState(targetUrl = '') {
    const target = normalizeWechatUrl(targetUrl || '');
    const audio = window._wechatMusicCardAudio;
    const audioUrl = normalizeWechatUrl(audio?.dataset?.cardUrl || '');
    if (audio && audioUrl && !audio.paused && !audio.ended && (!target || audioUrl === target)) {
        return {
            mode: 'audio',
            playing: true,
            url: audioUrl,
            currentTime: Number.isFinite(audio.currentTime) ? audio.currentTime : 0,
            duration: Number.isFinite(audio.duration) ? audio.duration : 0
        };
    }
    const bufferState = getWechatMusicBufferPlaybackState();
    if (bufferState && (!target || !bufferState.url || bufferState.url === target)) return bufferState;
    if (bufferState && !target) return bufferState;
    return { mode: '', playing: false, url: target || audioUrl, currentTime: 0, duration: 0 };
}

function startWechatMusicBufferTicker() {
    clearInterval(window._wechatMusicBufferTicker);
    window._wechatMusicBufferTicker = setInterval(() => {
        const state = getWechatMusicBufferPlaybackState();
        if (!state) {
            clearInterval(window._wechatMusicBufferTicker);
            window._wechatMusicBufferTicker = null;
            return;
        }
        updateWechatMusicListenProgress();
        updateWechatMusicLyricsFloat(state.currentTime || 0);
        updateWechatMusicIsland();
    }, 500);
}

function isWechatMusicBufferPlaying(safeUrl = '') {
    const playback = getWechatMusicBufferPlaybackState();
    const target = normalizeWechatUrl(safeUrl || '');
    return !!(playback && (!target || playback.url === target));
}

function isWechatMusicProxyUrl(url) {
    const safeUrl = normalizeWechatUrl(url || '');
    return /[?&]type=url\b/i.test(safeUrl) || /meting/i.test(safeUrl);
}

function isWechatTemporaryMusicCdnUrl(url) {
    const safeUrl = normalizeWechatUrl(url || '');
    return /(^https:\/\/m\d+\.music\.126\.net\/|\.music\.126\.net\/)/i.test(safeUrl)
        || /[?&](vuutv|authSecret|token|expires?)=/i.test(safeUrl);
}

function markWechatMusicCardNeedsTap(card, text = '音源准备好了，再点一次播放') {
    if (!card) return;
    card.classList.remove('loading');
    card.classList.add('needs-tap');
    card.dataset.playHint = text;
}

async function prepareWechatMusicCardPlayableUrl(card) {
    if (!card || card.dataset.playablePreparing === '1') return card?.dataset.audioUrl || '';
    const sourceUrl = normalizeWechatUrl(card.dataset.sourceUrl || card.dataset.audioUrl || '');
    if (!sourceUrl) return '';
    if (!isWechatMusicProxyUrl(sourceUrl)) {
        card.dataset.audioUrl = sourceUrl;
        card.dataset.sourceUrl = sourceUrl;
        card.dataset.playableReady = '1';
        return sourceUrl;
    }
    card.dataset.audioUrl = sourceUrl;
    card.dataset.sourceUrl = sourceUrl;
    card.dataset.playableReady = '1';
    return sourceUrl;
}

function getWechatResolvedMusicCache(url) {
    const cache = window._wechatResolvedMusicUrls || {};
    const item = cache[url];
    if (!item) return '';
    if (typeof item === 'string') return item;
    if (Date.now() - Number(item.time || 0) > 3 * 60 * 1000) return '';
    return item.url || '';
}

function setWechatResolvedMusicCache(url, resolvedUrl) {
    if (!url || !resolvedUrl) return;
    window._wechatResolvedMusicUrls = window._wechatResolvedMusicUrls || {};
    window._wechatResolvedMusicUrls[url] = { url: resolvedUrl, time: Date.now() };
}

async function resolveWechatPlayableMusicUrl(url) {
    const safeUrl = normalizeWechatUrl(String(url || '').replace(/\\u0026/gi, '&'));
    if (!safeUrl) return '';
    const cached = getWechatResolvedMusicCache(safeUrl);
    if (cached) return cached;
    if (!/[?&]type=url\b/i.test(safeUrl) && !/meting/i.test(safeUrl)) {
        setWechatResolvedMusicCache(safeUrl, safeUrl);
        return safeUrl;
    }
    try {
        const controller = new AbortController();
        const timer = setTimeout(() => controller.abort(), 4500);
        const resp = await fetch(safeUrl, { method: 'HEAD', redirect: 'follow', cache: 'no-store', signal: controller.signal });
        clearTimeout(timer);
        const contentType = resp.headers.get('content-type') || '';
        const finalUrl = normalizeWechatUrl(resp.url || '');
        if (resp.ok && finalUrl && (finalUrl !== safeUrl || /^audio\//i.test(contentType) || /\.(m4a|mp3|flac|aac|ogg)(\?|$)/i.test(finalUrl))) {
            setWechatResolvedMusicCache(safeUrl, finalUrl);
            return finalUrl;
        }
    } catch (e) {}
    setWechatResolvedMusicCache(safeUrl, safeUrl);
    return safeUrl;
}

function updateWechatMusicCardPlayingState(audioUrl, playing, loading = false) {
    document.querySelectorAll('.msg-music-card').forEach(card => {
        const matched = card.dataset.audioUrl === audioUrl;
        card.classList.toggle('playing', !!playing && matched);
        card.classList.toggle('loading', !!loading && matched);
        if (!matched) card.classList.remove('playing', 'loading');
    });
    const player = document.getElementById('wc-music-listen-player');
    if (player && player.dataset.audioUrl === audioUrl) {
        player.classList.toggle('playing', !!playing);
        player.classList.toggle('loading', !!loading);
        const icon = player.querySelector('.wc-music-listen-play i');
        if (icon) icon.className = loading ? 'ri-loader-4-line' : (playing ? 'ri-pause-fill' : 'ri-play-fill');
    }
}

function getWechatMusicCardMessageFromElement(card) {
    const row = card?.closest?.('.msg-row');
    const index = Number(row?.dataset?.msgIdx);
    const char = getCurrentChatChar();
    if (!char || !Array.isArray(char.history) || !Number.isInteger(index)) return null;
    const msg = char.history[index];
    return msg && msg.type === 'music_card' ? { char, msg, index } : null;
}

function getWechatMusicPlayerAvatars(char) {
    const userProfile = typeof getWechatChatUserProfile === 'function' ? getWechatChatUserProfile(char) : {};
    return {
        self: userProfile.avatar || '',
        peer: char?.avatar || DEFAULT_AVATAR
    };
}

function getWechatMusicOverlayRoot() {
    return getWechatModalRoot();
}

function mountWechatMusicOverlayElement(el) {
    const root = getWechatMusicOverlayRoot();
    if (el && root && el.parentElement !== root) root.appendChild(el);
    return el;
}

function ensureWechatMusicListenPlayer() {
    let panel = document.getElementById('wc-music-listen-player');
    if (panel) return mountWechatMusicOverlayElement(panel);
    panel = document.createElement('div');
    panel.id = 'wc-music-listen-player';
    panel.className = 'wc-music-listen-player hidden';
    panel.innerHTML = `
        <button type="button" class="wc-music-listen-close" onclick="closeWechatMusicListenPlayer()" aria-label="收起"><i class="ri-arrow-down-s-line"></i></button>
        <div class="wc-music-listen-art"><i class="ri-music-2-fill"></i></div>
        <div class="wc-music-listen-people">
            <img class="self" alt="">
            <img class="peer" alt="">
        </div>
        <div class="wc-music-listen-meta">
            <span>正在一起听歌</span>
            <strong></strong>
            <em></em>
        </div>
        <div class="wc-music-listen-progress" role="slider" aria-label="播放进度" aria-valuemin="0" aria-valuemax="100" aria-valuenow="0" onclick="seekWechatMusicListenProgress(event)" onpointerdown="beginWechatMusicListenSeek(event)"><span></span></div>
        <div class="wc-music-listen-actions">
            <button type="button" class="wc-music-listen-lyric" onclick="toggleWechatMusicLyricsFloat()" aria-label="歌词"><i class="ri-file-list-2-line"></i><span>歌词</span></button>
            <button type="button" onclick="playWechatMusicAdjacent(-1)" aria-label="上一首"><i class="ri-skip-back-fill"></i></button>
            <button type="button" class="wc-music-listen-play" onclick="toggleWechatMusicListenPlayback()" aria-label="播放"><i class="ri-play-fill"></i></button>
            <button type="button" onclick="playWechatMusicAdjacent(1)" aria-label="下一首"><i class="ri-skip-forward-fill"></i></button>
            <button type="button" onclick="toggleWechatMusicQueuePanel()" aria-label="音乐列表"><i class="ri-play-list-2-line"></i><span>列表</span></button>
            <button type="button" class="wc-music-listen-mode" onclick="cycleWechatMusicPlayMode()" aria-label="播放模式"><i class="ri-repeat-line"></i><span>列表循环</span></button>
            <button type="button" onclick="focusWechatMusicCommentInput()" aria-label="评论"><i class="ri-chat-1-line"></i><span>评论</span></button>
        </div>
        <div class="wc-music-queue-panel hidden">
            <div class="wc-music-queue-head"><span>音乐列表</span><button type="button" onclick="openWechatMusicQueueComposer()"><i class="ri-add-line"></i>继续添加音乐</button></div>
            <div class="wc-music-queue-list"></div>
        </div>
    `;
    mountWechatMusicOverlayElement(panel);
    bindWechatMusicQueueScroll(panel);
    return panel;
}

function bindWechatMusicQueueScroll(panel) {
    const list = panel?.querySelector('.wc-music-queue-list');
    if (!list || list.dataset.scrollBound === '1') return;
    list.dataset.scrollBound = '1';
    ['touchstart', 'touchmove', 'wheel'].forEach(type => {
        list.addEventListener(type, event => event.stopPropagation(), { passive: type !== 'touchmove' });
    });
}

function openWechatMusicListenPlayer(info, cardEl = null, msg = null, char = null) {
    const panel = ensureWechatMusicListenPlayer();
    const avatars = getWechatMusicPlayerAvatars(char || getCurrentChatChar());
    const previousKey = panel.dataset.trackKey || '';
    const nextKey = getWechatMusicTrackMatchKey(info || {});
    panel.dataset.audioUrl = info.audioUrl || '';
    panel.dataset.title = info.title || '一起听歌';
    panel.dataset.artist = info.artist || '';
    panel.dataset.artwork = info.artwork || '';
    panel.dataset.sourceUrl = info.sourceAudioUrl || info.audioUrl || '';
    panel.dataset.msgIndex = cardEl?.closest?.('.msg-row')?.dataset?.msgIdx || '';
    panel.dataset.lyricsText = info.lyricsText || '';
    panel.dataset.lyricsUrl = info.lyricsUrl || '';
    panel.dataset.sourceKey = info.sourceKey || '';
    panel.dataset.sourceMeta = info.sourceMeta || '';
    panel.dataset.sourceName = info.sourceName || '';
    panel.dataset.trackKey = nextKey;
    if (previousKey !== nextKey) {
        delete panel.dataset.lyricsLoaded;
        delete panel.dataset.lyricsLines;
        const lyricBox = document.getElementById('wc-music-lyrics-float');
        const lyricList = lyricBox?.querySelector('.wc-music-lyrics-lines');
        if (lyricList && lyricBox && !lyricBox.classList.contains('hidden')) {
            lyricList.innerHTML = '<p class="wc-music-lyrics-empty">正在载入歌词...</p>';
            getWechatMusicLyricsForPanel(panel).then(lines => {
                if (panel.dataset.trackKey !== nextKey) return;
                lyricList.innerHTML = lines.map((line, index) => `
                    <p class="wc-music-lyric-line" data-time="${Number.isFinite(line.time) ? line.time : ''}" data-line-index="${index}">${wcEscapeHtml(line.text)}</p>
                `).join('') || '<p class="wc-music-lyrics-empty">没有歌词内容</p>';
                updateWechatMusicLyricsFloat(window._wechatMusicCardAudio?.currentTime || 0, true);
            }).catch(() => {
                if (panel.dataset.trackKey === nextKey) lyricList.innerHTML = '<p class="wc-music-lyrics-empty">没有歌词内容</p>';
            });
        }
    }
    panel.querySelector('.wc-music-listen-art').innerHTML = info.artwork
        ? `<img src="${wcEscapeHtml(info.artwork)}" alt="" onerror="this.parentElement.innerHTML='<i class=&quot;ri-music-2-fill&quot;></i>'">`
        : '<i class="ri-music-2-fill"></i>';
    const selfAvatar = panel.querySelector('.wc-music-listen-people .self');
    const peerAvatar = panel.querySelector('.wc-music-listen-people .peer');
    if (selfAvatar) selfAvatar.src = avatars.self || DEFAULT_AVATAR;
    if (peerAvatar) peerAvatar.src = avatars.peer || DEFAULT_AVATAR;
    const titleEl = panel.querySelector('.wc-music-listen-meta strong');
    const artistEl = panel.querySelector('.wc-music-listen-meta em');
    if (titleEl) titleEl.textContent = info.title || '一起听歌';
    if (artistEl) artistEl.textContent = info.artist || info.sourceName || 'BYND Music';
    panel.classList.remove('hidden');
    hideWechatMusicIsland();
    renderWechatMusicPlayMode();
    renderWechatMusicQueuePanel();
    updateWechatMusicListenProgress();
    if (msg) {
        window._wechatMusicListenMessage = { msg, charId: char?.id || window.currentChatCharId || '' };
    }
}

function closeWechatMusicListenPlayer() {
    document.getElementById('wc-music-listen-player')?.classList.add('hidden');
    updateWechatMusicIsland();
}
window.closeWechatMusicListenPlayer = closeWechatMusicListenPlayer;

function collapseWechatMusicOverlaysToIsland() {
    document.getElementById('wc-music-listen-player')?.classList.add('hidden');
    document.getElementById('wc-music-lyrics-float')?.classList.add('hidden');
    updateWechatMusicIsland();
}
window.collapseWechatMusicOverlaysToIsland = collapseWechatMusicOverlaysToIsland;

function focusWechatMusicCommentInput() {
    closeWechatMusicListenPlayer();
    setTimeout(() => {
        const richInput = typeof getWechatRichInputElement === 'function' ? getWechatRichInputElement() : document.getElementById('wc-rich-msg-input');
        const input = (typeof isWechatRichInputEnabled === 'function' && isWechatRichInputEnabled() && richInput)
            ? richInput
            : (typeof getWechatActiveInputElement === 'function' ? getWechatActiveInputElement() : document.getElementById('wc-msg-input'));
        input?.focus?.();
        if (input?.isContentEditable) {
            const selection = window.getSelection && window.getSelection();
            const range = document.createRange();
            range.selectNodeContents(input);
            range.collapse(false);
            selection?.removeAllRanges();
            selection?.addRange(range);
        } else if (input && typeof input.setSelectionRange === 'function') {
            const end = input.value.length;
            input.setSelectionRange(end, end);
        }
    }, 30);
}
window.focusWechatMusicCommentInput = focusWechatMusicCommentInput;

function openWechatMusicQueueComposer() {
    openWechatComposer('music_card', null, { musicMode: 'queue' });
}
window.openWechatMusicQueueComposer = openWechatMusicQueueComposer;

function toggleWechatMusicListenPlayback() {
    const panel = document.getElementById('wc-music-listen-player');
    if (!panel) return;
    const playback = getWechatMusicPlaybackState(panel.dataset.audioUrl || '');
    if (playback.mode === 'buffer' && playback.playing) {
        stopWechatMusicBufferPlayback();
        updateWechatMusicCardPlayingState(panel.dataset.audioUrl || '', false);
        updateWechatMusicListenProgress();
        updateWechatMusicIsland();
        return;
    }
    playWechatMusicCard(panel.dataset.audioUrl || '', panel.dataset.title || '', panel.dataset.artist || '', panel, { toggle: true });
}
window.toggleWechatMusicListenPlayback = toggleWechatMusicListenPlayback;

function getWechatMusicPlayMode() {
    const mode = localStorage.getItem('wechat_music_play_mode') || 'list';
    return ['list', 'shuffle', 'one'].includes(mode) ? mode : 'list';
}

function renderWechatMusicPlayMode() {
    const btn = document.querySelector('#wc-music-listen-player .wc-music-listen-mode');
    if (!btn) return;
    const mode = getWechatMusicPlayMode();
    const meta = mode === 'shuffle'
        ? { icon: 'ri-shuffle-line', label: '随机' }
        : mode === 'one'
            ? { icon: 'ri-repeat-one-line', label: '单曲循环' }
            : { icon: 'ri-repeat-line', label: '列表循环' };
    btn.innerHTML = `<i class="${meta.icon}"></i><span>${meta.label}</span>`;
}

function cycleWechatMusicPlayMode() {
    const modes = ['list', 'shuffle', 'one'];
    const next = modes[(modes.indexOf(getWechatMusicPlayMode()) + 1) % modes.length];
    localStorage.setItem('wechat_music_play_mode', next);
    renderWechatMusicPlayMode();
}
window.cycleWechatMusicPlayMode = cycleWechatMusicPlayMode;

function getWechatMusicCardsInChat() {
    return Array.from(document.querySelectorAll('#chat-room-content .msg-music-card'))
        .filter(card => normalizeWechatUrl(card.dataset.audioUrl || ''));
}

function getWechatMusicQueueTracks() {
    const fromChat = getWechatMusicCardsInChat().map(card => ({
        title: card.dataset.title || '一起听歌',
        artist: card.dataset.artist || '',
        audioUrl: card.dataset.audioUrl || '',
        sourceAudioUrl: card.dataset.sourceUrl || card.dataset.audioUrl || '',
        artwork: card.dataset.artwork || '',
        lyricsText: card.dataset.lyricsText || '',
        lyricsUrl: card.dataset.lyricsUrl || '',
        sourceKey: card.dataset.sourceKey || '',
        sourceMeta: card.dataset.sourceMeta || '',
        sourceName: card.dataset.sourceName || '聊天'
    }));
    const added = getWechatPersistedMusicQueueTracks();
    let library = [];
    try {
        if (typeof getMusicLibraryTracks === 'function') {
            library = getMusicLibraryTracks().map(normalizeWechatMusicDraftTrack).filter(Boolean);
        }
    } catch (e) {}
    let favorites = [];
    try {
        const raw = typeof getMusicFavoritesStore === 'function'
            ? getMusicFavoritesStore()
            : JSON.parse(localStorage.getItem('bynd_music_favorites_v1') || '[]');
        favorites = (Array.isArray(raw) ? raw : []).map(normalizeWechatMusicDraftTrack).filter(Boolean);
    } catch (e) {}
    const seen = new Set();
    return [...fromChat, ...added, ...library, ...favorites].filter(track => {
        if (!track || !track.audioUrl) return false;
        const key = `${track.title}|${track.artist}|${track.audioUrl}`.toLowerCase();
        if (seen.has(key)) return false;
        seen.add(key);
        return true;
    }).slice(0, 40);
}

function isWechatMusicListenActive() {
    const panel = document.getElementById('wc-music-listen-player');
    const audio = window._wechatMusicCardAudio;
    const island = document.getElementById('wc-music-island');
    return !!(
        (panel && panel.dataset.audioUrl && !panel.classList.contains('hidden'))
        || (audio && audio.dataset && audio.dataset.cardUrl && !audio.ended && !audio.paused)
        || (island && island.classList.contains('show'))
    );
}

function getWechatPersistedMusicQueueTracks() {
    if (!Array.isArray(window._wechatMusicQueueAddedTracks)) {
        try {
            const raw = JSON.parse(localStorage.getItem(WECHAT_MUSIC_QUEUE_ADDED_KEY) || '[]');
            window._wechatMusicQueueAddedTracks = Array.isArray(raw) ? raw.map(normalizeWechatMusicDraftTrack).filter(Boolean) : [];
        } catch (e) {
            window._wechatMusicQueueAddedTracks = [];
        }
    }
    return window._wechatMusicQueueAddedTracks.map(normalizeWechatMusicDraftTrack).filter(Boolean);
}

function saveWechatPersistedMusicQueueTracks(tracks) {
    window._wechatMusicQueueAddedTracks = (Array.isArray(tracks) ? tracks : []).map(normalizeWechatMusicDraftTrack).filter(Boolean).slice(0, 80);
    try {
        localStorage.setItem(WECHAT_MUSIC_QUEUE_ADDED_KEY, JSON.stringify(window._wechatMusicQueueAddedTracks));
    } catch (e) {}
}

function addWechatMusicTrackToQueue(track) {
    const normalized = normalizeWechatMusicDraftTrack(track);
    if (!normalized || !normalized.audioUrl) return false;
    const added = getWechatPersistedMusicQueueTracks();
    const key = `${normalized.title}|${normalized.artist}|${normalized.audioUrl}`.toLowerCase();
    const exists = added.some(item => {
        const current = normalizeWechatMusicDraftTrack(item);
        return current && `${current.title}|${current.artist}|${current.audioUrl}`.toLowerCase() === key;
    });
    if (!exists) {
        added.unshift(normalized);
        saveWechatPersistedMusicQueueTracks(added);
    }
    renderWechatMusicQueuePanel();
    return true;
}
window.addWechatMusicTrackToQueue = addWechatMusicTrackToQueue;

function renderWechatMusicQueuePanel() {
    const panel = document.getElementById('wc-music-listen-player');
    const list = panel?.querySelector('.wc-music-queue-list');
    if (!panel || !list) return;
    const currentKey = getWechatMusicTrackMatchKey({
        title: panel.dataset.title || '',
        artist: panel.dataset.artist || '',
        audioUrl: panel.dataset.audioUrl || '',
        sourceAudioUrl: panel.dataset.sourceUrl || ''
    });
    const tracks = getWechatMusicQueueTracks();
    list.innerHTML = tracks.length ? tracks.map((track, index) => {
        const active = getWechatMusicTrackMatchKey(track) === currentKey;
        const art = track.artwork ? `<img src="${wcEscapeHtml(track.artwork)}" onerror="this.remove()">` : '<i class="ri-music-2-line"></i>';
        return `
            <button type="button" class="${active ? 'active' : ''}" onclick="playWechatMusicQueueTrack(${index})">
                <span>${art}</span>
                <b>${wcEscapeHtml(track.title || '一起听歌')}</b>
                <em>${wcEscapeHtml([track.artist, track.sourceName].filter(Boolean).join(' · ') || '音乐源')}</em>
                <i class="${active ? 'ri-volume-up-line' : 'ri-play-circle-line'}"></i>
            </button>
        `;
    }).join('') : '<div class="wc-music-queue-empty">当前没有可播放歌曲，点继续添加音乐。</div>';
    window._wechatMusicQueueTracks = tracks;
}

function toggleWechatMusicQueuePanel() {
    const panel = document.getElementById('wc-music-listen-player');
    const queue = panel?.querySelector('.wc-music-queue-panel');
    if (!queue) return;
    renderWechatMusicQueuePanel();
    queue.classList.toggle('hidden');
}
window.toggleWechatMusicQueuePanel = toggleWechatMusicQueuePanel;

function playWechatMusicQueueTrack(index) {
    const tracks = Array.isArray(window._wechatMusicQueueTracks) ? window._wechatMusicQueueTracks : getWechatMusicQueueTracks();
    const track = tracks[Number(index)];
    if (!track) return;
    playWechatMusicCard(track.audioUrl || track.playableUrl || track.sourceAudioUrl || '', track.title || '', track.artist || '', {
        dataset: {
            audioUrl: track.audioUrl || '',
            sourceUrl: track.sourceAudioUrl || track.audioUrl || '',
            playableUrl: track.playableUrl || '',
            title: track.title || '',
            artist: track.artist || '',
            artwork: track.artwork || '',
            lyricsText: track.lyricsText || '',
            lyricsUrl: track.lyricsUrl || '',
            sourceKey: track.sourceKey || '',
            sourceMeta: track.sourceMeta || '',
            sourceName: track.sourceName || ''
        },
        closest: () => null
    }, { queue: true });
}
window.playWechatMusicQueueTrack = playWechatMusicQueueTrack;

function getWechatMusicTrackMatchKey(track) {
    const audioUrl = normalizeWechatUrl(track?.audioUrl || '');
    const sourceUrl = normalizeWechatUrl(track?.sourceAudioUrl || track?.sourceUrl || '');
    const playableUrl = normalizeWechatUrl(track?.playableUrl || track?.resolvedAudioUrl || '');
    const title = String(track?.title || track?.trackName || track?.name || '').trim().toLowerCase();
    const artist = String(track?.artist || track?.artistName || track?.singer || '').trim().toLowerCase();
    return [audioUrl, sourceUrl, playableUrl].filter(Boolean).sort().join('|') || `${title}|${artist}`;
}

function playWechatMusicAdjacent(direction = 1, options = {}) {
    const tracks = getWechatMusicQueueTracks();
    if (!tracks.length) return;
    const panel = document.getElementById('wc-music-listen-player');
    const currentKey = getWechatMusicTrackMatchKey({
        title: panel?.dataset.title || '',
        artist: panel?.dataset.artist || '',
        audioUrl: panel?.dataset.audioUrl || '',
        sourceAudioUrl: panel?.dataset.sourceUrl || ''
    });
    const mode = options.mode || getWechatMusicPlayMode();
    let index = tracks.findIndex(track => getWechatMusicTrackMatchKey(track) === currentKey);
    if (mode === 'shuffle') {
        const next = tracks.length > 1
            ? Math.floor(Math.random() * (tracks.length - 1))
            : 0;
        index = tracks.length > 1 && next >= index ? next + 1 : next;
    } else {
        index = (index + Number(direction || 1) + tracks.length) % tracks.length;
    }
    if (index < 0) index = 0;
    window._wechatMusicQueueTracks = tracks;
    playWechatMusicQueueTrack(index);
}
window.playWechatMusicAdjacent = playWechatMusicAdjacent;

function handleWechatMusicPlaybackEnded() {
    document.querySelectorAll('.msg-music-card.playing').forEach(card => card.classList.remove('playing'));
    updateWechatMusicListenProgress();
    const audio = window._wechatMusicCardAudio;
    const panel = document.getElementById('wc-music-listen-player');
    const mode = getWechatMusicPlayMode();
    if (mode === 'one') {
        if (audio) {
            audio.currentTime = 0;
            audio.play().catch(() => {});
        }
        const replayUrl = panel?.dataset.audioUrl || audio?.dataset.cardUrl || '';
        if (replayUrl) updateWechatMusicCardPlayingState(replayUrl, true);
        return;
    }
    const tracks = getWechatMusicQueueTracks();
    if (tracks.length > 1 || mode === 'list' || mode === 'shuffle') {
        playWechatMusicAdjacent(1, { mode });
    }
}

function formatWechatMusicTime(seconds) {
    const value = Math.max(0, Math.floor(Number(seconds) || 0));
    return `${Math.floor(value / 60)}:${String(value % 60).padStart(2, '0')}`;
}

function seekWechatMusicListenProgress(event) {
    const bar = event?.currentTarget || document.querySelector('#wc-music-listen-player .wc-music-listen-progress');
    const panel = document.getElementById('wc-music-listen-player');
    const playback = getWechatMusicPlaybackState(panel?.dataset?.audioUrl || '');
    if (!bar || !playback.playing || !Number.isFinite(playback.duration) || playback.duration <= 0) return false;
    const rect = bar.getBoundingClientRect();
    const clientX = Number(event?.clientX ?? event?.touches?.[0]?.clientX ?? 0);
    const ratio = rect.width > 0 ? Math.max(0, Math.min(1, (clientX - rect.left) / rect.width)) : 0;
    const nextTime = ratio * playback.duration;
    renderWechatMusicSeekPreview(bar, ratio, nextTime);
    if (playback.mode === 'audio' && window._wechatMusicCardAudio) {
        window._wechatMusicCardAudio.currentTime = nextTime;
    } else if (playback.mode === 'buffer') {
        const current = window._wechatMusicBufferPlayback;
        const sourceUrl = current?.sourceUrl || current?.playableUrl || current?.safeUrl || panel?.dataset?.audioUrl || '';
        playWechatAudioBufferUrl(sourceUrl, current?.safeUrl || playback.url, { offset: nextTime }).catch(e => console.warn('wechat buffer seek failed:', e));
    }
    updateWechatMusicLyricsFloat(nextTime, true);
    return true;
}
window.seekWechatMusicListenProgress = seekWechatMusicListenProgress;

function renderWechatMusicSeekPreview(bar, ratio, nextTime) {
    const safeRatio = Math.max(0, Math.min(1, Number(ratio) || 0));
    const progressBar = bar || document.querySelector('#wc-music-listen-player .wc-music-listen-progress');
    const fill = progressBar?.querySelector('span');
    if (fill) fill.style.width = `${safeRatio * 100}%`;
    if (progressBar) {
        progressBar.setAttribute('aria-valuenow', String(Math.round(safeRatio * 100)));
        progressBar.dataset.seekPreviewTime = String(Math.max(0, Number(nextTime) || 0));
    }
}

function beginWechatMusicListenSeek(event) {
    const bar = event?.currentTarget;
    if (!bar) return;
    event.preventDefault();
    event.stopPropagation();
    bar.classList.add('is-seeking');
    if (typeof bar.setPointerCapture === 'function' && event.pointerId != null) {
        try { bar.setPointerCapture(event.pointerId); } catch (e) {}
    }
    seekWechatMusicListenProgress(event);
    const move = e => {
        e.preventDefault();
        seekWechatMusicListenProgress({ currentTarget: bar, clientX: e.clientX });
    };
    const end = () => {
        bar.classList.remove('is-seeking');
        delete bar.dataset.seekPreviewTime;
        updateWechatMusicListenProgress();
        window.removeEventListener('pointermove', move);
        window.removeEventListener('pointerup', end);
        window.removeEventListener('pointercancel', end);
    };
    window.addEventListener('pointermove', move, { passive: false });
    window.addEventListener('pointerup', end, { once: true });
    window.addEventListener('pointercancel', end, { once: true });
}
window.beginWechatMusicListenSeek = beginWechatMusicListenSeek;

function updateWechatMusicListenProgress() {
    const panel = document.getElementById('wc-music-listen-player');
    if (!panel || panel.classList.contains('hidden')) return;
    const fill = panel.querySelector('.wc-music-listen-progress span');
    const panelUrl = normalizeWechatUrl(panel.dataset.audioUrl || '');
    const playback = getWechatMusicPlaybackState(panelUrl);
    const isCurrent = !!(playback.playing && (!panelUrl || playback.url === panelUrl));
    const duration = isCurrent && Number.isFinite(playback.duration) ? playback.duration : 0;
    const current = isCurrent && Number.isFinite(playback.currentTime) ? playback.currentTime : 0;
    const percent = duration > 0 ? Math.max(0, Math.min(100, (current / duration) * 100)) : 0;
    const bar = panel.querySelector('.wc-music-listen-progress');
    if (!bar?.classList.contains('is-seeking')) {
        if (fill) fill.style.width = `${percent}%`;
        if (bar) bar.setAttribute('aria-valuenow', String(Math.round(percent)));
    }
    panel.classList.toggle('playing', !!isCurrent);
    const icon = panel.querySelector('.wc-music-listen-play i');
    if (icon && !panel.classList.contains('loading')) icon.className = isCurrent ? 'ri-pause-fill' : 'ri-play-fill';
}

function parseWechatMusicLyrics(raw, fallbackTitle = '') {
    const text = String(raw || '').trim();
    if (!text) return [];
    let autoTime = 0;
    return text.split(/\r?\n/).map(line => {
        const item = line.trim();
        if (!item) return null;
        const match = item.match(/^\[(\d{1,2}):(\d{2})(?:\.(\d{1,3}))?\]\s*(.*)$/);
        if (match) {
            return {
                time: Number(match[1]) * 60 + Number(match[2]) + Number(`0.${match[3] || 0}`),
                text: match[4].trim()
            };
        }
        const next = { time: autoTime, text: item };
        autoTime += 6;
        return next;
    }).filter(item => item && item.text);
}

async function getWechatMusicLyricsForPanel(panel) {
    if (!panel) return [];
    if (panel.dataset.lyricsLoaded === '1') {
        try { return JSON.parse(panel.dataset.lyricsLines || '[]') || []; } catch (e) { return []; }
    }
    let raw = panel.dataset.lyricsText || '';
    if (!raw && panel.dataset.lyricsUrl) {
        try {
            const resp = await fetch(panel.dataset.lyricsUrl);
            if (resp.ok) raw = await resp.text();
        } catch (e) {}
    }
    if (!raw && panel.dataset.sourceKey === 'meting' && panel.dataset.sourceMeta && typeof fetchMetingTextAsset === 'function') {
        try {
            const meta = JSON.parse(panel.dataset.sourceMeta);
            raw = await fetchMetingTextAsset(meta.base, meta.platform, 'lrc', meta.lyricId);
        } catch (e) {}
    }
    if (!raw && typeof fetchMusicLyrics === 'function') {
        try {
            const lyrics = await fetchMusicLyrics({
                trackName: panel.dataset.title || '',
                artistName: panel.dataset.artist || '',
                lyricsText: panel.dataset.lyricsText || '',
                lyricsUrl: panel.dataset.lyricsUrl || '',
                sourceKey: panel.dataset.sourceKey || '',
                sourceMeta: panel.dataset.sourceMeta || '',
                sourceName: panel.dataset.sourceName || ''
            });
            const lines = Array.isArray(lyrics?.lines) ? lyrics.lines.filter(line => line && line.text) : [];
            if (lines.length) {
                panel.dataset.lyricsLines = JSON.stringify(lines);
                panel.dataset.lyricsLoaded = '1';
                return lines;
            }
        } catch (e) {}
    }
    const lines = parseWechatMusicLyrics(raw, panel.dataset.title || '');
    panel.dataset.lyricsLines = JSON.stringify(lines);
    panel.dataset.lyricsLoaded = '1';
    return lines;
}

function ensureWechatMusicLyricsFloat() {
    let box = document.getElementById('wc-music-lyrics-float');
    if (box) return mountWechatMusicOverlayElement(box);
    box = document.createElement('div');
    box.id = 'wc-music-lyrics-float';
    box.className = 'wc-music-lyrics-float hidden';
    box.innerHTML = `
        <div class="wc-music-lyrics-handle">
            <span></span>
            <button type="button" onclick="hideWechatMusicLyricsFloat()" aria-label="关闭歌词"><i class="ri-close-line"></i></button>
        </div>
        <div class="wc-music-lyrics-lines"></div>
    `;
    mountWechatMusicOverlayElement(box);
    bindWechatMusicLyricsDrag(box);
    return box;
}

async function toggleWechatMusicLyricsFloat() {
    const panel = document.getElementById('wc-music-listen-player');
    const box = ensureWechatMusicLyricsFloat();
    if (!panel || panel.classList.contains('hidden')) return;
    if (!box.classList.contains('hidden')) {
        box.classList.add('hidden');
        return;
    }
    const list = box.querySelector('.wc-music-lyrics-lines');
    if (list) list.innerHTML = '<p class="wc-music-lyrics-empty">正在载入歌词...</p>';
    box.classList.remove('hidden');
    hideWechatMusicIsland();
    const lines = await getWechatMusicLyricsForPanel(panel);
    if (list) {
        list.innerHTML = lines.map((line, index) => `
            <p class="wc-music-lyric-line" data-time="${Number.isFinite(line.time) ? line.time : ''}" data-line-index="${index}">${wcEscapeHtml(line.text)}</p>
        `).join('') || '<p class="wc-music-lyrics-empty">没有歌词内容</p>';
    }
    updateWechatMusicLyricsFloat(window._wechatMusicCardAudio?.currentTime || 0, true);
}
window.toggleWechatMusicLyricsFloat = toggleWechatMusicLyricsFloat;

function hideWechatMusicLyricsFloat() {
    document.getElementById('wc-music-lyrics-float')?.classList.add('hidden');
    updateWechatMusicIsland();
}
window.hideWechatMusicLyricsFloat = hideWechatMusicLyricsFloat;

function getWechatCurrentLyricText() {
    const active = document.querySelector('#wc-music-lyrics-float .wc-music-lyric-line.active');
    if (active?.textContent?.trim()) return active.textContent.trim();
    const panel = document.getElementById('wc-music-listen-player');
    if (!panel?.dataset.lyricsLines) return '';
    try {
        const lines = JSON.parse(panel.dataset.lyricsLines || '[]');
        const current = Number(getWechatMusicPlaybackState(panel.dataset.audioUrl || '').currentTime || 0);
        let picked = null;
        (Array.isArray(lines) ? lines : []).forEach(line => {
            if (line && Number(line.time) <= current) picked = line;
        });
        return picked?.text || '';
    } catch (e) {
        return '';
    }
}

function ensureWechatMusicIsland() {
    let island = document.getElementById('wc-music-island');
    if (island) {
        if (!island.querySelector('.wc-music-island-art') || !island.querySelector('.wc-message-island-text')) {
            island.innerHTML = `
                <div class="wc-message-island-main">
                    <div class="wc-music-island-art"><i class="ri-music-2-fill"></i></div>
                    <div class="wc-message-island-text">
                        <strong></strong>
                        <span></span>
                    </div>
                </div>
                <i class="ri-disc-line"></i>
            `;
        }
        return mountWechatMusicOverlayElement(island);
    }
    island = document.createElement('div');
    island.id = 'wc-music-island';
    island.className = 'wc-message-island wc-music-island';
    island.innerHTML = `
        <div class="wc-message-island-main">
            <div class="wc-music-island-art"><i class="ri-music-2-fill"></i></div>
            <div class="wc-message-island-text">
                <strong></strong>
                <span></span>
            </div>
        </div>
        <i class="ri-disc-line"></i>
    `;
    mountWechatMusicOverlayElement(island);
    return island;
}

function shouldShowWechatMusicIsland() {
    const panel = document.getElementById('wc-music-listen-player');
    const playback = getWechatMusicPlaybackState();
    if (!playback.playing) return false;
    const lyrics = document.getElementById('wc-music-lyrics-float');
    return (!panel || panel.classList.contains('hidden')) && (!lyrics || lyrics.classList.contains('hidden'));
}

function updateWechatMusicIsland() {
    const existing = document.getElementById('wc-music-island');
    if (!shouldShowWechatMusicIsland()) {
        existing?.classList.remove('show');
        return;
    }
    const panel = document.getElementById('wc-music-listen-player');
    const island = ensureWechatMusicIsland();
    const playback = getWechatMusicPlaybackState();
    const audioUrl = panel?.dataset.audioUrl || playback.url || window._wechatMusicCardAudio?.dataset.cardUrl || '';
    const title = panel?.dataset.title || '正在播放';
    const artist = panel?.dataset.artist || panel?.dataset.sourceName || '';
    const lyric = getWechatCurrentLyricText();
    const artwork = panel?.dataset.artwork || '';
    const artEl = island.querySelector('.wc-music-island-art');
    if (artEl && artEl.dataset.artwork !== artwork) {
        artEl.dataset.artwork = artwork;
        artEl.innerHTML = artwork
            ? `<img src="${wcEscapeAttr(artwork)}" alt="" onerror="this.parentElement.dataset.artwork='';this.parentElement.innerHTML='<i class=&quot;ri-music-2-fill&quot;></i>'">`
            : '<i class="ri-music-2-fill"></i>';
    }
    const titleEl = island.querySelector('.wc-message-island-text strong');
    const subEl = island.querySelector('.wc-message-island-text span');
    if (titleEl) titleEl.textContent = lyric || title;
    if (subEl) subEl.textContent = lyric ? `${title}${artist ? ' · ' + artist : ''}` : (artist || '正在播放');
    island.onclick = () => {
        island.classList.remove('show');
        if (panel) {
            mountWechatMusicOverlayElement(panel);
            panel.classList.remove('hidden');
            renderWechatMusicQueuePanel();
            updateWechatMusicListenProgress();
        } else if (audioUrl) {
            openWechatMusicListenPlayer({ title, artist, audioUrl, artwork, sourceAudioUrl: audioUrl });
        }
    };
    island.classList.add('show');
}

function hideWechatMusicIsland() {
    document.getElementById('wc-music-island')?.classList.remove('show');
}
window.updateWechatMusicIsland = updateWechatMusicIsland;
window.hideWechatMusicIsland = hideWechatMusicIsland;

function updateWechatMusicLyricsFloat(currentTime, force = false) {
    const box = document.getElementById('wc-music-lyrics-float');
    if (!box || box.classList.contains('hidden')) return;
    const lines = Array.from(box.querySelectorAll('.wc-music-lyric-line'));
    if (!lines.length) return;
    let activeIndex = 0;
    for (let i = 0; i < lines.length; i++) {
        const time = Number(lines[i].dataset.time);
        if (Number.isFinite(time) && time <= currentTime + 0.2) activeIndex = i;
        else if (Number.isFinite(time)) break;
    }
    if (!force && Number(box.dataset.activeIndex) === activeIndex) return;
    box.dataset.activeIndex = String(activeIndex);
    lines.forEach((line, index) => {
        line.classList.toggle('active', index === activeIndex);
        line.classList.toggle('near-active', index === activeIndex + 1);
        line.classList.toggle('is-hidden', index !== activeIndex && index !== activeIndex + 1);
    });
    lines[activeIndex]?.scrollIntoView({ block: 'center', behavior: force ? 'auto' : 'smooth' });
    updateWechatMusicIsland();
}

function bindWechatMusicLyricsDrag(box) {
    if (!box || box.dataset.dragBound === '1') return;
    box.dataset.dragBound = '1';
    const handle = box.querySelector('.wc-music-lyrics-handle') || box;
    let drag = null;
    const move = event => {
        if (!drag) return;
        const point = event.touches ? event.touches[0] : event;
        const root = getWechatMusicOverlayRoot() || document.body;
        const rect = root.getBoundingClientRect();
        const width = box.offsetWidth || 260;
        const height = box.offsetHeight || 220;
        const left = Math.max(8, Math.min(rect.width - width - 8, point.clientX - rect.left - drag.x));
        const top = Math.max(70, Math.min(rect.height - height - 74, point.clientY - rect.top - drag.y));
        box.style.left = `${left}px`;
        box.style.top = `${top}px`;
        box.style.right = 'auto';
        box.style.bottom = 'auto';
    };
    const end = () => {
        drag = null;
        window.removeEventListener('mousemove', move);
        window.removeEventListener('mouseup', end);
        window.removeEventListener('touchmove', move);
        window.removeEventListener('touchend', end);
    };
    const start = event => {
        if (event.target.closest('button')) return;
        const point = event.touches ? event.touches[0] : event;
        const boxRect = box.getBoundingClientRect();
        drag = { x: point.clientX - boxRect.left, y: point.clientY - boxRect.top };
        window.addEventListener('mousemove', move);
        window.addEventListener('mouseup', end);
        window.addEventListener('touchmove', move, { passive: false });
        window.addEventListener('touchend', end);
    };
    handle.addEventListener('mousedown', start);
    handle.addEventListener('touchstart', start, { passive: true });
}


function isWechatIncomingMusicInvite(msg) {
    if (!msg || msg.type !== 'music_card' || msg.isMe) return false;
    const music = msg.music && typeof msg.music === 'object' ? msg.music : {};
    return music.invite !== false && msg.musicInvite !== false;
}

function isWechatMusicInviteAccepted(msg) {
    const music = msg && msg.music && typeof msg.music === 'object' ? msg.music : {};
    return !!(music.inviteAccepted || msg.musicInviteAccepted || music.coListening);
}

function isWechatMusicInviteRejected(msg) {
    const music = msg && msg.music && typeof msg.music === 'object' ? msg.music : {};
    return !!(music.inviteRejected || msg.musicInviteRejected);
}

function getWechatMusicInvitePlayableUrl(msg) {
    const info = getWechatMusicMessageInfo(msg);
    return normalizeWechatUrl(info.audioUrl || info.playableUrl || info.sourceAudioUrl || msg?.url || '');
}

function startWechatMusicCoListenFromMessage(char, msg, options = {}) {
    if (!char || !msg || msg.type !== 'music_card' || typeof window.startMusicCoListenFromWechat !== 'function') return false;
    const info = getWechatMusicMessageInfo(msg);
    const audioUrl = getWechatMusicInvitePlayableUrl(msg);
    if (!audioUrl) return false;
    return !!window.startMusicCoListenFromWechat({
        id: msg.timestamp || `wechat:${info.title}:${audioUrl}`,
        trackName: info.title,
        title: info.title,
        artistName: info.artist,
        artist: info.artist,
        collectionName: '\u5fae\u4fe1\u4e00\u8d77\u542c\u6b4c',
        artworkUrl100: info.artwork,
        artwork: info.artwork,
        audioUrl,
        trackViewUrl: msg.url || '',
        sourceName: info.sourceName || '\u5fae\u4fe1\u97f3\u4e50'
    }, char.id, { autoplay: false, queueAi: !!options.queueAi, reason: options.reason || 'wechat-invite' });
}

async function acceptWechatMusicInvite(msgIndex) {
    const index = Number(msgIndex);
    const char = getCurrentChatChar();
    if (!char || !Array.isArray(char.history) || !Number.isInteger(index)) return;
    const msg = char.history[index];
    if (!msg || msg.type !== 'music_card' || msg.isMe) return;
    msg.music = msg.music && typeof msg.music === 'object' ? msg.music : {};
    msg.music.invite = true;
    msg.music.inviteAccepted = true;
    msg.music.inviteRejected = false;
    msg.music.coListening = true;
    msg.music.acceptedAt = Date.now();
    msg.music.rejectedAt = 0;
    msg.musicInviteAccepted = true;
    msg.musicInviteRejected = false;
    syncWechatMessageDescription(msg);
    saveCharactersToStorage();
    refreshChatView(char);
    renderChatList();
    if (typeof showWechatToast === 'function') showWechatToast('\u5df2\u540c\u610f\u4e00\u8d77\u542c\u6b4c');

    let playableUrl = getWechatMusicInvitePlayableUrl(msg);
    if (!playableUrl || msg.music.pendingSearch || msg.music.lookupFailed) {
        await enrichWechatMusicCardMessage(char, msg, { force: true, reason: 'music_invite_accept' });
        playableUrl = getWechatMusicInvitePlayableUrl(msg);
    }
    if (!playableUrl) {
        if (typeof showWechatToast === 'function') showWechatToast('\u8fd9\u9996\u6b4c\u8fd8\u6ca1\u627e\u5230\u53ef\u64ad\u653e\u97f3\u6e90\uff0c\u6362\u4e2a\u5173\u952e\u8bcd\u8bd5\u8bd5');
        refreshChatView(char);
        return;
    }
    startWechatMusicCoListenFromMessage(char, msg, { reason: 'wechat-invite-accepted' });
    const info = getWechatMusicMessageInfo(msg);
    const card = document.querySelector(`.msg-row[data-msg-idx="${index}"] .msg-music-card`);
    await playWechatMusicCard(playableUrl, info.title, info.artist, card);
}
window.acceptWechatMusicInvite = acceptWechatMusicInvite;

function rejectWechatMusicInvite(msgIndex) {
    const index = Number(msgIndex);
    const char = getCurrentChatChar();
    if (!char || !Array.isArray(char.history) || !Number.isInteger(index)) return;
    const msg = char.history[index];
    if (!msg || msg.type !== 'music_card' || msg.isMe || isWechatMusicInviteAccepted(msg)) return;
    msg.music = msg.music && typeof msg.music === 'object' ? msg.music : {};
    msg.music.invite = true;
    msg.music.inviteAccepted = false;
    msg.music.inviteRejected = true;
    msg.music.coListening = false;
    msg.music.rejectedAt = Date.now();
    msg.musicInviteAccepted = false;
    msg.musicInviteRejected = true;
    syncWechatMessageDescription(msg);
    const info = getWechatMusicMessageInfo(msg);
    char.history.push({
        type: 'user_event',
        isMe: true,
        hiddenFromChat: true,
        internalEvent: true,
        eventKind: 'music_invite_rejected',
        musicMessageTimestamp: msg.timestamp || '',
        content: `用户拒绝了你发起的一起听歌邀请：《${info.title || '这首歌'}》${info.artist ? ` - ${info.artist}` : ''}。请按你的人设、当前关系和最近聊天自然回应，可以失落、嘴硬、换话题或提出别的歌，但不要重复系统说明。`,
        timestamp: createMessageTimestamp()
    });
    saveCharactersToStorage();
    refreshChatView(char);
    renderChatList();
    if (typeof showWechatToast === 'function') showWechatToast('已拒绝一起听歌邀请');
    const contentEl = document.getElementById('chat-room-content');
    if (typeof queueWechatAutoReplyToChar === 'function') {
        queueWechatAutoReplyToChar(char.id);
    } else if (contentEl) {
        triggerAiAfterMessage(char, contentEl).catch(err => console.warn('music invite rejection reply failed:', err));
    }
}
window.rejectWechatMusicInvite = rejectWechatMusicInvite;

function bindWechatMusicCardPlayback(scope) {
    if (!scope || typeof scope.querySelectorAll !== 'function') return;
    scope.querySelectorAll('.msg-music-card').forEach(card => {
        if (card.dataset.musicPlaybackBound === '1') return;
        card.dataset.musicPlaybackBound = '1';
        prepareWechatMusicCardPlayableUrl(card).catch(() => {});
        card.addEventListener('click', event => {
            event.preventDefault();
            event.stopPropagation();
            const title = card.dataset.title || card.querySelector('.msg-music-main strong')?.textContent || '一起听歌';
            const artist = card.dataset.artist || card.querySelector('.msg-music-main em')?.textContent || '';
            playWechatMusicCard(card.dataset.audioUrl || '', title, artist, card);
        });
        card.addEventListener('keydown', event => {
            if (event.key !== 'Enter' && event.key !== ' ') return;
            event.preventDefault();
            const title = card.dataset.title || card.querySelector('.msg-music-main strong')?.textContent || '一起听歌';
            const artist = card.dataset.artist || card.querySelector('.msg-music-main em')?.textContent || '';
            playWechatMusicCard(card.dataset.audioUrl || '', title, artist, card);
        });
    });
}

function playWechatAudioUrl(audio, url, safeUrl) {
    return new Promise((resolve, reject) => {
        let settled = false;
        const startTime = Number.isFinite(audio.currentTime) ? audio.currentTime : 0;
        const cleanup = () => {
            audio.removeEventListener('playing', onMaybePlaying);
            audio.removeEventListener('timeupdate', onTimeUpdate);
            audio.removeEventListener('error', onError);
        };
        const finish = (ok, error) => {
            if (settled) return;
            settled = true;
            cleanup();
            ok ? resolve() : reject(error || audio.error || new Error('audio play failed'));
        };
        const hasAdvanced = () => !audio.paused && !audio.error && Number.isFinite(audio.currentTime) && audio.currentTime > startTime + 0.08;
        const onTimeUpdate = () => {
            if (hasAdvanced()) finish(true);
        };
        const onMaybePlaying = () => setTimeout(() => {
            if (hasAdvanced()) finish(true);
        }, 450);
        const onError = () => finish(false, audio.error || new Error('audio source error'));
        audio.addEventListener('playing', onMaybePlaying, { once: true });
        audio.addEventListener('timeupdate', onTimeUpdate);
        audio.addEventListener('error', onError, { once: true });
        audio.dataset.cardUrl = safeUrl;
        audio.muted = false;
        audio.volume = 1;
        if (audio.src !== url) {
            audio.src = url;
            audio.load();
        }
        const playPromise = audio.play();
        if (playPromise && typeof playPromise.then === 'function') {
            playPromise.then(() => setTimeout(() => {
                if (hasAdvanced()) finish(true);
            }, 900)).catch(err => finish(false, err));
        }
        setTimeout(() => finish(false, new Error('audio clock stalled')), 2600);
    });
}

async function playWechatAudioBufferUrl(url, safeUrl, options = {}) {
    const context = getWechatMusicAudioContext();
    if (!context) throw new Error('Web Audio is not supported');
    if (context.state === 'suspended') await context.resume();
    if (context.state !== 'running') throw new Error('Web Audio is suspended');
    const playableUrl = await resolveWechatPlayableMusicUrl(url);
    const resp = await fetch(playableUrl || url, { cache: 'no-store', redirect: 'follow' });
    if (!resp.ok) throw new Error('audio fetch failed');
    const buffer = await context.decodeAudioData(await resp.arrayBuffer());
    stopWechatMusicBufferPlayback();
    const source = context.createBufferSource();
    source.buffer = buffer;
    source.connect(context.destination);
    const offset = Math.max(0, Math.min(Number(options.offset || 0), Math.max(0, buffer.duration - 0.05)));
    window._wechatMusicBufferPlayback = { source, context, safeUrl, sourceUrl: url, playableUrl, startedAt: context.currentTime, duration: buffer.duration, offset };
    source.onended = () => {
        if (window._wechatMusicBufferPlayback?.source === source) {
            window._wechatMusicBufferPlayback = null;
            clearInterval(window._wechatMusicBufferTicker);
            window._wechatMusicBufferTicker = null;
            document.querySelectorAll('.msg-music-card.playing').forEach(card => card.classList.remove('playing'));
            handleWechatMusicPlaybackEnded();
        }
    };
    source.start(0, offset);
    startWechatMusicBufferTicker();
}

function getWechatMusicMessageInfo(msg) {
    const music = msg && msg.music && typeof msg.music === 'object' ? msg.music : {};
    return {
        title: music.title || msg?.title || '一起听歌',
        artist: music.artist || msg?.artist || '',
        audioUrl: normalizeWechatUrl(music.audioUrl || msg?.audioUrl || music.playableUrl || msg?.playableUrl || music.url || msg?.url || ''),
        playableUrl: normalizeWechatUrl(music.playableUrl || msg?.playableUrl || music.audioUrl || msg?.audioUrl || music.url || msg?.url || ''),
        sourceAudioUrl: normalizeWechatUrl(music.sourceAudioUrl || msg?.sourceAudioUrl || music.audioUrl || msg?.audioUrl || music.url || msg?.url || ''),
        artwork: music.artwork || msg?.artwork || '',
        sourceName: music.sourceName || msg?.sourceName || '',
        lyricsText: music.lyricsText || msg?.lyricsText || '',
        lyricsUrl: music.lyricsUrl || msg?.lyricsUrl || '',
        sourceKey: music.sourceKey || msg?.sourceKey || '',
        sourceMeta: music.sourceMeta || msg?.sourceMeta || ''
    };
}

function getWechatMusicTrackFromMessage(msg) {
    if (!msg || msg.type !== 'music_card') return null;
    const info = getWechatMusicMessageInfo(msg);
    return normalizeWechatMusicDraftTrack({
        title: info.title,
        artist: info.artist,
        audioUrl: info.audioUrl || info.playableUrl || info.sourceAudioUrl,
        playableUrl: info.playableUrl || info.audioUrl || info.sourceAudioUrl,
        sourceAudioUrl: info.sourceAudioUrl || info.audioUrl || info.playableUrl,
        artwork: info.artwork,
        sourceName: info.sourceName,
        sourceMeta: info.sourceMeta,
        sourceKey: info.sourceKey,
        lyricsText: info.lyricsText,
        lyricsUrl: info.lyricsUrl,
        url: msg.url || ''
    });
}

async function switchWechatMusicListenTrackFromAi(char, msg) {
    if (!char || !msg || msg.type !== 'music_card' || msg.isMe || !isWechatMusicListenActive()) return false;
    const tempMsg = {
        ...msg,
        music: {
            ...(msg.music && typeof msg.music === 'object' ? msg.music : {}),
            invite: false,
            inviteAccepted: true,
            coListening: true
        },
        musicInvite: false,
        musicInviteAccepted: true
    };
    if (!isWechatMusicMessagePlayable(tempMsg) || tempMsg.music?.pendingSearch || tempMsg.music?.lookupFailed) {
        await enrichWechatMusicCardMessage(char, tempMsg, { force: true, reason: 'ai_music_switch' });
    }
    let track = getWechatMusicTrackFromMessage(tempMsg);
    if (!track || !track.audioUrl) {
        const info = getWechatMusicMessageInfo(tempMsg);
        const found = await findWechatMusicTrackForCard(info.title, info.artist, info.audioUrl || info.sourceAudioUrl);
        track = found ? normalizeWechatMusicDraftTrack(found) : null;
    }
    if (!track || !track.audioUrl) {
        if (typeof showWechatToast === 'function') showWechatToast('这首切歌还没找到可播放音源');
        return true;
    }
    addWechatMusicTrackToQueue(track);
    const cardLike = {
        dataset: {
            audioUrl: track.audioUrl || '',
            sourceUrl: track.sourceAudioUrl || track.audioUrl || '',
            playableUrl: track.playableUrl || '',
            title: track.title || '',
            artist: track.artist || '',
            artwork: track.artwork || '',
            lyricsText: track.lyricsText || '',
            lyricsUrl: track.lyricsUrl || '',
            sourceKey: track.sourceKey || '',
            sourceMeta: track.sourceMeta || '',
            sourceName: track.sourceName || ''
        },
        closest: () => null
    };
    await playWechatMusicCard(track.audioUrl || track.playableUrl || track.sourceAudioUrl || '', track.title || '', track.artist || '', cardLike, { queue: true, aiSwitch: true });
    renderWechatMusicQueuePanel();
    if (typeof showWechatToast === 'function') showWechatToast(`已切到 ${track.title}`);
    return true;
}

function isWechatMusicMessagePlayable(msg) {
    const info = getWechatMusicMessageInfo(msg);
    return !!(info.audioUrl || info.playableUrl || info.sourceAudioUrl);
}

async function findWechatMusicTrackForCard(title, artist, avoidUrl = '') {
    const searcher = typeof window.searchAcrossMusicSources === 'function' ? window.searchAcrossMusicSources : null;
    if (!searcher || !title) return null;
    try {
        const mode = typeof window.getMusicSourceMode === 'function' ? window.getMusicSourceMode() : 'smart';
        const query = [title, artist].filter(Boolean).join(' ');
        const rows = await searcher(query, mode || 'smart');
        const avoid = normalizeWechatUrl(avoidUrl || '');
        const normalized = (Array.isArray(rows) ? rows : [])
            .map(item => normalizeWechatMusicDraftTrack(item))
            .filter(item => item && item.audioUrl && item.audioUrl !== avoid);
        if (!normalized.length) return null;
        const titleKey = String(title || '').trim().toLowerCase();
        const artistKey = String(artist || '').trim().toLowerCase();
        const exact = normalized.find(item => {
            const itemTitle = String(item.title || '').trim().toLowerCase();
            const itemArtist = String(item.artist || '').trim().toLowerCase();
            return itemTitle === titleKey && (!artistKey || itemArtist.includes(artistKey) || artistKey.includes(itemArtist));
        });
        return exact || normalized[0];
    } catch (e) {
        console.warn('wechat music search failed:', e);
        return null;
    }
}

function applyWechatMusicTrackToMessage(msg, track) {
    if (!msg || !track) return false;
    const normalized = normalizeWechatMusicDraftTrack(track);
    if (!normalized) return false;
    const sourceAudioUrl = normalized.sourceAudioUrl || normalized.audioUrl;
    const selectedCardUrl = isWechatMusicProxyUrl(sourceAudioUrl)
        ? sourceAudioUrl
        : (normalized.playableUrl || normalized.audioUrl);
    const previousMusic = msg.music && typeof msg.music === 'object' ? msg.music : {};
    msg.music = {
        title: normalized.title,
        artist: normalized.artist || '',
        audioUrl: selectedCardUrl,
        playableUrl: normalized.playableUrl || normalized.audioUrl,
        sourceAudioUrl,
        url: normalized.url || '',
        artwork: normalized.artwork || '',
        sourceName: normalized.sourceName || '',
        sourceMeta: normalized.sourceMeta || '',
        sourceKey: normalized.sourceKey || '',
        lyricsText: normalized.lyricsText || '',
        lyricsUrl: normalized.lyricsUrl || '',
        invite: !!previousMusic.invite,
        inviteAccepted: !!previousMusic.inviteAccepted,
        inviteRejected: !!previousMusic.inviteRejected,
        acceptedAt: previousMusic.acceptedAt || 0,
        rejectedAt: previousMusic.rejectedAt || 0,
        coListening: !!previousMusic.coListening
    };
    msg.title = normalized.title;
    msg.artist = normalized.artist || '';
    msg.audioUrl = selectedCardUrl;
    msg.playableUrl = normalized.playableUrl || normalized.audioUrl;
    msg.sourceAudioUrl = sourceAudioUrl;
    msg.url = normalized.url || '';
    msg.artwork = normalized.artwork || '';
    syncWechatMessageDescription(msg);
    return true;
}

async function enrichWechatMusicCardMessage(char, msg, options = {}) {
    if (!char || !msg || msg.type !== 'music_card') return false;
    msg.music = msg.music && typeof msg.music === 'object' ? msg.music : {};
    if (!options.force && isWechatMusicMessagePlayable(msg) && !msg.music.pendingSearch) return true;
    if (msg.music.resolving) return false;
    const info = getWechatMusicMessageInfo(msg);
    if (!info.title) return false;
    msg.music.resolving = true;
    msg.music.pendingSearch = true;
    syncWechatMessageDescription(msg);
    if (window.currentChatCharId === char.id) refreshChatView(char);
    try {
        const track = await findWechatMusicTrackForCard(info.title, info.artist, info.audioUrl || info.sourceAudioUrl);
        if (track && applyWechatMusicTrackToMessage(msg, track)) {
            msg.music.pendingSearch = false;
            msg.music.resolving = false;
            saveCharactersToStorage();
            if (window.currentChatCharId === char.id) refreshChatView(char);
            renderChatList();
            return true;
        }
        msg.music.pendingSearch = false;
        msg.music.resolving = false;
        msg.music.lookupFailed = true;
        syncWechatMessageDescription(msg);
        saveCharactersToStorage();
        if (window.currentChatCharId === char.id) refreshChatView(char);
        renderChatList();
        return false;
    } catch (e) {
        msg.music.pendingSearch = false;
        msg.music.resolving = false;
        msg.music.lookupFailed = true;
        saveCharactersToStorage();
        console.warn('wechat music enrich failed:', e);
        return false;
    }
}

function scheduleWechatMusicReaction(char, msg) {
    if (!char || !msg || msg.type !== 'music_card' || !msg.isMe || msg.musicReactionRequested) return;
    msg.musicReactionRequested = createMessageTimestamp();
    saveCharactersToStorage();
    setTimeout(() => requestWechatMusicReaction(char.id, msg.timestamp), 650);
}

async function requestWechatMusicReaction(charOrId, msgTimestamp) {
    const char = typeof charOrId === 'string'
        ? (window.myCharacters || []).find(c => c.id === charOrId)
        : charOrId;
    if (!char || typeof callChatApi !== 'function') return;
    if (isWechatAiRateLimitPaused() || isWechatBackgroundApiPaused()) return;
    if (window._wechatAiBusy) {
        setTimeout(() => requestWechatMusicReaction(char.id, msgTimestamp), 1500);
        return;
    }
    const musicMsg = (char.history || []).find(item => item && item.type === 'music_card' && item.isMe && item.timestamp === msgTimestamp);
    if (!musicMsg || musicMsg.musicReactionDone) return;
    musicMsg.musicReactionDone = true;
    const info = getWechatMusicMessageInfo(musicMsg);
    const contentEl = document.getElementById('chat-room-content');
    window._wechatAiBusy = true;
    setWechatBusyState(true);
    if (window.currentChatCharId === char.id) syncWechatCurrentChatTitleState('正在听歌...');
    try {
        const messages = typeof buildMessages === 'function'
            ? buildMessages(char, char.history || [], 26)
            : [{ role: 'system', content: `你是${getWechatCharDisplayName(char)}，按人设回复。` }];
        messages.push({
            role: 'system',
            content: `用户刚给你发了一张音乐卡片：《${info.title}》${info.artist ? ` - ${info.artist}` : ''}。你要像真的在微信里一起听歌一样，按你的人设、心情、记忆和最近上下文评价这首歌。喜欢就自然回复；如果你不喜欢、觉得不合气氛，或人设上会想掌控歌单，可以切歌。切歌时先用一条短消息说理由，再单独输出一段 [微信音乐:你想换的歌名|歌手|]，第三栏 URL 可以留空，系统会搜索可播放音源。不要每次都切歌，不要编造不存在的 URL。`
        });
        const result = await callChatApi(messages, { background: true });
        if (result && result.ok) {
            const parts = splitWechatAiResponseSegments(result.content, char);
            let appended = 0;
            for (let i = 0; i < parts.length; i++) {
                if (i > 0) await new Promise(r => setTimeout(r, 260 + Math.random() * 260));
                appended += appendWechatAiMessageParts(char, contentEl, parts[i]) || 0;
            }
            if (appended > 0) showWechatDesktopMessageIsland(char);
            requestWechatAiStatusSnapshot(char, { reason: 'music_reaction' }).catch(e => console.warn('ai status snapshot failed:', e));
            scheduleWechatMemoryExtraction(char, 'music_reaction');
        }
    } catch (e) {
        console.warn('wechat music reaction failed:', e);
    } finally {
        saveCharactersToStorage();
        renderChatList();
        if (window.currentChatCharId === char.id) {
            syncWechatCurrentChatTitleState('');
            if (contentEl) contentEl.scrollTop = contentEl.scrollHeight;
        }
        setWechatBusyState(false);
        window._wechatAiBusy = false;
    }
}

async function recoverWechatMusicCardUrl(title, artist, currentUrl) {
    const searcher = typeof window.searchAcrossMusicSources === 'function' ? window.searchAcrossMusicSources : null;
    if (!searcher || !title) return '';
    try {
        const mode = typeof window.getMusicSourceMode === 'function' ? window.getMusicSourceMode() : 'smart';
        const rows = await searcher([title, artist].filter(Boolean).join(' '), mode || 'smart');
        const normalizedRows = (Array.isArray(rows) ? rows : [])
            .map(item => normalizeWechatMusicDraftTrack(item))
            .filter(item => item && item.audioUrl && item.audioUrl !== currentUrl);
        const titleKey = String(title || '').trim().toLowerCase();
        const artistKey = String(artist || '').trim().toLowerCase();
        const exact = normalizedRows.find(item => {
            const itemTitle = String(item.title || '').trim().toLowerCase();
            const itemArtist = String(item.artist || '').trim().toLowerCase();
            return itemTitle === titleKey && (!artistKey || itemArtist.includes(artistKey) || artistKey.includes(itemArtist));
        });
        return (exact || normalizedRows[0])?.audioUrl || '';
    } catch (e) {
        return '';
    }
}

async function playWechatMusicCard(audioUrl, title, artist, cardEl = null, options = {}) {
    const safeUrl = normalizeWechatUrl(String(audioUrl || '').replace(/\\u0026/gi, '&'));
    if (!safeUrl) {
        if (typeof showWechatToast === 'function') showWechatToast('这张音乐卡片没有可播放音频，先搜索选歌再发送');
        return;
    }
    const now = Date.now();
    const lastTap = window._wechatMusicCardLastTap || {};
    if (lastTap.url === safeUrl && now - Number(lastTap.time || 0) < 700) return;
    window._wechatMusicCardLastTap = { url: safeUrl, time: now };
    const sourceUrl = normalizeWechatUrl(cardEl?.dataset?.sourceUrl || safeUrl);
    const cardMessage = getWechatMusicCardMessageFromElement(cardEl);
    openWechatMusicListenPlayer({
        title: title || cardEl?.dataset?.title || '一起听歌',
        artist: artist || cardEl?.dataset?.artist || '',
        audioUrl: safeUrl,
        sourceAudioUrl: sourceUrl,
        artwork: cardEl?.dataset?.artwork || '',
        lyricsText: cardEl?.dataset?.lyricsText || '',
        lyricsUrl: cardEl?.dataset?.lyricsUrl || '',
        sourceKey: cardEl?.dataset?.sourceKey || '',
        sourceMeta: cardEl?.dataset?.sourceMeta || '',
        sourceName: cardEl?.dataset?.sourceName || ''
    }, cardEl, cardMessage?.msg, cardMessage?.char);
    if (cardEl && isWechatMusicProxyUrl(safeUrl) && cardEl.dataset.playableReady !== '1') {
        prepareWechatMusicCardPlayableUrl(cardEl).then(playable => {
            const nextUrl = normalizeWechatUrl(playable || '');
            if (nextUrl && nextUrl !== safeUrl && !isWechatTemporaryMusicCdnUrl(nextUrl)) {
                cardEl.dataset.audioUrl = nextUrl;
                cardEl.dataset.playableReady = '1';
                cardEl.classList.remove('loading');
            }
        }).catch(() => {});
    }
    const context = getWechatMusicAudioContext();
    if (context?.state === 'suspended') context.resume().catch(() => {});
    const audio = getWechatMusicAudioPlayer();
    if (!options.queue && ((audio.dataset.cardUrl === safeUrl && !audio.paused) || isWechatMusicBufferPlaying(safeUrl))) {
        if (!options.toggle) {
            updateWechatMusicCardPlayingState(safeUrl, true);
            return;
        }
        audio.pause();
        stopWechatMusicBufferPlayback();
        updateWechatMusicCardPlayingState(safeUrl, false);
        updateWechatMusicIsland();
        return;
    }
    stopWechatMusicBufferPlayback();
    const seq = ++wechatMusicCardPlaySeq;
    updateWechatMusicCardPlayingState(safeUrl, false, true);
    const candidates = [];
    const addCandidate = value => {
        const nextUrl = normalizeWechatUrl(value || '');
        if (nextUrl && !candidates.includes(nextUrl)) candidates.push(nextUrl);
    };
    const cached = getWechatResolvedMusicCache(sourceUrl || safeUrl);
    addCandidate(cached);
    addCandidate(safeUrl);
    if (!cardEl && isWechatMusicProxyUrl(safeUrl)) {
        try {
            const resolvedFirst = await resolveWechatPlayableMusicUrl(safeUrl);
            addCandidate(resolvedFirst);
        } catch (e) {}
    }
    let lastError = null;
    let nativeFallbackUrl = candidates.find(Boolean) || safeUrl;
    for (const candidate of candidates) {
        nativeFallbackUrl = candidate || nativeFallbackUrl;
        try {
            await playWechatAudioUrl(audio, candidate, safeUrl);
            if (seq === wechatMusicCardPlaySeq) {
                updateWechatMusicCardPlayingState(safeUrl, true);
            }
            return;
        } catch (e) {
            lastError = e;
        }
        if (!cardEl) {
            try {
                audio.pause();
                await playWechatAudioBufferUrl(candidate, safeUrl);
                if (seq === wechatMusicCardPlaySeq) {
                    updateWechatMusicCardPlayingState(safeUrl, true);
                }
                return;
            } catch (e) {
                lastError = e;
            }
        }
    }
    const resolved = await resolveWechatPlayableMusicUrl(safeUrl);
    if (resolved && !candidates.includes(resolved)) {
        nativeFallbackUrl = resolved;
        try {
            await playWechatAudioUrl(audio, resolved, safeUrl);
            if (seq === wechatMusicCardPlaySeq) updateWechatMusicCardPlayingState(safeUrl, true);
            return;
        } catch (e) {
            lastError = e;
        }
        try {
            audio.pause();
            await playWechatAudioBufferUrl(resolved, safeUrl);
            if (seq === wechatMusicCardPlaySeq) updateWechatMusicCardPlayingState(safeUrl, true);
            return;
        } catch (e) {
            lastError = e;
        }
    }
    const recovered = await recoverWechatMusicCardUrl(title, artist, safeUrl);
    if (recovered) {
        const nextUrl = normalizeWechatUrl(recovered);
        nativeFallbackUrl = nextUrl || nativeFallbackUrl;
        if (cardEl && nextUrl) cardEl.dataset.audioUrl = nextUrl;
        try {
            await playWechatAudioUrl(audio, nextUrl, nextUrl);
            if (seq === wechatMusicCardPlaySeq) updateWechatMusicCardPlayingState(nextUrl, true);
            return;
        } catch (e) {
            lastError = e;
        }
        try {
            audio.pause();
            await playWechatAudioBufferUrl(nextUrl, nextUrl);
            if (seq === wechatMusicCardPlaySeq) updateWechatMusicCardPlayingState(nextUrl, true);
            return;
        } catch (e) {
            lastError = e;
        }
    }
    window._wechatMusicLastError = {
        name: lastError?.name || '',
        message: lastError?.message || String(lastError || ''),
        url: safeUrl,
        time: Date.now()
    };
    updateWechatMusicCardPlayingState(safeUrl, false);
    const errorName = lastError?.name || '';
    if (typeof showWechatToast === 'function') {
        showWechatToast(errorName === 'NotAllowedError' ? '浏览器拦截了播放，请再点一次音乐卡片' : '播放失败，换一首或换一个音乐源试试');
    }
}

function normalizeWechatMusicDraftTrack(track) {
    if (!track || typeof track !== 'object') return null;
    const title = track.trackName || track.title || track.name || '';
    if (!title) return null;
    const audioUrl = normalizeWechatUrl(track.audioUrl || track.musicUrl || track.playUrl || track.src || '');
    const sourceAudioUrl = normalizeWechatUrl(track.sourceAudioUrl || track.sourceUrl || audioUrl);
    return {
        title,
        artist: track.artistName || track.artist || track.singer || '',
        audioUrl,
        playableUrl: normalizeWechatUrl(track.playableUrl || track.resolvedAudioUrl || audioUrl),
        sourceAudioUrl,
        url: normalizeWechatUrl(track.trackViewUrl || track.pageUrl || track.shareUrl || ''),
        artwork: track.artworkUrl100 || track.artwork || track.cover || track.pic || '',
        sourceName: track.sourceName || track.collectionName || '',
        sourceMeta: track.sourceMeta || '',
        sourceKey: track.sourceKey || '',
        lyricsText: track.lyricsText || '',
        lyricsUrl: track.lyricsUrl || '',
        raw: track
    };
}

function getWechatMusicCardDraft() {
    const track = typeof window.getCurrentMusicTrack === 'function' ? window.getCurrentMusicTrack() : null;
    const normalized = normalizeWechatMusicDraftTrack(track);
    if (normalized) return normalized;
    const inputValue = document.getElementById('music-search-input')?.value || '';
    return {
        title: inputValue.trim() || '一起听歌',
        artist: '',
        url: '',
        artwork: ''
    };
}

function getWechatMusicComposeOptions(existingMsg = null) {
    const options = [];
    const add = track => {
        const normalized = normalizeWechatMusicDraftTrack(track);
        if (!normalized) return;
        const key = `${normalized.title}|${normalized.artist}|${normalized.url}`.toLowerCase();
        if (options.some(item => item.key === key)) return;
        options.push({ ...normalized, key });
    };
    if (existingMsg) add(existingMsg.music || existingMsg);
    add(getWechatMusicCardDraft());
    try {
        const favorites = typeof getMusicFavoritesStore === 'function'
            ? getMusicFavoritesStore()
            : JSON.parse(localStorage.getItem('bynd_music_favorites_v1') || '[]');
        (Array.isArray(favorites) ? favorites : []).slice(0, 24).forEach(add);
    } catch (e) {}
    return options.length ? options : [getWechatMusicCardDraft()];
}

function renderWechatMusicComposeResults() {
    const list = document.getElementById('wc-compose-music-results');
    const status = document.getElementById('wc-compose-music-status');
    if (!list) return;
    const results = Array.isArray(window._wechatMusicComposeResults) ? window._wechatMusicComposeResults : [];
    const selected = window._wechatMusicComposeSelected || null;
    const isQueueMode = document.getElementById('wc-composer-modal')?.dataset.musicMode === 'queue';
    if (status) status.textContent = selected?.resolving
        ? '正在解析可播放地址...'
        : (selected?.audioUrl ? '已选择：' + selected.title : (results.length ? '请选择一首可播放音乐' : `搜索后选择一首歌再${isQueueMode ? '添加' : '发送'}`));
    list.innerHTML = results.length ? results.map((track, index) => {
        const active = selected && selected.audioUrl === track.audioUrl && selected.title === track.title;
        return `
            <button type="button" class="wc-music-result-item ${active ? 'active' : ''}" onclick="selectWechatMusicComposeTrack(${index})">
                <div class="wc-music-result-cover">${track.artwork ? `<img src="${wcEscapeHtml(track.artwork)}" onerror="this.remove()">` : '<i class="ri-music-2-line"></i>'}</div>
                <div>
                    <strong>${wcEscapeHtml(track.title)}</strong>
                    <span>${wcEscapeHtml([track.artist, track.sourceName].filter(Boolean).join(' · ') || '音乐源')}</span>
                </div>
                <i class="${active ? 'ri-checkbox-circle-fill' : 'ri-play-circle-line'}"></i>
            </button>
        `;
    }).join('') : '<div class="wc-music-result-empty">输入歌名或歌手，点搜索。</div>';
}

async function selectWechatMusicComposeTrack(index) {
    const results = Array.isArray(window._wechatMusicComposeResults) ? window._wechatMusicComposeResults : [];
    const track = results[index];
    if (!track || !track.audioUrl) {
        if (typeof showWechatToast === 'function') showWechatToast('这首没有可播放音频，换一个结果');
        return;
    }
    window._wechatMusicComposeSelected = { ...track, resolving: true };
    renderWechatMusicComposeResults();
    const sourceAudioUrl = track.sourceAudioUrl || track.audioUrl;
    let playableUrl = track.playableUrl || '';
    try {
        playableUrl = await resolveWechatPlayableMusicUrl(sourceAudioUrl);
    } catch (e) {
        playableUrl = track.audioUrl;
    }
    const primaryAudioUrl = isWechatMusicProxyUrl(sourceAudioUrl) ? sourceAudioUrl : (playableUrl || track.audioUrl);
    const nextTrack = { ...track, sourceAudioUrl, playableUrl: playableUrl || track.audioUrl, audioUrl: primaryAudioUrl, resolving: false };
    window._wechatMusicComposeResults[index] = nextTrack;
    window._wechatMusicComposeSelected = nextTrack;
    renderWechatMusicComposeResults();
}
window.selectWechatMusicComposeTrack = selectWechatMusicComposeTrack;

async function searchWechatMusicForComposer() {
    const input = document.getElementById('wc-compose-music-query');
    const status = document.getElementById('wc-compose-music-status');
    const query = String(input?.value || '').trim();
    if (!query) {
        if (typeof showWechatToast === 'function') showWechatToast('先输入歌名或歌手');
        return;
    }
    if (status) status.textContent = '正在搜索音乐...';
    window._wechatMusicComposeSelected = null;
    try {
        const mode = typeof window.getMusicSourceMode === 'function' ? window.getMusicSourceMode() : 'smart';
        const searcher = typeof window.searchAcrossMusicSources === 'function' ? window.searchAcrossMusicSources : null;
        let tracks = searcher ? await searcher(query, mode || 'smart') : [];
        tracks = (Array.isArray(tracks) ? tracks : []).map(normalizeWechatMusicDraftTrack).filter(item => item && item.audioUrl);
        window._wechatMusicComposeResults = tracks.slice(0, 18);
        const isQueueMode = document.getElementById('wc-composer-modal')?.dataset.musicMode === 'queue';
        if (status) status.textContent = tracks.length ? `搜索完成，选择一首后${isQueueMode ? '添加' : '发送'}` : '没有搜到可播放音频，换关键词试试';
    } catch (e) {
        window._wechatMusicComposeResults = [];
        if (status) status.textContent = '搜索失败，换关键词或音乐源再试';
    }
    renderWechatMusicComposeResults();
}
window.searchWechatMusicForComposer = searchWechatMusicForComposer;

